  1Ôćĺpackage cmd
  2Ôćĺ
  3Ôćĺimport (
  4Ôćĺ	"context"
  5Ôćĺ	"fmt"
  6Ôćĺ	"os"
  7Ôćĺ	"path/filepath"
  8Ôćĺ	"strings"
  9Ôćĺ	"time"
 10Ôćĺ
 11Ôćĺ	"github.com/spf13/cobra"
 12Ôćĺ	"github.com/usenurge/nurgesh/internal/account"
 13Ôćĺ	"github.com/usenurge/nurgesh/internal/db"
 14Ôćĺ	"github.com/usenurge/nurgesh/internal/metrics"
 15Ôćĺ	"github.com/usenurge/nurgesh/internal/project"
 16Ôćĺ	"github.com/usenurge/nurgesh/internal/update"
 17Ôćĺ)
 18Ôćĺ
 19Ôćĺvar (
 20Ôćĺ	buildVersion = "dev"
 21Ôćĺ	buildCommit  = "none"
 22Ôćĺ	buildDate    = "unknown"
 23Ôćĺ)
 24Ôćĺ
 25Ôćĺvar convexSiteURL = ""
 26Ôćĺ
 27Ôćĺ// SetVersion sets the build version info from ldflags.
 28Ôćĺfunc SetVersion(version, commit, date string) {
 29Ôćĺ	buildVersion = version
 30Ôćĺ	buildCommit = commit
 31Ôćĺ	buildDate = date
 32Ôćĺ}
 33Ôćĺ
 34Ôćĺ// SetConvexURL sets the Convex deployment URL from ldflags.
 35Ôćĺfunc SetConvexURL(url string) {
 36Ôćĺ	convexSiteURL = url
 37Ôćĺ}
 38Ôćĺ
 39Ôćĺ// GetConvexURL returns the Convex site URL, allowing env var override for development.
 40Ôćĺfunc GetConvexURL() string {
 41Ôćĺ	if env := os.Getenv("NURGE_CONVEX_URL"); env != "" {
 42Ôćĺ		return env
 43Ôćĺ	}
 44Ôćĺ	return convexSiteURL
 45Ôćĺ}
 46Ôćĺ
 47Ôćĺ// GetDashboardURL returns the dashboard URL, allowing env var override for development.
 48Ôćĺfunc GetDashboardURL() string {
 49Ôćĺ	if env := os.Getenv("NURGE_DASHBOARD_URL"); env != "" {
 50Ôćĺ		return env
 51Ôćĺ	}
 52Ôćĺ	return "https://app.nurge.sh"
 53Ôćĺ}
 54Ôćĺ
 55Ôćĺvar (
 56Ôćĺ	initForce     bool
 57Ôćĺ	initSkipHooks bool
 58Ôćĺ	initVerbose   bool
 59Ôćĺ)
 60Ôćĺ
 61Ôćĺvar rootCmd = &cobra.Command{
 62Ôćĺ	Use:   "nurge [directory]",
 63Ôćĺ	Short: "nurge ÔÇö outbound that learns",
 64Ôćĺ	Long:  "Nurge is an outbound sales tool that learns from your sent email history.\n\nRun 'nurge <directory>' to create a new project, or 'nurge' in an empty directory to initialize it.",
 65Ôćĺ	RunE:  runInit,
 66Ôćĺ}
 67Ôćĺ
 68Ôćĺvar versionCmd = &cobra.Command{
 69Ôćĺ	Use:         "version",
 70Ôćĺ	Short:       "Print the version of nurge",
 71Ôćĺ	Annotations: map[string]string{"skipAuth": "true"},
 72Ôćĺ	Run: func(cmd *cobra.Command, args []string) {
 73Ôćĺ		fmt.Printf("nurge %s (commit: %s, built: %s)\n", buildVersion, buildCommit, buildDate)
 74Ôćĺ	},
 75Ôćĺ}
 76Ôćĺ
 77Ôćĺ// runInit is the shared init logic used by both the root command and the hidden init alias.
 78Ôćĺfunc runInit(cmd *cobra.Command, args []string) error {
 79Ôćĺ	dirCreated := ""
 80Ôćĺ
 81Ôćĺ	if len(args) == 1 {
 82Ôćĺ		dir := args[0]
 83Ôćĺ		if err := os.MkdirAll(dir, 0755); err != nil {
 84Ôćĺ			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 85Ôćĺ		}
 86Ôćĺ		abs, err := filepath.Abs(dir)
 87Ôćĺ		if err != nil {
 88Ôćĺ			return err
 89Ôćĺ		}
 90Ôćĺ		if err := os.Chdir(abs); err != nil {
 91Ôćĺ			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 92Ôćĺ		}
 93Ôćĺ		dirCreated = dir
 94Ôćĺ	} else if !initForce {
 95Ôćĺ		// No directory arg: only init if current dir is empty or already initialized
 96Ôćĺ		empty, _ := project.IsDirEmpty(".")
 97Ôćĺ		alreadyInit := project.IsNurgeProject(".")
 98Ôćĺ		if !empty && !alreadyInit {
 99Ôćĺ			return cmd.Help()
100Ôćĺ		}
101Ôćĺ	}
102Ôćĺ
103Ôćĺ	// Check if current directory is non-empty (unless --force)
104Ôćĺ	if !initForce {
105Ôćĺ		empty, err := project.IsDirEmpty(".")
106Ôćĺ		if err != nil {
107Ôćĺ			return err
108Ôćĺ		}
109Ôćĺ		if !empty && !project.IsNurgeProject(".") {
110Ôćĺ			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
111Ôćĺ		}
112Ôćĺ	}
113Ôćĺ
114Ôćĺ	opts := project.Options{
115Ôćĺ		SkipHooks: initSkipHooks,
116Ôćĺ		Force:     initForce,
117Ôćĺ		Verbose:   initVerbose,
118Ôćĺ	}
119Ôćĺ	if err := project.Run(opts); err != nil {
120Ôćĺ		return err
121Ôćĺ	}
122Ôćĺ
123Ôćĺ	if dirCreated != "" {
124Ôćĺ		fmt.Println()
125Ôćĺ		fmt.Printf("  Now run: cd %s\n", dirCreated)
126Ôćĺ		fmt.Println()
127Ôćĺ	}
128Ôćĺ
129Ôćĺ	return nil
130Ôćĺ}
131Ôćĺ
132Ôćĺ// shouldSkipAuth walks the command tree to check if any command in the
133Ôćĺ// chain has the skipAuth annotation. This handles cases like
134Ôćĺ// "nurge account login" where account has skipAuth.
135Ôćĺfunc shouldSkipAuth(cmd *cobra.Command) bool {
136Ôćĺ	for c := cmd; c != nil; c = c.Parent() {
137Ôćĺ		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
138Ôćĺ			return true
139Ôćĺ		}
140Ôćĺ	}
141Ôćĺ	return false
142Ôćĺ}
143Ôćĺ
144Ôćĺfunc init() {
145Ôćĺ	rootCmd.AddCommand(versionCmd)
146Ôćĺ
147Ôćĺ	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
148Ôćĺ	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
149Ôćĺ	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
150Ôćĺ
151Ôćĺ	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
152Ôćĺ		// Root command (init) skips auth ÔÇö it's the first thing a user runs
153Ôćĺ		if cmd == rootCmd ||
154Ôćĺ			shouldSkipAuth(cmd) ||
155Ôćĺ			cmd.Name() == "help" ||
156Ôćĺ			cmd.Name() == "completion" {
157Ôćĺ			return nil
158Ôćĺ		}
159Ôćĺ		if _, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL()); err != nil {
160Ôćĺ			return err
161Ôćĺ		}
162Ôćĺ
163Ôćĺ		// Check for pending skill upgrade marker.
164Ôćĺ		checkPendingSkillUpgrade()
165Ôćĺ		return nil
166Ôćĺ	}
167Ôćĺ}
168Ôćĺ
169Ôćĺ// isKnownCommand checks if name matches any registered subcommand.
170Ôćĺfunc isKnownCommand(name string) bool {
171Ôćĺ	for _, c := range rootCmd.Commands() {
172Ôćĺ		if c.Name() == name {
173Ôćĺ			return true
174Ôćĺ		}
175Ôćĺ		for _, alias := range c.Aliases {
176Ôćĺ			if alias == name {
177Ôćĺ				return true
178Ôćĺ			}
179Ôćĺ		}
180Ôćĺ	}
181Ôćĺ	return name == "help" || name == "completion"
182Ôćĺ}
183Ôćĺ
184Ôćĺfunc Execute() error {
185Ôćĺ	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
186Ôćĺ	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
187Ôćĺ	// when the first arg isn't a known subcommand or flag.
188Ôćĺ	if len(os.Args) > 1 {
189Ôćĺ		first := os.Args[1]
190Ôćĺ		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
191Ôćĺ			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
192Ôćĺ		}
193Ôćĺ	}
194Ôćĺ
195Ôćĺ	// Start async update check before stdout wrapping (uses stderr, no interaction).
196Ôćĺ	type updateResult struct {
197Ôćĺ		info *update.UpdateInfo
198Ôćĺ	}
199Ôćĺ	updateCh := make(chan updateResult, 1)
200Ôćĺ	cmdName := resolveCommandName()
201Ôćĺ	if buildVersion != "dev" && cmdName != "update" && cmdName != "version" {
202Ôćĺ		go func() {
203Ôćĺ			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
204Ôćĺ			defer cancel()
205Ôćĺ			info, _ := update.CheckForUpdate(ctx, buildVersion)
206Ôćĺ			updateCh <- updateResult{info: info}
207Ôćĺ		}()
208Ôćĺ	}
209Ôćĺ
210Ôćĺ	// Wrap stdout with a counting writer to measure output size.
211Ôćĺ	cw := metrics.NewCountingWriter(os.Stdout)
212Ôćĺ	rootCmd.SetOut(cw)
213Ôćĺ	origStdout := os.Stdout
214Ôćĺ	r, w, _ := os.Pipe()
215Ôćĺ	os.Stdout = w
216Ôćĺ
217Ôćĺ	// Copy pipe output to counting writer in background.
218Ôćĺ	done := make(chan struct{})
219Ôćĺ	go func() {
220Ôćĺ		buf := make([]byte, 4096)
221Ôćĺ		for {
222Ôćĺ			n, err := r.Read(buf)
223Ôćĺ			if n > 0 {
224Ôćĺ				cw.Write(buf[:n])
225Ôćĺ			}
226Ôćĺ			if err != nil {
227Ôćĺ				break
228Ôćĺ			}
229Ôćĺ		}
230Ôćĺ		close(done)
231Ôćĺ	}()
232Ôćĺ
233Ôćĺ	err := rootCmd.Execute()
234Ôćĺ
235Ôćĺ	// Restore stdout and flush.
236Ôćĺ	w.Close()
237Ôćĺ	<-done
238Ôćĺ	os.Stdout = origStdout
239Ôćĺ
240Ôćĺ	// Print update notification if available (to stderr, so --format json is clean).
241Ôćĺ	select {
242Ôćĺ	case r := <-updateCh:
243Ôćĺ		if r.info != nil {
244Ôćĺ			fmt.Fprintf(os.Stderr, "\nÔćĺ nurge %s available. Run: nurge update\n", r.info.LatestVersion)
245Ôćĺ		}
246Ôćĺ	default:
247Ôćĺ	}
248Ôćĺ
249Ôćĺ	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
250Ôćĺ	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
251Ôćĺ		if d, dbErr := db.Open(); dbErr == nil {
252Ôćĺ			_ = metrics.EnsureTable(d)
253Ôćĺ			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
254Ôćĺ			d.Close()
255Ôćĺ		}
256Ôćĺ	}
257Ôćĺ
258Ôćĺ	return err
259Ôćĺ}
260Ôćĺ
261Ôćĺ// checkPendingSkillUpgrade prints a reminder if a pending skill upgrade marker exists.
262Ôćĺfunc checkPendingSkillUpgrade() {
263Ôćĺ	markerPath := filepath.Join(".nurge", "pending-skill-upgrade.json")
264Ôćĺ	if _, err := os.Stat(markerPath); err == nil {
265Ôćĺ		fmt.Fprintf(os.Stderr, "Ôćĺ Skill templates updated. Run /nurge:upgrade-skills in Claude Code to apply.\n")
266Ôćĺ	}
267Ôćĺ}
268Ôćĺ
269Ôćĺ// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
270Ôćĺfunc resolveCommandName() string {
271Ôćĺ	if len(os.Args) < 2 {
272Ôćĺ		return "init"
273Ôćĺ	}
274Ôćĺ	// Build command name from args, skipping flags.
275Ôćĺ	var parts []string
276Ôćĺ	for _, arg := range os.Args[1:] {
277Ôćĺ		if strings.HasPrefix(arg, "-") {
278Ôćĺ			break
279Ôćĺ		}
280Ôćĺ		parts = append(parts, arg)
281Ôćĺ	}
282Ôćĺ	if len(parts) == 0 {
283Ôćĺ		return "init"
284Ôćĺ	}
285Ôćĺ	return strings.Join(parts, " ")
286Ôćĺ}
