 33Ôćĺfunc connectGmail() error {
 34Ôćĺ	af, err := account.LoadAuth()
 35Ôćĺ	if err != nil || af.Token == "" {
 36Ôćĺ		return fmt.Errorf("not logged in. Run: nurge account login")
 37Ôćĺ	}
 38Ôćĺ
 39Ôćĺ	client := account.NewConvexClient(GetConvexURL())
 40Ôćĺ
 41Ôćĺ	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
 42Ôćĺ	resp, err := client.ConnectGmail(af.Token)
 43Ôćĺ	if err != nil {
 44Ôćĺ		return fmt.Errorf("connect failed: %w", err)
 45Ôćĺ	}
 46Ôćĺ
 47Ôćĺ	if resp.AlreadyConnected {
 48Ôćĺ		if resp.MaxReached {
 49Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
 50Ôćĺ		} else {
 51Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m Gmail already connected (%s)\n", resp.Email)
 52Ôćĺ		}
 53Ôćĺ		if project.IsNurgeProject(".") {
 54Ôćĺ			_ = project.SetConnector("gmail", "email", resp.Email)
 55Ôćĺ		}
 56Ôćĺ		return nil
 57Ôćĺ	}
 58Ôćĺ
 59Ôćĺ	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
 60Ôćĺ	if err := util.OpenBrowser(resp.URL); err != nil {
 61Ôćĺ		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
 62Ôćĺ	}
 63Ôćĺ
 64Ôćĺ	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
 65Ôćĺ	timeout := time.After(5 * time.Minute)
 66Ôćĺ	ticker := time.NewTicker(2 * time.Second)
 67Ôćĺ	defer ticker.Stop()
 68Ôćĺ
 69Ôćĺ	for {
 70Ôćĺ		select {
 71Ôćĺ		case <-timeout:
 72Ôćĺ			fmt.Fprintf(os.Stderr, "\n")
 73Ôćĺ			return fmt.Errorf("timed out waiting for Gmail connection")
 74Ôćĺ		case <-ticker.C:
 75Ôćĺ			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
 76Ôćĺ			if err != nil {
 77Ôćĺ				continue
 78Ôćĺ			}
 79Ôćĺ			if status.Connected {
 80Ôćĺ				fmt.Fprintf(os.Stderr, "\n  \033[32mÔťô\033[0m Gmail connected (%s)\n", status.Email)
 81Ôćĺ				if project.IsNurgeProject(".") {
 82Ôćĺ					_ = project.SetConnector("gmail", "email", status.Email)
 83Ôćĺ				}
 84Ôćĺ				return nil
 85Ôćĺ			}
 86Ôćĺ			fmt.Fprintf(os.Stderr, ".")
 87Ôćĺ		}
 88Ôćĺ	}
 89Ôćĺ}
