 15Ôćĺvar emailsFormat string
 16Ôćĺ
 17Ôćĺvar emailsCmd = &cobra.Command{
 18Ôćĺ	Use:   "emails",
 19Ôćĺ	Short: "Manage synced emails",
 20Ôćĺ}
 21Ôćĺ
 22Ôćĺvar emailsListCmd = &cobra.Command{
 23Ôćĺ	Use:   "list",
 24Ôćĺ	Short: "List synced emails",
 25Ôćĺ	RunE: func(cmd *cobra.Command, args []string) error {
 26Ôćĺ		d, err := db.Open()
 27Ôćĺ		if err != nil {
 28Ôćĺ			return err
 29Ôćĺ		}
 30Ôćĺ		defer d.Close()
 31Ôćĺ
 32Ôćĺ		class, _ := cmd.Flags().GetString("class")
 33Ôćĺ		limit, _ := cmd.Flags().GetInt("limit")
 34Ôćĺ		compact, _ := cmd.Flags().GetBool("compact")
 35Ôćĺ
 36Ôćĺ		opts := email.ListOptions{Class: class, Limit: limit}
 37Ôćĺ
 38Ôćĺ		if compact {
 39Ôćĺ			list, err := email.ListCompact(d, opts)
 40Ôćĺ			if err != nil {
 41Ôćĺ				return err
 42Ôćĺ			}
 43Ôćĺ			if emailsFormat == "json" {
 44Ôćĺ				enc := json.NewEncoder(os.Stdout)
 45Ôćĺ				enc.SetIndent("", "  ")
 46Ôćĺ				return enc.Encode(list)
 47Ôćĺ			}
 48Ôćĺ			for _, e := range list {
