223Ôćĺ// inferSenderDomain tries to detect the sender's domain from connected email.
224Ôćĺfunc inferSenderDomain(d *sql.DB) string {
225Ôćĺ	var fromEmail string
226Ôćĺ	err := d.QueryRow("SELECT from_email FROM emails LIMIT 1").Scan(&fromEmail)
227Ôćĺ	if err != nil {
228Ôćĺ		return ""
229Ôćĺ	}
230Ôćĺ	parts := strings.SplitN(fromEmail, "@", 2)
231Ôćĺ	if len(parts) == 2 {
232Ôćĺ		return strings.ToLower(parts[1])
233Ôćĺ	}
234Ôćĺ	return ""
235Ôćĺ}
