 27Ôćĺvar sendCmd = &cobra.Command{
 28Ôćĺ	Use:   "send",
 29Ôćĺ	Short: "Send an email via Unipile",
 30Ôćĺ	Long:  "Send an email through your connected email account via Convex + Unipile.",
 31Ôćĺ	RunE: func(cmd *cobra.Command, args []string) error {
 32Ôćĺ		if sendSequence != "" && sendTaskID != "" {
 33Ôćĺ			return fmt.Errorf("--sequence and --task-id cannot be used together")
 34Ôćĺ		}
 35Ôćĺ
 36Ôćĺ		// Load auth token
 37Ôćĺ		authFile, err := account.LoadAuth()
 38Ôćĺ		if err != nil || authFile.Token == "" {
 39Ôćĺ			return fmt.Errorf("not logged in. Run: nurge account login")
 40Ôćĺ		}
 41Ôćĺ
 42Ôćĺ		// If --task-id is provided, resolve draft content from local DB for defaults
 43Ôćĺ		if sendTaskID != "" {
 44Ôćĺ			d, err := db.Open()
 45Ôćĺ			if err != nil {
 46Ôćĺ				return fmt.Errorf("opening database: %w", err)
 47Ôćĺ			}
 48Ôćĺ			defer d.Close()
 49Ôćĺ
 50Ôćĺ			task, err := sequence.TaskByID(d, sendTaskID)
 51Ôćĺ			if err != nil {
 52Ôćĺ				return err
 53Ôćĺ			}
 54Ôćĺ			if sendTo == "" {
 55Ôćĺ				sendTo = task.ContactEmail
 56Ôćĺ			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 57Ôćĺ				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 58Ôćĺ			}
 59Ôćĺ			if sendSubject == "" || sendBody == "" {
 60Ôćĺ				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 61Ôćĺ				if err != nil {
 62Ôćĺ					return err
 63Ôćĺ				}
 64Ôćĺ				if sendSubject == "" {
 65Ôćĺ					sendSubject = renderedSubject
 66Ôćĺ				}
 67Ôćĺ				if sendBody == "" {
 68Ôćĺ					sendBody = renderedBody
 69Ôćĺ				}
 70Ôćĺ			}
 71Ôćĺ		}
 72Ôćĺ
 73Ôćĺ		if sendTo == "" {
 74Ôćĺ			return fmt.Errorf("recipient (--to) is required")
 75Ôćĺ		}
 76Ôćĺ		if sendSubject == "" {
 77Ôćĺ			return fmt.Errorf("subject (--subject) is required")
 78Ôćĺ		}
 79Ôćĺ		if sendBody == "" {
 80Ôćĺ			return fmt.Errorf("body (--body) is required")
 81Ôćĺ		}
 82Ôćĺ
 83Ôćĺ		// Build request
 84Ôćĺ		req := account.SendEmailRequest{
 85Ôćĺ			To:       strings.TrimSpace(sendTo),
 86Ôćĺ			Cc:       strings.TrimSpace(sendCc),
 87Ôćĺ			Subject:  sendSubject,
 88Ôćĺ			Body:     sendBody,
 89Ôćĺ			SendType: sequence.NormalizeSendType(sendSendType),
 90Ôćĺ			Sync:     true, // CLI-initiated sends are always sync
 91Ôćĺ			TaskID:   sendTaskID,
 92Ôćĺ		}
 93Ôćĺ
 94Ôćĺ		// Sequence enrollment
 95Ôćĺ		if sendSequence != "" {
 96Ôćĺ			req.SendType = sequence.SendTypeFirstTouch
 97Ôćĺ
 98Ôćĺ			d, err := db.Open()
 99Ôćĺ			if err != nil {
100Ôćĺ				return fmt.Errorf("opening database: %w", err)
101Ôćĺ			}
102Ôćĺ			defer d.Close()
103Ôćĺ
104Ôćĺ			seqReq := &account.SequenceRequest{
105Ôćĺ				SequenceName: sendSequence,
106Ôćĺ				CampaignName: sendCampaign,
107Ôćĺ				ContactName:  sendContactName,
108Ôćĺ			}
109Ôćĺ
110Ôćĺ			// Best-effort mailbox resolution for Convex
111Ôćĺ			if sendCampaign != "" {
112Ôćĺ				if campaign, cErr := sequence.CampaignByName(d, sendCampaign); cErr == nil {
113Ôćĺ					if mbx, mErr := sequence.CampaignMailbox(d, campaign); mErr == nil && mbx != nil {
114Ôćĺ						seqReq.MailboxID = mbx.ID
115Ôćĺ					}
116Ôćĺ				}
117Ôćĺ			}
118Ôćĺ
119Ôćĺ			// Get steps from built-in template
120Ôćĺ			tmpl, tmplErr := sequence.TemplateByName(d, sendSequence)
121Ôćĺ			if tmplErr == nil {
122Ôćĺ				for _, step := range tmpl.Steps {
123Ôćĺ					if step.StepNumber <= 1 {
124Ôćĺ						continue // skip first touch, that's the current send
125Ôćĺ					}
126Ôćĺ					seqReq.Steps = append(seqReq.Steps, account.SequenceStep{
127Ôćĺ						StepNumber: step.StepNumber,
128Ôćĺ						StepName:   step.Name,
129Ôćĺ						SendType:   step.SendType,
130Ôćĺ						DelayDays:  parseDays(step.Delay),
131Ôćĺ					})
132Ôćĺ				}
133Ôćĺ			}
134Ôćĺ
135Ôćĺ			req.Sequence = seqReq
136Ôćĺ		}
137Ôćĺ
138Ôćĺ		// Call Convex
139Ôćĺ		client := account.NewConvexClient(GetConvexURL())
140Ôćĺ		resp, err := client.SendEmail(authFile.Token, req)
141Ôćĺ		if err != nil {
142Ôćĺ			return fmt.Errorf("send failed: %w", err)
143Ôćĺ		}
144Ôćĺ
145Ôćĺ		if resp.Queued {
146Ôćĺ			fmt.Printf("  \033[33mÔĆ│\033[0m Queued for %s (task: %s)\n", sendTo, resp.TaskID)
147Ôćĺ		} else {
148Ôćĺ			fmt.Printf("  \033[32mÔťô\033[0m Sent to %s (message ID: %s)\n", sendTo, resp.MessageID)
149Ôćĺ		}
150Ôćĺ
151Ôćĺ		if resp.EnrollmentID != "" {
152Ôćĺ			fmt.Printf("  Ôć│ Enrolled in sequence %s (%s)\n", sendSequence, resp.EnrollmentID)
153Ôćĺ		}
154Ôćĺ
155Ôćĺ		return nil
156Ôćĺ	},
157Ôćĺ}
