200Ôćĺvar skillsWriteCmd = &cobra.Command{
201Ôćĺ	Use:   "write",
202Ôćĺ	Short: "Write multiple skill files from stdin (one CLI call instead of many file writes)",
203Ôćĺ	Long: `Reads a JSON array from stdin: [{"name": "outbound", "content": "---\nname: nurge-outbound\n..."}]
204ÔćĺWrites each as .claude/skills/nurge-{name}/SKILL.md.
205ÔćĺAlso saves each version to the database for tracking.
206ÔćĺReturns a compact summary instead of echoing all file contents back.`,
207Ôćĺ	RunE: func(cmd *cobra.Command, args []string) error {
208Ôćĺ		var entries []skillEntry
209Ôćĺ		if err := json.NewDecoder(os.Stdin).Decode(&entries); err != nil {
210Ôćĺ			return fmt.Errorf("parsing stdin: %w", err)
211Ôćĺ		}
212Ôćĺ		if len(entries) == 0 {
213Ôćĺ			return fmt.Errorf("no skills provided")
214Ôćĺ		}
215Ôćĺ
216Ôćĺ		// Write skill files to disk.
217Ôćĺ		var written []string
218Ôćĺ		for _, e := range entries {
219Ôćĺ			if e.Name == "" || e.Content == "" {
220Ôćĺ				return fmt.Errorf("each skill must have 'name' and 'content' fields")
221Ôćĺ			}
222Ôćĺ			name := e.Name
223Ôćĺ			// Normalize: allow both "outbound" and "nurge-outbound".
224Ôćĺ			if !strings.HasPrefix(name, "nurge-") {
225Ôćĺ				name = "nurge-" + name
226Ôćĺ			}
227Ôćĺ
228Ôćĺ			dir := filepath.Join(".claude", "skills", name)
229Ôćĺ			if err := os.MkdirAll(dir, 0755); err != nil {
230Ôćĺ				return fmt.Errorf("creating dir %s: %w", dir, err)
231Ôćĺ			}
232Ôćĺ			path := filepath.Join(dir, "SKILL.md")
233Ôćĺ			if err := os.WriteFile(path, []byte(e.Content), 0644); err != nil {
234Ôćĺ				return fmt.Errorf("writing %s: %w", path, err)
235Ôćĺ			}
236Ôćĺ			written = append(written, name)
237Ôćĺ		}
238Ôćĺ
239Ôćĺ		// Save versions to DB if available.
240Ôćĺ		d, err := db.Open()
241Ôćĺ		if err == nil {
242Ôćĺ			defer d.Close()
243Ôćĺ			counts, err := session.CurrentSnapshotCounts(d)
244Ôćĺ			if err == nil {
245Ôćĺ				for _, e := range entries {
246Ôćĺ					name := e.Name
247Ôćĺ					if !strings.HasPrefix(name, "nurge-") {
248Ôćĺ						name = "nurge-" + name
249Ôćĺ					}
250Ôćĺ					_, _ = session.SaveSkillVersion(d, name, e.Content, counts.EmailCount, counts.LearningCount)
251Ôćĺ				}
252Ôćĺ			}
253Ôćĺ		}
254Ôćĺ
255Ôćĺ		fmt.Printf("  Ôťô Wrote %d skills: %s\n", len(written), strings.Join(written, ", "))
256Ôćĺ		return nil
257Ôćĺ	},
258Ôćĺ}
