299Ôćĺfunc readSkillContent(path string) (string, error) {
300Ôćĺ	var data []byte
301Ôćĺ	var err error
302Ôćĺ	if strings.TrimSpace(path) != "" {
303Ôćĺ		data, err = os.ReadFile(path)
304Ôćĺ		if err != nil {
305Ôćĺ			return "", fmt.Errorf("reading skill content: %w", err)
306Ôćĺ		}
307Ôćĺ	} else {
308Ôćĺ		data, err = io.ReadAll(os.Stdin)
309Ôćĺ		if err != nil {
310Ôćĺ			return "", fmt.Errorf("reading stdin: %w", err)
311Ôćĺ		}
312Ôćĺ	}
313Ôćĺ
314Ôćĺ	content := strings.TrimSpace(string(data))
315Ôćĺ	if content == "" {
316Ôćĺ		return "", fmt.Errorf("no skill content provided")
317Ôćĺ	}
318Ôćĺ	return content, nil
319Ôćĺ}
