242Ôćĺfunc executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
243Ôćĺ	results := make([]dispatcherExecutionResult, 0, len(dispatch))
244Ôćĺ	for _, item := range dispatch {
245Ôćĺ		if !item.Ready {
246Ôćĺ			continue
247Ôćĺ		}
248Ôćĺ
249Ôćĺ		attemptedAt := timeNow()
250Ôćĺ		fromAddress := strings.TrimSpace(item.TransportEmail)
251Ôćĺ		if fromAddress == "" {
252Ôćĺ			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
253Ôćĺ		}
254Ôćĺ		if fromAddress == "" {
255Ôćĺ			results = append(results, dispatcherExecutionResult{
256Ôćĺ				TaskID:       item.ID,
257Ôćĺ				ContactEmail: item.ContactEmail,
258Ôćĺ				MailboxEmail: item.SelectedMailboxEmail,
259Ôćĺ				Status:       "failed",
260Ôćĺ				Error:        "no transport address available for task",
261Ôćĺ			})
262Ôćĺ			continue
263Ôćĺ		}
264Ôćĺ
265Ôćĺ		sent, err := email.Send(srv, fromAddress, email.SendOptions{
266Ôćĺ			To:       item.ContactEmail,
267Ôćĺ			Subject:  dispatchSubject(item),
268Ôćĺ			Body:     item.RenderedBody,
269Ôćĺ			ThreadID: item.ThreadID,
270Ôćĺ		})
271Ôćĺ		if err != nil {
272Ôćĺ			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
273Ôćĺ				return results, markErr
274Ôćĺ			}
275Ôćĺ			if updateErr := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusFailed, "", "", err.Error()); updateErr != nil {
276Ôćĺ				return results, updateErr
277Ôćĺ			}
278Ôćĺ			if logErr := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
279Ôćĺ				MailboxID:    item.SelectedMailboxID,
280Ôćĺ				EnrollmentID: item.EnrollmentID,
281Ôćĺ				TaskID:       item.ID,
282Ôćĺ				ContactEmail: item.ContactEmail,
283Ôćĺ				SendType:     item.SendType,
284Ôćĺ				Status:       "failed",
285Ôćĺ				Subject:      dispatchSubject(item),
286Ôćĺ				Error:        err.Error(),
287Ôćĺ				AttemptedAt:  attemptedAt,
288Ôćĺ			}); logErr != nil {
289Ôćĺ				return results, logErr
290Ôćĺ			}
291Ôćĺ			results = append(results, dispatcherExecutionResult{
292Ôćĺ				TaskID:       item.ID,
293Ôćĺ				ContactEmail: item.ContactEmail,
294Ôćĺ				MailboxEmail: item.SelectedMailboxEmail,
295Ôćĺ				Status:       "failed",
296Ôćĺ				Error:        err.Error(),
297Ôćĺ			})
298Ôćĺ			continue
299Ôćĺ		}
300Ôćĺ
301Ôćĺ		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
302Ôćĺ			return results, err
303Ôćĺ		}
304Ôćĺ		if err := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
305Ôćĺ			return results, err
306Ôćĺ		}
307Ôćĺ		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
308Ôćĺ			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
309Ôćĺ		}
310Ôćĺ		if err := email.StoreEmail(d, &email.RawMessage{
311Ôćĺ			ID:        sent.MessageID,
312Ôćĺ			Source:    "gmail",
313Ôćĺ			Direction: "outbound",
314Ôćĺ			ThreadID:  sent.ThreadID,
315Ôćĺ			Subject:   dispatchSubject(item),
316Ôćĺ			FromEmail: fromAddress,
317Ôćĺ			ToEmails:  recipientsJSON(item.ContactEmail),
318Ôćĺ			Date:      attemptedAt.UTC().Format(time.RFC3339),
319Ôćĺ			Labels:    `["SENT"]`,
320Ôćĺ		}); err != nil {
321Ôćĺ			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
322Ôćĺ		}
323Ôćĺ		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
324Ôćĺ			TaskID:    item.ID,
325Ôćĺ			ThreadID:  sent.ThreadID,
326Ôćĺ			MessageID: sent.MessageID,
327Ôćĺ			MailboxID: item.SelectedMailboxID,
328Ôćĺ			SentAt:    attemptedAt,
329Ôćĺ		}); err != nil {
330Ôćĺ			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
331Ôćĺ		}
332Ôćĺ		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
333Ôćĺ			MailboxID:    item.SelectedMailboxID,
334Ôćĺ			EnrollmentID: item.EnrollmentID,
335Ôćĺ			TaskID:       item.ID,
336Ôćĺ			ContactEmail: item.ContactEmail,
337Ôćĺ			SendType:     item.SendType,
338Ôćĺ			Status:       "sent",
339Ôćĺ			Subject:      dispatchSubject(item),
340Ôćĺ			MessageID:    sent.MessageID,
341Ôćĺ			AttemptedAt:  attemptedAt,
342Ôćĺ		}); err != nil {
343Ôćĺ			return results, err
344Ôćĺ		}
345Ôćĺ
346Ôćĺ		results = append(results, dispatcherExecutionResult{
347Ôćĺ			TaskID:       item.ID,
348Ôćĺ			ContactEmail: item.ContactEmail,
349Ôćĺ			MailboxEmail: item.SelectedMailboxEmail,
350Ôćĺ			MessageID:    sent.MessageID,
351Ôćĺ			Status:       "sent",
352Ôćĺ		})
353Ôćĺ	}
354Ôćĺ	return results, nil
355Ôćĺ}
