357Ôćĺfunc preview(body string, limit int) string {
358Ôćĺ	body = strings.TrimSpace(body)
359Ôćĺ	body = strings.ReplaceAll(body, "\n", " ")
360Ôćĺ	if limit <= 0 || len(body) <= limit {
361Ôćĺ		return body
362Ôćĺ	}
363Ôćĺ	return body[:limit-1] + "ÔÇŽ"
364Ôćĺ}
365Ôćĺ
366Ôćĺfunc dispatchSubject(item sequence.DispatchTask) string {
367Ôćĺ	if strings.TrimSpace(item.RenderedSubject) != "" {
368Ôćĺ		return strings.TrimSpace(item.RenderedSubject)
369Ôćĺ	}
370Ôćĺ	return strings.TrimSpace(item.Subject)
371Ôćĺ}
