373Ôćĺfunc shellSnippet(value string) string {
374Ôćĺ	if value == "" {
375Ôćĺ		return "''"
376Ôćĺ	}
377Ôćĺ	return "'" + strings.ReplaceAll(value, "'", `'"'"'`) + "'"
378Ôćĺ}
