  9Ôćĺ
 10Ôćĺ// Options holds CLI flags for nurge init.
 11Ôćĺtype Options struct {
 12Ôćĺ	SkipHooks bool
 13Ôćĺ	Force     bool
 14Ôćĺ	Verbose   bool
 15Ôćĺ}
 16Ôćĺ
 17Ôćĺ// Step is the interface each init step implements.
 18Ôćĺtype Step interface {
 19Ôćĺ	Name() string
 20Ôćĺ	Done() (bool, error)
 21Ôćĺ	Run() error
 22Ôćĺ}
 23Ôćĺ
 24Ôćĺ// Run executes all init steps in order.
 25Ôćĺfunc Run(opts Options) error {
 26Ôćĺ	fmt.Println()
 27Ôćĺ	fmt.Println("  nurge ÔÇö outbound that learns")
 28Ôćĺ	fmt.Println()
 29Ôćĺ
 30Ôćĺ	steps := buildSteps(opts)
 31Ôćĺ
 32Ôćĺ	for _, s := range steps {
 33Ôćĺ		if !opts.Force {
 34Ôćĺ			done, err := s.Done()
 35Ôćĺ			if err != nil {
 36Ôćĺ				printFail(s.Name(), err)
 37Ôćĺ				return err
 38Ôćĺ			}
 39Ôćĺ			if done {
 40Ôćĺ				printSkip(s.Name())
 41Ôćĺ				continue
 42Ôćĺ			}
 43Ôćĺ		}
 44Ôćĺ
 45Ôćĺ		if err := s.Run(); err != nil {
 46Ôćĺ			printFail(s.Name(), err)
 47Ôćĺ			return err
 48Ôćĺ		}
 49Ôćĺ		printDone(s.Name())
 50Ôćĺ	}
 51Ôćĺ
 52Ôćĺ	return nil
 53Ôćĺ}
 54Ôćĺ
 55Ôćĺfunc buildSteps(opts Options) []Step {
 56Ôćĺ	var steps []Step
 57Ôćĺ
 58Ôćĺ	steps = append(steps, &projectStep{})
 59Ôćĺ	steps = append(steps, &databaseStep{})
 60Ôćĺ	steps = append(steps, &gitignoreStep{})
 61Ôćĺ
 62Ôćĺ	if !opts.SkipHooks {
 63Ôćĺ		steps = append(steps, &hooksStep{})
 64Ôćĺ	}
 65Ôćĺ
 66Ôćĺ	steps = append(steps, &skillStep{})
 67Ôćĺ	steps = append(steps, &gitStep{})
 68Ôćĺ	steps = append(steps, &nextStepStep{})
 69Ôćĺ
 70Ôćĺ	return steps
 71Ôćĺ}
 72Ôćĺ
 73Ôćĺfunc printDone(name string) {
 74Ôćĺ	fmt.Fprintf(os.Stdout, "  \033[32mÔťô\033[0m %s\n", name)
 75Ôćĺ}
 76Ôćĺ
 77Ôćĺfunc printSkip(name string) {
 78Ôćĺ	fmt.Fprintf(os.Stdout, "  \033[32mÔťô\033[0m %s (already done)\n", name)
 79Ôćĺ}
 80Ôćĺ
 81Ôćĺfunc printFail(name string, err error) {
 82Ôćĺ	fmt.Fprintf(os.Stderr, "  \033[31mÔťŚ\033[0m %s: %v\n", name, err)
 83Ôćĺ}
