 85Ôćĺ// IsDirEmpty returns true if dir contains no entries except allowed ones
 86Ôćĺ// (.nurge, .git, .gitignore, .DS_Store, .claude).
 87Ôćĺfunc IsDirEmpty(dir string) (bool, error) {
 88Ôćĺ	allowed := map[string]bool{
 89Ôćĺ		".nurge":     true,
 90Ôćĺ		".git":       true,
 91Ôćĺ		".gitignore": true,
 92Ôćĺ		".DS_Store":  true,
 93Ôćĺ		".claude":    true,
 94Ôćĺ	}
 95Ôćĺ
 96Ôćĺ	entries, err := os.ReadDir(dir)
 97Ôćĺ	if err != nil {
 98Ôćĺ		return false, err
 99Ôćĺ	}
100Ôćĺ	for _, e := range entries {
101Ôćĺ		name := strings.TrimSuffix(e.Name(), "/")
102Ôćĺ		if !allowed[name] {
103Ôćĺ			return false, nil
104Ôćĺ		}
105Ôćĺ	}
106Ôćĺ	return true, nil
107Ôćĺ}
108Ôćĺ
109Ôćĺ// IsNurgeProject returns true if dir contains a .nurge/ directory.
110Ôćĺfunc IsNurgeProject(dir string) bool {
111Ôćĺ	info, err := os.Stat(filepath.Join(dir, ".nurge"))
112Ôćĺ	return err == nil && info.IsDir()
113Ôćĺ}
