 10Ôćĺ
 11Ôćĺconst configFile = ".nurge/config.json"
 12Ôćĺ
 13Ôćĺ// ConnectorState holds the state of a single connected service.
 14Ôćĺtype ConnectorState struct {
 15Ôćĺ	Connected   bool   `json:"connected"`
 16Ôćĺ	ConnectedAt string `json:"connected_at,omitempty"`
 17Ôćĺ	Account     string `json:"account,omitempty"`
 18Ôćĺ	Type        string `json:"type"` // "crm" or "email"
 19Ôćĺ}
 20Ôćĺ
 21Ôćĺ// Config is the top-level nurge configuration.
 22Ôćĺtype Config struct {
 23Ôćĺ	Version        int                        `json:"version"`
 24Ôćĺ	CreatedAt      string                     `json:"created_at"`
 25Ôćĺ	Connectors     map[string]ConnectorState  `json:"connectors"`
 26Ôćĺ	SetupCompleted bool                       `json:"setup_completed"`
 27Ôćĺ	Settings       map[string]string          `json:"settings,omitempty"`
 28Ôćĺ}
 29Ôćĺ
 30Ôćĺ// Path returns the path to config.json.
 31Ôćĺfunc Path() string {
 32Ôćĺ	return configFile
 33Ôćĺ}
 34Ôćĺ
 35Ôćĺ// Default returns a new Config with default values.
 36Ôćĺfunc Default() *Config {
 37Ôćĺ	return &Config{
 38Ôćĺ		Version:        1,
 39Ôćĺ		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 40Ôćĺ		Connectors:     make(map[string]ConnectorState),
 41Ôćĺ		SetupCompleted: false,
 42Ôćĺ	}
 43Ôćĺ}
 44Ôćĺ
 45Ôćĺ// Load reads config from disk.
 46Ôćĺfunc Load() (*Config, error) {
 47Ôćĺ	data, err := os.ReadFile(configFile)
 48Ôćĺ	if err != nil {
 49Ôćĺ		return nil, fmt.Errorf("reading config: %w", err)
 50Ôćĺ	}
 51Ôćĺ	var cfg Config
 52Ôćĺ	if err := json.Unmarshal(data, &cfg); err != nil {
 53Ôćĺ		return nil, fmt.Errorf("parsing config: %w", err)
 54Ôćĺ	}
 55Ôćĺ	if cfg.Connectors == nil {
 56Ôćĺ		cfg.Connectors = make(map[string]ConnectorState)
 57Ôćĺ	}
 58Ôćĺ	return &cfg, nil
 59Ôćĺ}
 60Ôćĺ
 61Ôćĺ// Write saves config to disk.
 62Ôćĺfunc Write(cfg *Config) error {
 63Ôćĺ	data, err := json.MarshalIndent(cfg, "", "  ")
 64Ôćĺ	if err != nil {
 65Ôćĺ		return fmt.Errorf("marshaling config: %w", err)
 66Ôćĺ	}
 67Ôćĺ	if err := os.WriteFile(configFile, data, 0644); err != nil {
 68Ôćĺ		return fmt.Errorf("writing config: %w", err)
 69Ôćĺ	}
 70Ôćĺ	return nil
 71Ôćĺ}
 72Ôćĺ
 73Ôćĺ// SetConnector updates a connector in the config and saves.
 74Ôćĺfunc SetConnector(id, connType, account string) error {
 75Ôćĺ	cfg, err := Load()
 76Ôćĺ	if err != nil {
 77Ôćĺ		return err
 78Ôćĺ	}
 79Ôćĺ	cfg.Connectors[id] = ConnectorState{
 80Ôćĺ		Connected:   true,
 81Ôćĺ		ConnectedAt: time.Now().UTC().Format(time.RFC3339),
 82Ôćĺ		Account:     account,
 83Ôćĺ		Type:        connType,
 84Ôćĺ	}
 85Ôćĺ	return Write(cfg)
 86Ôćĺ}
 87Ôćĺ
 88Ôćĺ// RemoveConnector removes a connector from config and saves.
 89Ôćĺfunc RemoveConnector(id string) error {
 90Ôćĺ	cfg, err := Load()
 91Ôćĺ	if err != nil {
 92Ôćĺ		return err
 93Ôćĺ	}
 94Ôćĺ	delete(cfg.Connectors, id)
 95Ôćĺ	return Write(cfg)
 96Ôćĺ}
 97Ôćĺ
 98Ôćĺ// Get returns the value for a settings key, or empty string if not set.
 99Ôćĺfunc Get(key string) (string, error) {
100Ôćĺ	cfg, err := Load()
101Ôćĺ	if err != nil {
102Ôćĺ		return "", err
103Ôćĺ	}
104Ôćĺ	if cfg.Settings == nil {
105Ôćĺ		return "", nil
106Ôćĺ	}
107Ôćĺ	return cfg.Settings[key], nil
108Ôćĺ}
109Ôćĺ
110Ôćĺ// Set stores a key/value pair in settings and saves the config.
111Ôćĺfunc Set(key, value string) error {
112Ôćĺ	cfg, err := Load()
113Ôćĺ	if err != nil {
114Ôćĺ		return err
115Ôćĺ	}
116Ôćĺ	if cfg.Settings == nil {
117Ôćĺ		cfg.Settings = make(map[string]string)
118Ôćĺ	}
119Ôćĺ	cfg.Settings[key] = value
120Ôćĺ	return Write(cfg)
121Ôćĺ}
122Ôćĺ
123Ôćĺ// SetSetupCompleted sets the top-level setup_completed flag and saves.
124Ôćĺ// When marking as complete, also removes the global setup skill ÔÇö it's no longer needed.
125Ôćĺfunc SetSetupCompleted(completed bool) error {
126Ôćĺ	cfg, err := Load()
127Ôćĺ	if err != nil {
128Ôćĺ		return err
129Ôćĺ	}
130Ôćĺ	cfg.SetupCompleted = completed
131Ôćĺ	if err := Write(cfg); err != nil {
132Ôćĺ		return err
133Ôćĺ	}
134Ôćĺ	if completed {
135Ôćĺ		removeSetupSkill()
136Ôćĺ	}
137Ôćĺ	return nil
138Ôćĺ}
