140Ôćĺ// removeSetupSkill deletes the global setup skill directory.
141Ôćĺ// Graceful ÔÇö ignores errors if already removed.
142Ôćĺfunc removeSetupSkill() {
143Ôćĺ	home, err := os.UserHomeDir()
144Ôćĺ	if err != nil {
145Ôćĺ		return
146Ôćĺ	}
147Ôćĺ	os.RemoveAll(filepath.Join(home, ".claude", "skills", "nurge-setup"))
