176Ôćĺfunc recipientsJSON(raw string) string {
177Ôćĺ	raw = strings.TrimSpace(raw)
178Ôćĺ	if raw == "" {
179Ôćĺ		return "[]"
180Ôćĺ	}
181Ôćĺ	parts := strings.Split(raw, ",")
182Ôćĺ	recipients := make([]string, 0, len(parts))
183Ôćĺ	for _, part := range parts {
184Ôćĺ		part = strings.TrimSpace(part)
185Ôćĺ		if part != "" {
186Ôćĺ			recipients = append(recipients, part)
187Ôćĺ		}
188Ôćĺ	}
189Ôćĺ	data, _ := json.Marshal(recipients)
190Ôćĺ	return string(data)
191Ôćĺ}
