193Ôćĺ// parseDays extracts day count from a duration string like "3d" or "72h".
194Ôćĺfunc parseDays(delay string) int {
195Ôćĺ	delay = strings.TrimSpace(delay)
196Ôćĺ	if delay == "" || delay == "0s" {
197Ôćĺ		return 0
198Ôćĺ	}
199Ôćĺ	// Handle "Xd" format
200Ôćĺ	if strings.HasSuffix(delay, "d") {
201Ôćĺ		var d int
202Ôćĺ		fmt.Sscanf(delay, "%dd", &d)
203Ôćĺ		return d
204Ôćĺ	}
205Ôćĺ	// Handle "Xh" format
206Ôćĺ	if strings.HasSuffix(delay, "h") {
207Ôćĺ		var h int
208Ôćĺ		fmt.Sscanf(delay, "%dh", &h)
209Ôćĺ		return h / 24
210Ôćĺ	}
211Ôćĺ	return 3 // default
212Ôćĺ}
