173Ôćĺfunc relativeDueStatus(value string, now time.Time) string {
174Ôćĺ	dueAt, err := time.Parse(time.RFC3339, value)
175Ôćĺ	if err != nil {
176Ôćĺ		return "due"
177Ôćĺ	}
178Ôćĺ
179Ôćĺ	delta := dueAt.Sub(now.UTC())
180Ôćĺ	if delta >= 0 {
181Ôćĺ		if delta < time.Minute {
182Ôćĺ			return "due soon"
183Ôćĺ		}
184Ôćĺ		if delta < time.Hour {
185Ôćĺ			return fmt.Sprintf("in %dm", int(delta.Round(time.Minute)/time.Minute))
186Ôćĺ		}
187Ôćĺ		if delta < 24*time.Hour {
188Ôćĺ			return fmt.Sprintf("in %dh", int(delta.Round(time.Hour)/time.Hour))
189Ôćĺ		}
190Ôćĺ		return fmt.Sprintf("in %dd", int(delta.Hours()/24))
191Ôćĺ	}
192Ôćĺ
193Ôćĺ	overdue := -delta
194Ôćĺ	if overdue < time.Hour {
195Ôćĺ		return fmt.Sprintf("%dm overdue", int(overdue.Round(time.Minute)/time.Minute))
196Ôćĺ	}
197Ôćĺ	if overdue < 24*time.Hour {
198Ôćĺ		return fmt.Sprintf("%dh overdue", int(overdue.Round(time.Hour)/time.Hour))
199Ôćĺ	}
200Ôćĺ	return fmt.Sprintf("%dd overdue", int(overdue.Hours()/24))
201Ôćĺ}
