 52Ôćĺ
 53Ôćĺ	projectRoot, err := filepath.Abs(opts.ProjectRoot)
 54Ôćĺ	if err != nil {
 55Ôćĺ		return nil, fmt.Errorf("resolving project root: %w", err)
 56Ôćĺ	}
 57Ôćĺ	executablePath, err := filepath.Abs(opts.ExecutablePath)
