 64Ôćĺ	plistPath := filepath.Join(projectRoot, dispatcherPlistRelativePath)
 65Ôćĺ
 66Ôćĺ	if err := os.MkdirAll(filepath.Dir(scriptPath), 0755); err != nil {
 67Ôćĺ		return nil, fmt.Errorf("creating wrapper directory: %w", err)
 68Ôćĺ	}
 69Ôćĺ	if err := os.MkdirAll(filepath.Dir(logPath), 0755); err != nil {
 70Ôćĺ		return nil, fmt.Errorf("creating log directory: %w", err)
 71Ôćĺ	}
 72Ôćĺ	if err := os.MkdirAll(filepath.Dir(plistPath), 0755); err != nil {
 73Ôćĺ		return nil, fmt.Errorf("creating automation directory: %w", err)
 74Ôćĺ	}
 75Ôćĺ
 76Ôćĺ	script, err := BuildDispatcherScript(projectRoot, executablePath, DispatcherOptions{
 77Ôćĺ		ProjectRoot:     projectRoot,
 78Ôćĺ		ExecutablePath:  executablePath,
 79Ôćĺ		IntervalMinutes: opts.IntervalMinutes,
 80Ôćĺ		SyncReplies:     opts.SyncReplies,
 81Ôćĺ		TransportEmail:  opts.TransportEmail,
 82Ôćĺ	})
 83Ôćĺ	if err != nil {
 84Ôćĺ		return nil, err
 85Ôćĺ	}
