 93Ôćĺ		return nil, fmt.Errorf("writing launchd plist: %w", err)
 94Ôćĺ	}
 95Ôćĺ
 96Ôćĺ	cronLine, _ := CronLine(scriptPath, opts.IntervalMinutes)
 97Ôćĺ
 98Ôćĺ	assets := &DispatcherAssets{
 99Ôćĺ		ProjectRoot:      projectRoot,
100Ôćĺ		ScriptPath:       scriptPath,
101Ôćĺ		LogPath:          logPath,
102Ôćĺ		CronLine:         cronLine,
103Ôćĺ		LaunchdLabel:     label,
104Ôćĺ		LaunchdPlistPath: plistPath,
105Ôćĺ		IntervalMinutes:  opts.IntervalMinutes,
