119Ôćĺ// BuildDispatcherScript renders a shell wrapper that always runs from the
120Ôćĺ// project root and appends output to the project's dispatcher log.
121Ôćĺfunc BuildDispatcherScript(projectRoot, executablePath string, opts DispatcherOptions) (string, error) {
122Ôćĺ	projectRoot = strings.TrimSpace(projectRoot)
123Ôćĺ	executablePath = strings.TrimSpace(executablePath)
124Ôćĺ	if projectRoot == "" {
125Ôćĺ		return "", fmt.Errorf("project root is required")
126Ôćĺ	}
127Ôćĺ	if executablePath == "" {
128Ôćĺ		return "", fmt.Errorf("executable path is required")
129Ôćĺ	}
130Ôćĺ
131Ôćĺ	logPath := filepath.Join(projectRoot, dispatcherLogRelativePath)
132Ôćĺ
133Ôćĺ	args := []string{
134Ôćĺ		shellQuote(executablePath),
135Ôćĺ		"dispatcher",
136Ôćĺ		"run",
137Ôćĺ		"--execute",
138Ôćĺ		fmt.Sprintf("--sync-replies=%t", opts.SyncReplies),
139Ôćĺ	}
140Ôćĺ	if transport := strings.TrimSpace(opts.TransportEmail); transport != "" {
141Ôćĺ		args = append(args, "--transport-email", shellQuote(transport))
142Ôćĺ	}
143Ôćĺ
144Ôćĺ	script := strings.Join([]string{
145Ôćĺ		"#!/bin/sh",
146Ôćĺ		"set -eu",
147Ôćĺ		"",
148Ôćĺ		"PROJECT_ROOT=" + shellQuote(projectRoot),
149Ôćĺ		"LOG_PATH=" + shellQuote(logPath),
150Ôćĺ		"",
151Ôćĺ		"mkdir -p \"$(dirname \"$LOG_PATH\")\"",
152Ôćĺ		"cd \"$PROJECT_ROOT\"",
153Ôćĺ		"exec " + strings.Join(args, " ") + " >>\"$LOG_PATH\" 2>&1",
154Ôćĺ		"",
155Ôćĺ	}, "\n")
156Ôćĺ
157Ôćĺ	return script, nil
158Ôćĺ}
