160Ôćĺ// CronLine returns a crontab entry for the generated wrapper when the
161Ôćĺ// requested interval maps cleanly to standard cron syntax.
162Ôćĺfunc CronLine(scriptPath string, intervalMinutes int) (string, bool) {
163Ôćĺ	spec, ok := cronExpression(intervalMinutes)
164Ôćĺ	if !ok {
165Ôćĺ		return "", false
166Ôćĺ	}
167Ôćĺ	return spec + " " + shellQuote(scriptPath), true
168Ôćĺ}
169Ôćĺ
170Ôćĺfunc cronExpression(intervalMinutes int) (string, bool) {
171Ôćĺ	if intervalMinutes <= 0 {
172Ôćĺ		return "", false
173Ôćĺ	}
174Ôćĺ	if intervalMinutes == 1 {
175Ôćĺ		return "* * * * *", true
176Ôćĺ	}
177Ôćĺ	if intervalMinutes < 60 {
178Ôćĺ		if 60%intervalMinutes != 0 {
179Ôćĺ			return "", false
180Ôćĺ		}
181Ôćĺ		return fmt.Sprintf("*/%d * * * *", intervalMinutes), true
182Ôćĺ	}
183Ôćĺ	if intervalMinutes == 60 {
184Ôćĺ		return "0 * * * *", true
185Ôćĺ	}
186Ôćĺ	if intervalMinutes < 24*60 && intervalMinutes%60 == 0 {
187Ôćĺ		hours := intervalMinutes / 60
188Ôćĺ		if 24%hours != 0 {
189Ôćĺ			return "", false
190Ôćĺ		}
191Ôćĺ		return fmt.Sprintf("0 */%d * * *", hours), true
192Ôćĺ	}
193Ôćĺ	if intervalMinutes == 24*60 {
194Ôćĺ		return "0 0 * * *", true
195Ôćĺ	}
196Ôćĺ	return "", false
197Ôćĺ}
198Ôćĺ
199Ôćĺ// BuildLaunchdPlist renders a launchd agent definition that runs the
200Ôćĺ// generated wrapper on a fixed interval.
201Ôćĺfunc BuildLaunchdPlist(label, projectRoot, scriptPath, logPath string, intervalMinutes int) string {
202Ôćĺ	if intervalMinutes <= 0 {
203Ôćĺ		intervalMinutes = 5
204Ôćĺ	}
205Ôćĺ	startIntervalSeconds := intervalMinutes * 60
206Ôćĺ
207Ôćĺ	lines := []string{
208Ôćĺ		`<?xml version="1.0" encoding="UTF-8"?>`,
209Ôćĺ		`<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">`,
210Ôćĺ		`<plist version="1.0">`,
211Ôćĺ		`<dict>`,
212Ôćĺ		`  <key>Label</key>`,
213Ôćĺ		`  <string>` + xmlEscape(label) + `</string>`,
214Ôćĺ		`  <key>ProgramArguments</key>`,
215Ôćĺ		`  <array>`,
216Ôćĺ		`    <string>` + xmlEscape(scriptPath) + `</string>`,
217Ôćĺ		`  </array>`,
218Ôćĺ		`  <key>WorkingDirectory</key>`,
219Ôćĺ		`  <string>` + xmlEscape(projectRoot) + `</string>`,
220Ôćĺ		`  <key>RunAtLoad</key>`,
221Ôćĺ		`  <true/>`,
222Ôćĺ		`  <key>StartInterval</key>`,
223Ôćĺ		fmt.Sprintf("  <integer>%d</integer>", startIntervalSeconds),
224Ôćĺ		`  <key>StandardOutPath</key>`,
225Ôćĺ		`  <string>` + xmlEscape(logPath) + `</string>`,
226Ôćĺ		`  <key>StandardErrorPath</key>`,
227Ôćĺ		`  <string>` + xmlEscape(logPath) + `</string>`,
228Ôćĺ		`</dict>`,
229Ôćĺ		`</plist>`,
230Ôćĺ		"",
231Ôćĺ	}
232Ôćĺ
233Ôćĺ	return strings.Join(lines, "\n")
234Ôćĺ}
235Ôćĺ
236Ôćĺfunc launchdLabel(projectRoot string) string {
237Ôćĺ	base := strings.ToLower(filepath.Base(projectRoot))
238Ôćĺ	base = strings.Map(func(r rune) rune {
239Ôćĺ		switch {
240Ôćĺ		case r >= 'a' && r <= 'z':
241Ôćĺ			return r
242Ôćĺ		case r >= '0' && r <= '9':
243Ôćĺ			return r
244Ôćĺ		default:
245Ôćĺ			return '-'
246Ôćĺ		}
247Ôćĺ	}, base)
248Ôćĺ	base = strings.Trim(base, "-")
249Ôćĺ	for strings.Contains(base, "--") {
250Ôćĺ		base = strings.ReplaceAll(base, "--", "-")
251Ôćĺ	}
252Ôćĺ	if base == "" {
253Ôćĺ		base = "project"
254Ôćĺ	}
255Ôćĺ	return "com.usenurge.dispatcher." + base
256Ôćĺ}
257Ôćĺ
258Ôćĺfunc shellQuote(value string) string {
259Ôćĺ	if value == "" {
260Ôćĺ		return "''"
261Ôćĺ	}
262Ôćĺ	return "'" + strings.ReplaceAll(value, "'", `'"'"'`) + "'"
263Ôćĺ}
264Ôćĺ
265Ôćĺfunc xmlEscape(value string) string {
266Ôćĺ	replacer := strings.NewReplacer(
267Ôćĺ		"&", "&amp;",
268Ôćĺ		"<", "&lt;",
269Ôćĺ		">", "&gt;",
270Ôćĺ		`"`, "&quot;",
271Ôćĺ		"'", "&apos;",
272Ôćĺ	)
273Ôćĺ	return replacer.Replace(value)
274Ôćĺ}
