39Ôćĺ		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
40Ôćĺ	}
41Ôćĺ	if opts.ThreadID != "" {
42Ôćĺ		msg.ThreadId = opts.ThreadID
