48Ôćĺ	}
49Ôćĺ
50Ôćĺ	return &SentMessage{
51Ôćĺ		MessageID: sent.Id,
52Ôćĺ		ThreadID:  sent.ThreadId,
53Ôćĺ	}, nil
54Ôćĺ}
55Ôćĺ
56Ôćĺfunc buildRawMessage(from string, opts SendOptions) string {
57Ôćĺ	var b strings.Builder
58Ôćĺ	b.WriteString("From: " + from + "\r\n")
59Ôćĺ	b.WriteString("To: " + opts.To + "\r\n")
