62Ôćĺ	}
63Ôćĺ	b.WriteString("Subject: " + opts.Subject + "\r\n")
64Ôćĺ	b.WriteString("MIME-Version: 1.0\r\n")
65Ôćĺ	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
