114Ôćĺfunc gatherStatus() *sessionStatus {
115Ôćĺ	s := &sessionStatus{
116Ôćĺ		settings: make(map[string]string),
117Ôćĺ	}
118Ôćĺ
119Ôćĺ	// Load config (graceful ÔÇö may not exist)
120Ôćĺ	cfg, err := project.Load()
121Ôćĺ	if err == nil {
122Ôćĺ		s.configLoaded = true
123Ôćĺ		s.setupCompleted = cfg.SetupCompleted
124Ôćĺ		s.connectors = cfg.Connectors
125Ôćĺ		if cfg.Settings != nil {
126Ôćĺ			s.settings = cfg.Settings
127Ôćĺ		}
128Ôćĺ	}
129Ôćĺ
130Ôćĺ	// Load DB stats (graceful ÔÇö may not exist)
131Ôćĺ	if !db.Exists() {
132Ôćĺ		return s
133Ôćĺ	}
134Ôćĺ	d, err := db.Open()
135Ôćĺ	if err != nil {
136Ôćĺ		return s
137Ôćĺ	}
138Ôćĺ	defer d.Close()
139Ôćĺ
140Ôćĺ	stats, err := email.Stats(d)
141Ôćĺ	if err == nil {
142Ôćĺ		s.emailTotal = stats.Total
143Ôćĺ		s.outboundTotal = stats.ByClass["outbound"]
144Ôćĺ	}
145Ôćĺ
146Ôćĺ	weekly, err := email.ThisWeek(d)
147Ôćĺ	if err == nil {
148Ôćĺ		s.weeklyStats = weekly
149Ôćĺ	}
150Ôćĺ
151Ôćĺ	skills, err := session.ListSkills(d)
152Ôćĺ	if err == nil {
153Ôćĺ		s.skillCount = len(skills)
154Ôćĺ		for _, sk := range skills {
155Ôćĺ			s.skillNames = append(s.skillNames, sk.SkillName)
156Ôćĺ		}
157Ôćĺ	}
158Ôćĺ
159Ôćĺ	// Contact count (graceful)
160Ôćĺ	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
161Ôćĺ
162Ôćĺ	// Learning count (graceful)
163Ôćĺ	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
164Ôćĺ
165Ôćĺ	memories, err := session.ListStrategicMemory(d, 3)
166Ôćĺ	if err == nil {
167Ôćĺ		s.recentStrategicMemory = memories
168Ôćĺ	}
169Ôćĺ
170Ôćĺ	staleSkills, err := session.ListStaleSkills(d, 5)
171Ôćĺ	if err == nil {
172Ôćĺ		s.staleSkills = staleSkills
173Ôćĺ	}
174Ôćĺ
175Ôćĺ	return s
176Ôćĺ}
