178Ôćĺ// hookOutput is the JSON structure Claude Code expects from hook stdout.
179Ôćĺtype hookOutput struct {
180Ôćĺ	SystemMessage   string           `json:"systemMessage,omitempty"`
181Ôćĺ	HookSpecificOut *hookSpecificOut `json:"hookSpecificOutput,omitempty"`
182Ôćĺ}
183Ôćĺ
