189Ôćĺ// runSessionStart outputs JSON with systemMessage (visible banner) and
190Ôćĺ// additionalContext (LLM context) for the SessionStart hook.
191Ôćĺ// Also captures the session in DB + log.
192Ôćĺfunc runSessionStart() error {
193Ôćĺ	// Read stdin (Claude Code sends session info)
194Ôćĺ	input, _ := session.ReadStdin()
195Ôćĺ
196Ôćĺ	// Sync permissions ÔÇö ensures existing users get any new permissions
197Ôćĺ	// added in later versions. Graceful ÔÇö never fails the hook.
198Ôćĺ	project.SyncPermissions()
199Ôćĺ
200Ôćĺ	syncReport := attemptSessionStartSync()
201Ôćĺ
202Ôćĺ	// Auto-update check (non-blocking, cached)
203Ôćĺ	updateMsg := checkAndAutoUpdate()
204Ôćĺ
205Ôćĺ	s := gatherStatus()
206Ôćĺ	s.startSync = syncReport
207Ôćĺ
208Ôćĺ	// Capture session + sync event in a single DB open (graceful ÔÇö don't fail the hook)
209Ôćĺ	if input != nil && input.SessionID != "" && db.Exists() {
210Ôćĺ		if d, err := db.Open(); err == nil {
211Ôćĺ	
212Ôćĺ			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
213Ôćĺ			session.AddEvent(d, input.SessionID, "session_start", input)
214Ôćĺ			if syncReport != nil && syncReport.Attempted {
215Ôćĺ				session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
216Ôćĺ			}
217Ôćĺ			d.Close()
218Ôćĺ		}
219Ôćĺ		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
220Ôćĺ		session.FlushLog()
221Ôćĺ	}
222Ôćĺ
223Ôćĺ	banner := buildBanner(s)
224Ôćĺ	if updateMsg != "" {
225Ôćĺ		banner += "\n  " + updateMsg
226Ôćĺ	}
227Ôćĺ	context := buildPromptContext(s)
228Ôćĺ
229Ôćĺ	out := hookOutput{
230Ôćĺ		SystemMessage: banner,
231Ôćĺ		HookSpecificOut: &hookSpecificOut{
232Ôćĺ			HookEventName:     "SessionStart",
233Ôćĺ			AdditionalContext: context,
234Ôćĺ		},
235Ôćĺ	}
236Ôćĺ
237Ôćĺ	enc := json.NewEncoder(os.Stdout)
238Ôćĺ	return enc.Encode(out)
239Ôćĺ}
