241Ôćĺ// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
242Ôćĺ// Returns (nil, nil, nil) when the hook should silently no-op.
243Ôćĺfunc openSessionDB() (*sql.DB, *session.HookInput, error) {
244Ôćĺ	input, err := session.ReadStdin()
245Ôćĺ	if err != nil || input == nil || input.SessionID == "" {
246Ôćĺ		return nil, nil, nil
247Ôćĺ	}
248Ôćĺ	if !db.Exists() {
249Ôćĺ		return nil, nil, nil
250Ôćĺ	}
251Ôćĺ	d, err := db.Open()
252Ôćĺ	if err != nil {
253Ôćĺ		return nil, nil, nil
254Ôćĺ	}
255Ôćĺ	return d, input, nil
256Ôćĺ}
