272Ôćĺ// runStop captures a stop event and creates a checkpoint.
273Ôćĺfunc runStop() error {
274Ôćĺ	d, input, _ := openSessionDB()
275Ôćĺ	if d == nil {
276Ôćĺ		return nil
277Ôćĺ	}
278Ôćĺ	defer d.Close()
279Ôćĺ
280Ôćĺ	session.AddEvent(d, input.SessionID, "stop", input)
281Ôćĺ	if len(input.ModifiedFiles) > 0 {
282Ôćĺ		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
283Ôćĺ	}
284Ôćĺ
285Ôćĺ	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
286Ôćĺ	session.FlushLog()
287Ôćĺ	return nil
