290Ôćĺ// runSessionEnd marks a session as ended.
291Ôćĺfunc runSessionEnd() error {
292Ôćĺ	d, input, _ := openSessionDB()
293Ôćĺ	if d == nil {
294Ôćĺ		return nil
295Ôćĺ	}
296Ôćĺ	defer d.Close()
297Ôćĺ
298Ôćĺ	session.EndSession(d, input.SessionID)
299Ôćĺ	session.AddEvent(d, input.SessionID, "session_end", input)
300Ôćĺ
301Ôćĺ	pushReport := attemptSessionEndPush(d)
302Ôćĺ	if pushReport.Attempted {
303Ôćĺ		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
304Ôćĺ		if pushReport.Error != "" {
305Ôćĺ			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
306Ôćĺ		} else {
307Ôćĺ			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
308Ôćĺ		}
309Ôćĺ	}
310Ôćĺ
311Ôćĺ	session.Logger().Info("session-end", "session_id", input.SessionID)
312Ôćĺ	session.FlushLog()
313Ôćĺ	return nil
