534Ôćĺfunc attemptSessionStartSync() *sessionSyncReport {
535Ôćĺ	report := &sessionSyncReport{}
536Ôćĺ
537Ôćĺ	if !db.Exists() {
538Ôćĺ		return report
539Ôćĺ	}
540Ôćĺ
541Ôćĺ	d, err := db.Open()
542Ôćĺ	if err != nil {
543Ôćĺ		report.Attempted = true
544Ôćĺ		report.Error = shortSyncError(err)
545Ôćĺ		return report
546Ôćĺ	}
547Ôćĺ	defer d.Close()
548Ôćĺ
549Ôćĺ	engine := loadSyncEngine(d)
550Ôćĺ	if engine == nil {
551Ôćĺ		return report
552Ôćĺ	}
553Ôćĺ
554Ôćĺ	report.Attempted = true
555Ôćĺ	pull, err := engine.Pull()
556Ôćĺ	if err != nil {
557Ôćĺ		report.Error = shortSyncError(err)
558Ôćĺ		return report
559Ôćĺ	}
560Ôćĺ
561Ôćĺ	report.RowsUpserted = pull.RowsUpserted
562Ôćĺ	report.TablesUpdated = pull.TablesUpdated
563Ôćĺ	report.PreviousVersion = pull.PreviousVersion
564Ôćĺ	report.CurrentVersion = pull.CurrentVersion
565Ôćĺ
566Ôćĺ	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
567Ôćĺ	if err == nil {
568Ôćĺ		report.Delta = delta
569Ôćĺ	}
570Ôćĺ	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
571Ôćĺ	if err == nil {
572Ôćĺ		for _, memory := range memories {
573Ôćĺ			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
574Ôćĺ				Category:       memory.Category,
575Ôćĺ				Summary:        memory.Summary,
576Ôćĺ				AffectedSkills: memory.AffectedSkills,
577Ôćĺ				Evidence:       memory.Evidence,
578Ôćĺ				Source:         memory.Source,
579Ôćĺ				SourceKey:      memory.SourceKey,
580Ôćĺ				Priority:       memory.Priority,
581Ôćĺ			})
582Ôćĺ		}
583Ôćĺ	}
584Ôćĺ
585Ôćĺ	return report
586Ôćĺ}
