588Ôćĺfunc attemptSessionEndPush(d *sql.DB) *sessionPushReport {
589Ôćĺ	report := &sessionPushReport{}
590Ôćĺ
591Ôćĺ	if d == nil {
592Ôćĺ		return report
593Ôćĺ	}
594Ôćĺ
595Ôćĺ	engine := loadSyncEngine(d)
596Ôćĺ	if engine == nil {
597Ôćĺ		return report
598Ôćĺ	}
599Ôćĺ
600Ôćĺ	report.Attempted = true
601Ôćĺ	push, err := engine.Push()
602Ôćĺ	if err != nil {
