612Ôćĺfunc buildSyncBannerLine(report *sessionSyncReport) string {
613Ôćĺ	if report == nil || !report.Attempted {
614Ôćĺ		return ""
615Ôćĺ	}
616Ôćĺ	if report.Error != "" {
617Ôćĺ		return "Remote sync unavailable ÔÇö using last local state"
618Ôćĺ	}
619Ôćĺ	if report.RowsUpserted == 0 {
620Ôćĺ		return ""
621Ôćĺ	}
622Ôćĺ
623Ôćĺ	parts := []string{}
624Ôćĺ	if report.Delta != nil {
625Ôćĺ		if report.Delta.TasksSent > 0 {
626Ôćĺ			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
627Ôćĺ		}
628Ôćĺ		if report.Delta.RepliesNeedingAttention > 0 {
629Ôćĺ			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
630Ôćĺ		}
631Ôćĺ		if report.Delta.TasksFailed > 0 {
632Ôćĺ			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
633Ôćĺ		}
634Ôćĺ		if len(report.Delta.AuthExpiredMailboxes) > 0 {
635Ôćĺ			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
636Ôćĺ		}
637Ôćĺ	}
638Ôćĺ	if len(parts) == 0 {
