644Ôćĺfunc buildSyncPromptContext(report *sessionSyncReport) string {
645Ôćĺ	if report == nil || !report.Attempted {
646Ôćĺ		return ""
647Ôćĺ	}
648Ôćĺ
649Ôćĺ	var b strings.Builder
650Ôćĺ	if report.Error != "" {
651Ôćĺ		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
652Ôćĺ		return b.String()
653Ôćĺ	}
654Ôćĺ
655Ôćĺ	if report.RowsUpserted == 0 {
656Ôćĺ		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
657Ôćĺ		return b.String()
658Ôćĺ	}
659Ôćĺ
660Ôćĺ	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
661Ôćĺ		report.RowsUpserted,
662Ôćĺ		pluralSuffix(report.RowsUpserted),
663Ôćĺ		report.TablesUpdated,
664Ôćĺ		pluralSuffix(report.TablesUpdated),
665Ôćĺ	)
666Ôćĺ
667Ôćĺ	if report.Delta == nil {
668Ôćĺ		return b.String()
669Ôćĺ	}
670Ôćĺ
671Ôćĺ	if report.Delta.TasksSent > 0 {
672Ôćĺ		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
673Ôćĺ	}
674Ôćĺ	if report.Delta.TasksFailed > 0 {
675Ôćĺ		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
676Ôćĺ	}
677Ôćĺ	if report.Delta.RepliesNeedingAttention > 0 {
678Ôćĺ		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
679Ôćĺ		for _, item := range report.Delta.RecentReplies {
680Ôćĺ			if strings.TrimSpace(item.Subject) != "" {
681Ôćĺ				fmt.Fprintf(&b, "- Reply: %s (%s) ÔÇö %s\n", item.ContactEmail, item.Classification, item.Subject)
682Ôćĺ				continue
683Ôćĺ			}
684Ôćĺ			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
685Ôćĺ		}
686Ôćĺ	}
687Ôćĺ	if report.Delta.EnrollmentsStopped > 0 {
688Ôćĺ		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
689Ôćĺ	}
690Ôćĺ	if report.Delta.EnrollmentsCompleted > 0 {
691Ôćĺ		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
692Ôćĺ	}
693Ôćĺ	if report.Delta.SuppressionsAdded > 0 {
694Ôćĺ		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
695Ôćĺ	}
696Ôćĺ	if len(report.Delta.AuthExpiredMailboxes) > 0 {
697Ôćĺ		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
698Ôćĺ	}
699Ôćĺ
700Ôćĺ	return b.String()
701Ôćĺ}
