769Ôćĺ// --- Auto-update ---
770Ôćĺ
771Ôćĺconst (
772Ôćĺ	updateCacheFile   = ".nurge/update_check.json"
773Ôćĺ	updateCheckTTL    = 24 * time.Hour
774Ôćĺ	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
775Ôćĺ)
776Ôćĺ
777Ôćĺtype updateCache struct {
778Ôćĺ	LatestVersion string `json:"latest_version"`
779Ôćĺ	CheckedAt     string `json:"checked_at"`
780Ôćĺ	UpdatedAt     string `json:"updated_at,omitempty"`
781Ôćĺ}
782Ôćĺ
783Ôćĺ// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
784Ôćĺ// Returns a message for the banner, or empty string.
785Ôćĺfunc checkAndAutoUpdate() string {
786Ôćĺ	// Read cache
787Ôćĺ	cache := readUpdateCache()
788Ôćĺ
789Ôćĺ	// If checked recently, just report
790Ôćĺ	if cache != nil && cache.CheckedAt != "" {
791Ôćĺ		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
792Ôćĺ		if err == nil && time.Since(checkedAt) < updateCheckTTL {
793Ôćĺ			// Cache is fresh ÔÇö check if we just updated
794Ôćĺ			if cache.UpdatedAt != "" {
795Ôćĺ				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
796Ôćĺ				if err == nil && time.Since(updatedAt) < 5*time.Minute {
797Ôćĺ					// Clear the updated flag for next time
798Ôćĺ					cache.UpdatedAt = ""
799Ôćĺ					writeUpdateCache(cache)
800Ôćĺ					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
801Ôćĺ				}
802Ôćĺ			}
803Ôćĺ			return ""
804Ôćĺ		}
805Ôćĺ	}
806Ôćĺ
807Ôćĺ	// Check for latest version (with timeout)
808Ôćĺ	latest := fetchLatestVersion()
809Ôćĺ	if latest == "" {
810Ôćĺ		// Network failed ÔÇö update cache timestamp so we don't retry immediately
811Ôćĺ		if cache == nil {
812Ôćĺ			cache = &updateCache{}
813Ôćĺ		}
814Ôćĺ		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
815Ôćĺ		writeUpdateCache(cache)
816Ôćĺ		return ""
817Ôćĺ	}
818Ôćĺ
819Ôćĺ	// Save to cache
820Ôćĺ	if cache == nil {
821Ôćĺ		cache = &updateCache{}
822Ôćĺ	}
823Ôćĺ	cache.LatestVersion = latest
824Ôćĺ	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
825Ôćĺ
826Ôćĺ	// Compare: if current version matches latest, no update needed
827Ôćĺ	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
828Ôćĺ		writeUpdateCache(cache)
829Ôćĺ		return ""
830Ôćĺ	}
831Ôćĺ
832Ôćĺ	// Different version ÔÇö auto-update
833Ôćĺ	if runAutoUpdate() {
834Ôćĺ		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
835Ôćĺ		writeUpdateCache(cache)
836Ôćĺ		return fmt.Sprintf("Updating to %s...", latest)
837Ôćĺ	}
838Ôćĺ
839Ôćĺ	writeUpdateCache(cache)
840Ôćĺ	return ""
841Ôćĺ}
842Ôćĺ
843Ôćĺfunc readUpdateCache() *updateCache {
844Ôćĺ	data, err := os.ReadFile(updateCacheFile)
845Ôćĺ	if err != nil {
846Ôćĺ		return nil
847Ôćĺ	}
848Ôćĺ	var c updateCache
849Ôćĺ	if err := json.Unmarshal(data, &c); err != nil {
850Ôćĺ		return nil
851Ôćĺ	}
852Ôćĺ	return &c
853Ôćĺ}
854Ôćĺ
855Ôćĺfunc writeUpdateCache(c *updateCache) {
856Ôćĺ	data, err := json.Marshal(c)
857Ôćĺ	if err != nil {
858Ôćĺ		return
859Ôćĺ	}
860Ôćĺ	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
861Ôćĺ	os.WriteFile(updateCacheFile, data, 0644)
862Ôćĺ}
863Ôćĺ
864Ôćĺ// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
865Ôćĺfunc fetchLatestVersion() string {
866Ôćĺ	client := &http.Client{Timeout: 3 * time.Second}
867Ôćĺ	resp, err := client.Get(githubReleasesURL)
868Ôćĺ	if err != nil {
869Ôćĺ		return ""
870Ôćĺ	}
871Ôćĺ	defer resp.Body.Close()
872Ôćĺ
873Ôćĺ	if resp.StatusCode != 200 {
874Ôćĺ		return ""
875Ôćĺ	}
876Ôćĺ
877Ôćĺ	var release struct {
878Ôćĺ		TagName string `json:"tag_name"`
879Ôćĺ	}
880Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
881Ôćĺ		return ""
882Ôćĺ	}
883Ôćĺ	return release.TagName
884Ôćĺ}
885Ôćĺ
886Ôćĺ// runAutoUpdate runs the install script in the background. Returns true if launched.
887Ôćĺfunc runAutoUpdate() bool {
888Ôćĺ	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
889Ôćĺ	if err := cmd.Start(); err != nil {
890Ôćĺ		return false
891Ôćĺ	}
892Ôćĺ	// Don't wait ÔÇö let it run in background
893Ôćĺ	go cmd.Wait()
894Ôćĺ	return true
895Ôćĺ}
896Ôćĺ
897Ôćĺfunc capitalize(s string) string {
898Ôćĺ	if s == "" {
899Ôćĺ		return s
900Ôćĺ	}
901Ôćĺ	return strings.ToUpper(s[:1]) + s[1:]
902Ôćĺ}
903Ôćĺ
904Ôćĺfunc formatCount(n int) string {
905Ôćĺ	if n >= 1000 {
906Ôćĺ		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
907Ôćĺ	}
908Ôćĺ	return fmt.Sprintf("%d", n)
909Ôćĺ}
