 70Ôćĺ// Enrich enriches a single contact, filling missing fields via the waterfall.
 71Ôćĺfunc Enrich(db *sql.DB, req EnrichRequest) (*EnrichResult, error) {
 72Ôćĺ	if req.ContactEmail == "" {
 73Ôćĺ		return nil, fmt.Errorf("contact email is required")
 74Ôćĺ	}
 75Ôćĺ
 76Ôćĺ	// Load provider registry
 77Ôćĺ	registry, err := LoadProviders()
 78Ôćĺ	if err != nil {
 79Ôćĺ		return nil, fmt.Errorf("loading providers: %w", err)
 80Ôćĺ	}
 81Ôćĺ
 82Ôćĺ	// Load contact from DB
 83Ôćĺ	contact, err := loadContact(db, req.ContactEmail)
 84Ôćĺ	if err != nil {
 85Ôćĺ		return nil, fmt.Errorf("loading contact %s: %w", req.ContactEmail, err)
 86Ôćĺ	}
 87Ôćĺ
 88Ôćĺ	// Determine which fields need enrichment
 89Ôćĺ	currentValues := contact.fieldMap()
 90Ôćĺ	var targetFields []string
 91Ôćĺ	if len(req.Fields) > 0 {
 92Ôćĺ		targetFields = req.Fields
 93Ôćĺ	} else {
 94Ôćĺ		targetFields = AllEnrichableFields()
 95Ôćĺ	}
 96Ôćĺ
 97Ôćĺ	var missingFields []string
 98Ôćĺ	for _, f := range targetFields {
 99Ôćĺ		if val, ok := currentValues[f]; !ok || val == "" {
100Ôćĺ			missingFields = append(missingFields, f)
101Ôćĺ		}
102Ôćĺ	}
103Ôćĺ
104Ôćĺ	result := &EnrichResult{
105Ôćĺ		ContactEmail: req.ContactEmail,
106Ôćĺ		FieldsFilled: make(map[string]string),
107Ôćĺ	}
108Ôćĺ
109Ôćĺ	if len(missingFields) == 0 {
110Ôćĺ		return result, nil
111Ôćĺ	}
112Ôćĺ
113Ôćĺ	providersUsedSet := make(map[string]bool)
114Ôćĺ
115Ôćĺ	// For each missing field, try providers in waterfall order
116Ôćĺ	for _, field := range missingFields {
117Ôćĺ		var providerNames []string
118Ôćĺ		if len(req.Providers) > 0 {
119Ôćĺ			// Use explicitly requested providers
120Ôćĺ			providerNames = req.Providers
121Ôćĺ		} else {
122Ôćĺ			// Use default waterfall
123Ôćĺ			providerNames = WaterfallForField(field)
124Ôćĺ		}
125Ôćĺ
126Ôćĺ		filled := false
127Ôćĺ		for _, provName := range providerNames {
128Ôćĺ			provider, ok := registry.GetProvider(provName)
129Ôćĺ			if !ok {
130Ôćĺ				continue
131Ôćĺ			}
132Ôćĺ
133Ôćĺ			// Check if this provider can fill this field
134Ôćĺ			canFill := false
135Ôćĺ			for _, pf := range provider.FieldsProvided {
136Ôćĺ				if pf == field {
137Ôćĺ					canFill = true
138Ôćĺ					break
139Ôćĺ				}
140Ôćĺ			}
141Ôćĺ			if !canFill {
142Ôćĺ				continue
143Ôćĺ			}
144Ôćĺ
145Ôćĺ			// Build cache key from provider + contact input
146Ôćĺ			cacheInput := buildCacheInput(provider, contact)
147Ôćĺ			cacheKey, err := assembly.CacheKey(provName, cacheInput)
148Ôćĺ			if err != nil {
149Ôćĺ				continue
150Ôćĺ			}
151Ôćĺ
152Ôćĺ			// Check cache first
153Ôćĺ			cached, err := assembly.GetCached(db, provName, cacheKey)
154Ôćĺ			if err != nil {
155Ôćĺ				log.Printf("cache lookup error for %s/%s: %v", provName, field, err)
156Ôćĺ				continue
157Ôćĺ			}
158Ôćĺ
159Ôćĺ			if cached != nil {
160Ôćĺ				// Extract field value from cached output
161Ôćĺ				var outputMap map[string]string
162Ôćĺ				if err := json.Unmarshal(cached.OutputData, &outputMap); err == nil {
163Ôćĺ					if val, ok := outputMap[field]; ok && val != "" {
164Ôćĺ						result.FieldsFilled[field] = val
165Ôćĺ						result.Cached++
166Ôćĺ						providersUsedSet[provName] = true
167Ôćĺ						filled = true
168Ôćĺ						break
169Ôćĺ					}
170Ôćĺ				}
171Ôćĺ			}
172Ôćĺ
173Ôćĺ			// Not cached -- this is where a real API call would go.
174Ôćĺ			// For now, log what WOULD happen and leave the field missing.
175Ôćĺ			log.Printf("enrich: would call provider %q (type=%s) to fill %q for %s",
176Ôćĺ				provName, provider.Type, field, req.ContactEmail)
177Ôćĺ			result.TotalCost += provider.CostPerCall
178Ôćĺ			providersUsedSet[provName] = true
179Ôćĺ		}
180Ôćĺ
181Ôćĺ		if !filled {
182Ôćĺ			result.FieldsMissing = append(result.FieldsMissing, field)
183Ôćĺ		}
184Ôćĺ	}
185Ôćĺ
186Ôćĺ	// Collect providers used
187Ôćĺ	for p := range providersUsedSet {
188Ôćĺ		result.ProvidersUsed = append(result.ProvidersUsed, p)
189Ôćĺ	}
190Ôćĺ
191Ôćĺ	// Update contacts table with any filled fields
192Ôćĺ	if len(result.FieldsFilled) > 0 {
193Ôćĺ		if err := updateContactFields(db, req.ContactEmail, result.FieldsFilled, result.ProvidersUsed); err != nil {
194Ôćĺ			return result, fmt.Errorf("updating contact: %w", err)
195Ôćĺ		}
196Ôćĺ	}
197Ôćĺ
198Ôćĺ	return result, nil
199Ôćĺ}
