201Ôćĺ// BatchEnrich finds unenriched contacts and enriches them.
202Ôćĺfunc BatchEnrich(db *sql.DB, limit int) ([]EnrichResult, error) {
203Ôćĺ	rows, err := db.Query(`
204Ôćĺ		SELECT email FROM contacts
205Ôćĺ		WHERE enriched_at = '' OR enriched_at IS NULL
206Ôćĺ		ORDER BY created_at DESC
207Ôćĺ		LIMIT ?
208Ôćĺ	`, limit)
209Ôćĺ	if err != nil {
210Ôćĺ		return nil, fmt.Errorf("querying unenriched contacts: %w", err)
211Ôćĺ	}
212Ôćĺ	defer rows.Close()
213Ôćĺ
214Ôćĺ	var emails []string
215Ôćĺ	for rows.Next() {
216Ôćĺ		var email string
217Ôćĺ		if err := rows.Scan(&email); err != nil {
218Ôćĺ			continue
219Ôćĺ		}
220Ôćĺ		emails = append(emails, email)
221Ôćĺ	}
222Ôćĺ	if err := rows.Err(); err != nil {
223Ôćĺ		return nil, fmt.Errorf("scanning unenriched contacts: %w", err)
224Ôćĺ	}
225Ôćĺ
226Ôćĺ	var results []EnrichResult
227Ôćĺ	for _, email := range emails {
228Ôćĺ		r, err := Enrich(db, EnrichRequest{ContactEmail: email})
229Ôćĺ		if err != nil {
230Ôćĺ			log.Printf("enrich: skipping %s: %v", email, err)
231Ôćĺ			continue
232Ôćĺ		}
233Ôćĺ		results = append(results, *r)
234Ôćĺ	}
235Ôćĺ
236Ôćĺ	return results, nil
237Ôćĺ}
