239Ôćĺ// Stats returns enrichment coverage across all contacts.
240Ôćĺfunc Stats(db *sql.DB) (*EnrichStats, error) {
241Ôćĺ	stats := &EnrichStats{
242Ôćĺ		FieldCoverage: make(map[string]int),
243Ôćĺ	}
244Ôćĺ
245Ôćĺ	// Total contacts
246Ôćĺ	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts`).Scan(&stats.TotalContacts); err != nil {
247Ôćĺ		return nil, fmt.Errorf("counting contacts: %w", err)
248Ôćĺ	}
249Ôćĺ
250Ôćĺ	// Enriched contacts (have enriched_at set)
251Ôćĺ	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts WHERE enriched_at != '' AND enriched_at IS NOT NULL`).Scan(&stats.Enriched); err != nil {
252Ôćĺ		return nil, fmt.Errorf("counting enriched contacts: %w", err)
253Ôćĺ	}
254Ôćĺ	stats.Unenriched = stats.TotalContacts - stats.Enriched
255Ôćĺ
256Ôćĺ	// Per-field coverage
257Ôćĺ	fieldColumns := map[string]string{
258Ôćĺ		"email":         "email",
259Ôćĺ		"name":          "name",
260Ôćĺ		"title":         "title",
261Ôćĺ		"company":       "company",
262Ôćĺ		"phone":         "phone",
263Ôćĺ		"industry":      "industry",
264Ôćĺ		"company_size":  "company_size",
265Ôćĺ		"funding_stage": "funding_stage",
266Ôćĺ		"website":       "website",
267Ôćĺ		"linkedin_url":  "linkedin_url",
268Ôćĺ	}
269Ôćĺ	for field, col := range fieldColumns {
270Ôćĺ		var count int
271Ôćĺ		query := fmt.Sprintf(`SELECT COUNT(*) FROM contacts WHERE %s != '' AND %s IS NOT NULL`, col, col)
272Ôćĺ		if err := db.QueryRow(query).Scan(&count); err != nil {
273Ôćĺ			continue
274Ôćĺ		}
275Ôćĺ		stats.FieldCoverage[field] = count
276Ôćĺ	}
277Ôćĺ
278Ôćĺ	return stats, nil
279Ôćĺ}
