339Ôćĺ// updateContactFields writes filled fields back to the contacts table
340Ôćĺ// and updates enriched_at and enrichment_sources.
341Ôćĺfunc updateContactFields(db *sql.DB, email string, fields map[string]string, providers []string) error {
342Ôćĺ	var setClauses []string
343Ôćĺ	var args []any
344Ôćĺ
345Ôćĺ	for field, value := range fields {
346Ôćĺ		col, ok := enrichableColumns[field]
347Ôćĺ		if !ok {
348Ôćĺ			continue
349Ôćĺ		}
350Ôćĺ		setClauses = append(setClauses, fmt.Sprintf("%s = ?", col))
351Ôćĺ		args = append(args, value)
352Ôćĺ	}
353Ôćĺ
354Ôćĺ	if len(setClauses) == 0 {
355Ôćĺ		return nil
356Ôćĺ	}
357Ôćĺ
358Ôćĺ	// Update enriched_at
359Ôćĺ	setClauses = append(setClauses, "enriched_at = ?")
360Ôćĺ	args = append(args, time.Now().UTC().Format("2006-01-02 15:04:05"))
361Ôćĺ
362Ôćĺ	// Merge enrichment_sources
363Ôćĺ	sourcesJSON, _ := json.Marshal(providers)
364Ôćĺ	setClauses = append(setClauses, "enrichment_sources = ?")
365Ôćĺ	args = append(args, string(sourcesJSON))
366Ôćĺ
367Ôćĺ	// updated_at
368Ôćĺ	setClauses = append(setClauses, "updated_at = datetime('now')")
369Ôćĺ
370Ôćĺ	args = append(args, email)
371Ôćĺ
372Ôćĺ	query := fmt.Sprintf("UPDATE contacts SET %s WHERE email = ?", strings.Join(setClauses, ", "))
373Ôćĺ	_, err := db.Exec(query, args...)
374Ôćĺ	return err
375Ôćĺ}
