393Ôćĺ// Save processes one enrichment input: updates the contacts table and optionally
394Ôćĺ// caches the full result in enrichment_cache.
395Ôćĺfunc Save(db *sql.DB, input SaveInput) SaveResult {
396Ôćĺ	result := SaveResult{ContactEmail: input.ContactEmail}
397Ôćĺ
398Ôćĺ	if input.ContactEmail == "" {
399Ôćĺ		result.Error = "contact_email is required"
400Ôćĺ		return result
401Ôćĺ	}
402Ôćĺ
403Ôćĺ	// 1. Update contacts table with non-empty mapped fields.
404Ôćĺ	updated, err := saveUpdateContact(db, input)
405Ôćĺ	if err != nil {
406Ôćĺ		result.Error = fmt.Sprintf("updating contact: %v", err)
407Ôćĺ		return result
408Ôćĺ	}
409Ôćĺ	result.ContactUpdated = updated
410Ôćĺ
411Ôćĺ	// 2. Optionally cache in enrichment_cache if provider is specified.
412Ôćĺ	if input.Provider != "" {
413Ôćĺ		if err := saveCacheEnrichment(db, input); err != nil {
414Ôćĺ			result.Error = fmt.Sprintf("caching enrichment: %v", err)
415Ôćĺ			return result
416Ôćĺ		}
417Ôćĺ		result.CacheStored = true
418Ôćĺ	}
419Ôćĺ
420Ôćĺ	return result
421Ôćĺ}
422Ôćĺ
423Ôćĺ// SaveBatch processes multiple enrichment inputs and returns results for each.
424Ôćĺfunc SaveBatch(db *sql.DB, inputs []SaveInput) []SaveResult {
425Ôćĺ	results := make([]SaveResult, 0, len(inputs))
426Ôćĺ	for _, input := range inputs {
427Ôćĺ		results = append(results, Save(db, input))
428Ôćĺ	}
429Ôćĺ	return results
430Ôćĺ}
