432Ôćĺ// saveUpdateContact updates the contacts row for the given email with non-empty fields.
433Ôćĺfunc saveUpdateContact(db *sql.DB, input SaveInput) (bool, error) {
434Ôćĺ	if len(input.Fields) == 0 {
435Ôćĺ		return false, nil
436Ôćĺ	}
437Ôćĺ
438Ôćĺ	var setClauses []string
439Ôćĺ	var args []any
440Ôćĺ
441Ôćĺ	for fieldName, value := range input.Fields {
442Ôćĺ		if value == "" {
443Ôćĺ			continue
444Ôćĺ		}
445Ôćĺ		col, ok := enrichableColumns[fieldName]
446Ôćĺ		if !ok {
447Ôćĺ			continue
448Ôćĺ		}
449Ôćĺ		setClauses = append(setClauses, fmt.Sprintf("%s = ?", col))
450Ôćĺ		args = append(args, value)
451Ôćĺ	}
452Ôćĺ
453Ôćĺ	if len(setClauses) == 0 {
454Ôćĺ		return false, nil
455Ôćĺ	}
456Ôćĺ
457Ôćĺ	setClauses = append(setClauses, "updated_at = ?")
458Ôćĺ	args = append(args, time.Now().UTC().Format("2006-01-02 15:04:05"))
459Ôćĺ	args = append(args, input.ContactEmail)
460Ôćĺ
461Ôćĺ	query := fmt.Sprintf("UPDATE contacts SET %s WHERE email = ?", strings.Join(setClauses, ", "))
462Ôćĺ	res, err := db.Exec(query, args...)
463Ôćĺ	if err != nil {
464Ôćĺ		return false, err
465Ôćĺ	}
466Ôćĺ	n, _ := res.RowsAffected()
467Ôćĺ	return n > 0, nil
468Ôćĺ}
469Ôćĺ
470Ôćĺ// saveCacheEnrichment upserts the enrichment result into enrichment_cache.
471Ôćĺfunc saveCacheEnrichment(db *sql.DB, input SaveInput) error {
472Ôćĺ	dataBytes, err := json.Marshal(input.Fields)
473Ôćĺ	if err != nil {
474Ôćĺ		return fmt.Errorf("marshaling fields: %w", err)
475Ôćĺ	}
476Ôćĺ
477Ôćĺ	source := input.Source
478Ôćĺ	if source == "" {
479Ôćĺ		source = "manual"
480Ôćĺ	}
481Ôćĺ
482Ôćĺ	inputKey, _ := assembly.CacheKey(input.Provider, input.ContactEmail)
483Ôćĺ	now := time.Now().UTC().Format("2006-01-02 15:04:05")
484Ôćĺ	expires := time.Now().UTC().Add(168 * time.Hour).Format("2006-01-02 15:04:05")
485Ôćĺ
486Ôćĺ	_, err = db.Exec(`
487Ôćĺ		INSERT INTO enrichment_cache (provider, input_key, input_data, output_data, expires_at, created_at)
488Ôćĺ		VALUES (?, ?, ?, ?, ?, ?)
489Ôćĺ		ON CONFLICT(provider, input_key) DO UPDATE SET
490Ôćĺ			output_data = excluded.output_data,
491Ôćĺ			expires_at = excluded.expires_at
492Ôćĺ	`, input.Provider, inputKey, input.ContactEmail, string(dataBytes), expires, now)
493Ôćĺ
494Ôćĺ	return err
495Ôćĺ}
