 14Ôćĺ// TierScore holds the breakdown of a contact's tier scoring.
 15Ôćĺtype TierScore struct {
 16Ôćĺ	ICPFit        float64  `json:"icp_fit"`
 17Ôćĺ	BuyingTrigger float64  `json:"buying_trigger"`
 18Ôćĺ	IntentSignal  float64  `json:"intent_signal"`
 19Ôćĺ	Accessibility float64  `json:"accessibility"`
 20Ôćĺ	Total         float64  `json:"total"`
 21Ôćĺ	Tier          int      `json:"tier"`
 22Ôćĺ	Reasons       []string `json:"reasons,omitempty"`
 23Ôćĺ}
 24Ôćĺ
 25Ôćĺ// ICPConfig holds the ideal customer profile configuration.
 26Ôćĺtype ICPConfig struct {
 27Ôćĺ	TargetIndustries []string
 28Ôćĺ	CompanySizeRange string // e.g., "50-500"
 29Ôćĺ	FundingStage     string // e.g., "series-a"
