 32Ôćĺ}
 33Ôćĺ
 34Ôćĺ// ContactData holds the fields needed for scoring a contact.
 35Ôćĺtype ContactData struct {
 36Ôćĺ	Email        string
 37Ôćĺ	Name         string
 38Ôćĺ	Domain       string
 39Ôćĺ	Company      string
 40Ôćĺ	Title        string
 41Ôćĺ	Phone        string
 42Ôćĺ	Industry     string
 43Ôćĺ	CompanySize  string
 44Ôćĺ	FundingStage string
 45Ôćĺ	LinkedInURL  string
 46Ôćĺ	Website      string
 47Ôćĺ	Signals      []string
 48Ôćĺ	EmailCount   int
 49Ôćĺ	LastEmailedAt string
 50Ôćĺ}
 51Ôćĺ
 52Ôćĺ// TierResult is a scored contact returned by BatchScore.
 53Ôćĺtype TierResult struct {
