 66Ôćĺ}
 67Ôćĺ
 68Ôćĺ// Weights for each scoring dimension.
 69Ôćĺconst (
 70Ôćĺ	weightICPFit        = 0.40
 71Ôćĺ	weightBuyingTrigger = 0.25
 72Ôćĺ	weightIntentSignal  = 0.20
 73Ôćĺ	weightAccessibility = 0.15
 74Ôćĺ)
 75Ôćĺ
 76Ôćĺ// ScoreContact computes a TierScore for a contact given ICP configuration
 77Ôćĺ// and database-derived intent signals.
 78Ôćĺfunc ScoreContact(contact ContactData, icp ICPConfig, hasReply bool, hasActiveSequence bool) TierScore {
 79Ôćĺ	var score TierScore
 80Ôćĺ
 81Ôćĺ	// --- ICP Fit (0-100) ---
 82Ôćĺ	score.ICPFit, score.Reasons = scoreICPFit(contact, icp)
 83Ôćĺ
 84Ôćĺ	// --- Buying Trigger (0-100) ---
 85Ôćĺ	score.BuyingTrigger = scoreBuyingTrigger(contact.Signals, &score.Reasons)
 86Ôćĺ
 87Ôćĺ	// --- Intent Signal (0-100) ---
 88Ôćĺ	score.IntentSignal = scoreIntentSignal(contact, hasReply, hasActiveSequence, &score.Reasons)
 89Ôćĺ
 90Ôćĺ	// --- Accessibility (0-100) ---
 91Ôćĺ	score.Accessibility = scoreAccessibility(contact, &score.Reasons)
 92Ôćĺ
 93Ôćĺ	// --- Total (weighted sum) ---
 94Ôćĺ	score.Total = score.ICPFit*weightICPFit +
 95Ôćĺ		score.BuyingTrigger*weightBuyingTrigger +
 96Ôćĺ		score.IntentSignal*weightIntentSignal +
 97Ôćĺ		score.Accessibility*weightAccessibility
 98Ôćĺ
 99Ôćĺ	// Round to 1 decimal
100Ôćĺ	score.Total = float64(int(score.Total*10)) / 10
101Ôćĺ
102Ôćĺ	// --- Tier assignment ---
103Ôćĺ	switch {
104Ôćĺ	case score.Total >= 70:
105Ôćĺ		score.Tier = 1
106Ôćĺ	case score.Total >= 40:
107Ôćĺ		score.Tier = 2
108Ôćĺ	default:
109Ôćĺ		score.Tier = 3
110Ôćĺ	}
111Ôćĺ
112Ôćĺ	return score
113Ôćĺ}
114Ôćĺ
115Ôćĺfunc scoreICPFit(contact ContactData, icp ICPConfig) (float64, []string) {
116Ôćĺ	var fit float64
117Ôćĺ	var reasons []string
118Ôćĺ
119Ôćĺ	// Industry match: +40 exact, +20 related
120Ôćĺ	if contact.Industry != "" && len(icp.TargetIndustries) > 0 {
121Ôćĺ		contactInd := strings.ToLower(contact.Industry)
122Ôćĺ		matched := false
123Ôćĺ		for _, ind := range icp.TargetIndustries {
124Ôćĺ			if strings.ToLower(ind) == contactInd {
125Ôćĺ				fit += 40
126Ôćĺ				reasons = append(reasons, fmt.Sprintf("industry match: %s", contact.Industry))
127Ôćĺ				matched = true
128Ôćĺ				break
129Ôćĺ			}
130Ôćĺ		}
131Ôćĺ		if !matched {
132Ôćĺ			// Check for related industry (substring match as heuristic)
133Ôćĺ			for _, ind := range icp.TargetIndustries {
134Ôćĺ				if strings.Contains(contactInd, strings.ToLower(ind)) ||
135Ôćĺ					strings.Contains(strings.ToLower(ind), contactInd) {
136Ôćĺ					fit += 20
137Ôćĺ					reasons = append(reasons, fmt.Sprintf("related industry: %s ~ %s", contact.Industry, ind))
138Ôćĺ					break
139Ôćĺ				}
140Ôćĺ			}
141Ôćĺ		}
142Ôćĺ	}
143Ôćĺ
144Ôćĺ	// Company size in range: +30
145Ôćĺ	if contact.CompanySize != "" && icp.CompanySizeRange != "" {
146Ôćĺ		if sizeInRange(contact.CompanySize, icp.CompanySizeRange) {
147Ôćĺ			fit += 30
148Ôćĺ			reasons = append(reasons, fmt.Sprintf("company size %s in range %s", contact.CompanySize, icp.CompanySizeRange))
149Ôćĺ		}
150Ôćĺ	}
151Ôćĺ
152Ôćĺ	// Geography match: +15
153Ôćĺ	if icp.Geography != "" && contact.Domain != "" {
154Ôćĺ		// Simple heuristic: geography is stored in config, we check domain TLD or company info
155Ôćĺ		// This is a basic check; enrichment would improve accuracy
156Ôćĺ		if strings.EqualFold(icp.Geography, "global") {
157Ôćĺ			fit += 15
158Ôćĺ			reasons = append(reasons, "geography: global target")
159Ôćĺ		}
160Ôćĺ	}
161Ôćĺ
162Ôćĺ	// Funding stage match: +15
163Ôćĺ	if contact.FundingStage != "" && icp.FundingStage != "" {
164Ôćĺ		if strings.EqualFold(contact.FundingStage, icp.FundingStage) {
165Ôćĺ			fit += 15
166Ôćĺ			reasons = append(reasons, fmt.Sprintf("funding stage match: %s", contact.FundingStage))
167Ôćĺ		}
168Ôćĺ	}
169Ôćĺ
170Ôćĺ	// Title match (bonus, uses target titles from ICP)
171Ôćĺ	if contact.Title != "" && len(icp.TargetTitles) > 0 {
172Ôćĺ		contactTitle := strings.ToLower(contact.Title)
173Ôćĺ		for _, t := range icp.TargetTitles {
174Ôćĺ			if strings.Contains(contactTitle, strings.ToLower(t)) {
175Ôćĺ				// Title match doesn't add to the 100-point scale directly
176Ôćĺ				// but we record it as a reason for context
177Ôćĺ				reasons = append(reasons, fmt.Sprintf("title match: %s", contact.Title))
178Ôćĺ				break
179Ôćĺ			}
180Ôćĺ		}
181Ôćĺ	}
182Ôćĺ
183Ôćĺ	if fit > 100 {
184Ôćĺ		fit = 100
185Ôćĺ	}
186Ôćĺ	return fit, reasons
187Ôćĺ}
188Ôćĺ
189Ôćĺfunc scoreBuyingTrigger(signals []string, reasons *[]string) float64 {
190Ôćĺ	triggerScores := map[string]float64{
191Ôćĺ		"funding":        40,
192Ôćĺ		"job_change":     35,
193Ôćĺ		"hiring":         25,
194Ôćĺ		"product_launch": 20,
195Ôćĺ		"expansion":      15,
196Ôćĺ	}
197Ôćĺ
198Ôćĺ	var total float64
199Ôćĺ	for _, sig := range signals {
200Ôćĺ		s := strings.ToLower(sig)
201Ôćĺ		if pts, ok := triggerScores[s]; ok {
202Ôćĺ			total += pts
203Ôćĺ			*reasons = append(*reasons, fmt.Sprintf("buying trigger: %s (+%.0f)", sig, pts))
204Ôćĺ		}
205Ôćĺ	}
206Ôćĺ
207Ôćĺ	if total > 100 {
208Ôćĺ		total = 100
209Ôćĺ	}
