213Ôćĺfunc scoreIntentSignal(contact ContactData, hasReply bool, hasActiveSequence bool, reasons *[]string) float64 {
214Ôćĺ	var total float64
215Ôćĺ
216Ôćĺ	// Has prior email interaction (email_count > 0): +40
217Ôćĺ	if contact.EmailCount > 0 {
