233Ôćĺ				*reasons = append(*reasons, "emailed within last 30 days")
234Ôćĺ			}
235Ôćĺ		} else if t, err := time.Parse("2006-01-02T15:04:05", contact.LastEmailedAt); err == nil {
236Ôćĺ			if time.Since(t) <= 30*24*time.Hour {
237Ôćĺ				total += 20
238Ôćĺ				*reasons = append(*reasons, "emailed within last 30 days")
239Ôćĺ			}
240Ôćĺ		}
241Ôćĺ	}
242Ôćĺ
243Ôćĺ	// Part of active sequence: +10
244Ôćĺ	if hasActiveSequence {
245Ôćĺ		total += 10
246Ôćĺ		*reasons = append(*reasons, "active sequence enrollment")
247Ôćĺ	}
248Ôćĺ
249Ôćĺ	if total > 100 {
250Ôćĺ		total = 100
251Ôćĺ	}
252Ôćĺ	return total
