293Ôćĺ// isGenericEmail checks if the email looks like a generic/role address.
294Ôćĺfunc isGenericEmail(email string) bool {
295Ôćĺ	prefixes := []string{
296Ôćĺ		"info@", "contact@", "hello@", "support@", "sales@",
297Ôćĺ		"admin@", "help@", "team@", "office@", "general@",
298Ôćĺ		"enquiries@", "noreply@", "no-reply@",
299Ôćĺ	}
300Ôćĺ	lower := strings.ToLower(email)
301Ôćĺ	for _, p := range prefixes {
302Ôćĺ		if strings.HasPrefix(lower, p) {
303Ôćĺ			return true
304Ôćĺ		}
305Ôćĺ	}
306Ôćĺ	return false
307Ôćĺ}
308Ôćĺ
309Ôćĺ// sizeInRange checks if a company size string falls within a range like "50-500".
310Ôćĺfunc sizeInRange(sizeStr, rangeStr string) bool {
311Ôćĺ	// Parse size: could be "150", "150-200", "~200", etc.
312Ôćĺ	size := parseFirstNumber(sizeStr)
313Ôćĺ	if size <= 0 {
314Ôćĺ		return false
315Ôćĺ	}
316Ôćĺ
317Ôćĺ	parts := strings.SplitN(rangeStr, "-", 2)
318Ôćĺ	if len(parts) != 2 {
319Ôćĺ		return false
320Ôćĺ	}
321Ôćĺ
322Ôćĺ	low := parseFirstNumber(parts[0])
323Ôćĺ	high := parseFirstNumber(parts[1])
324Ôćĺ	if low <= 0 || high <= 0 {
325Ôćĺ		return false
326Ôćĺ	}
327Ôćĺ
328Ôćĺ	return size >= low && size <= high
329Ôćĺ}
330Ôćĺ
331Ôćĺ// parseFirstNumber extracts the first integer from a string.
332Ôćĺfunc parseFirstNumber(s string) int {
333Ôćĺ	s = strings.TrimSpace(s)
334Ôćĺ	// Strip non-digit prefix
335Ôćĺ	start := -1
336Ôćĺ	for i, c := range s {
337Ôćĺ		if c >= '0' && c <= '9' {
338Ôćĺ			if start == -1 {
339Ôćĺ				start = i
340Ôćĺ			}
341Ôćĺ		} else if start != -1 {
342Ôćĺ			n, err := strconv.Atoi(s[start:i])
343Ôćĺ			if err == nil {
344Ôćĺ				return n
345Ôćĺ			}
346Ôćĺ			return 0
347Ôćĺ		}
348Ôćĺ	}
349Ôćĺ	if start >= 0 {
350Ôćĺ		n, err := strconv.Atoi(s[start:])
351Ôćĺ		if err == nil {
352Ôćĺ			return n
353Ôćĺ		}
354Ôćĺ	}
355Ôćĺ	return 0
356Ôćĺ}
