443Ôćĺ// ScoreAndSave loads a contact from the DB, scores it, updates the DB, and returns the score.
444Ôćĺfunc ScoreAndSave(d *sql.DB, contactEmail string) (*TierScore, error) {
445Ôćĺ	contact, err := loadContactFromDB(d, contactEmail)
446Ôćĺ	if err != nil {
447Ôćĺ		return nil, err
