468Ôćĺ// BatchScore scores all contacts that are unscored (tier=0) or stale.
469Ôćĺ// It returns the list of results and the count of contacts scored.
470Ôćĺfunc BatchScore(d *sql.DB, limit int) ([]TierResult, error) {
471Ôćĺ	icp := LoadICPConfig()
472Ôćĺ
473Ôćĺ	rows, err := d.Query(`
474Ôćĺ		SELECT email, name, domain, company, title, phone,
475Ôćĺ		       industry, company_size, funding_stage,
476Ôćĺ		       linkedin_url, website, signals,
477Ôćĺ		       email_count, COALESCE(last_emailed_at, '')
478Ôćĺ		FROM contacts
479Ôćĺ		WHERE tier = 0
480Ôćĺ		   OR tier_scored_at = ''
481Ôćĺ		   OR tier_scored_at < datetime('now', '-7 days')
482Ôćĺ		ORDER BY email_count DESC
483Ôćĺ		LIMIT ?`, limit)
484Ôćĺ	if err != nil {
485Ôćĺ		return nil, fmt.Errorf("querying contacts for batch scoring: %w", err)
486Ôćĺ	}
487Ôćĺ	defer rows.Close()
488Ôćĺ
489Ôćĺ	var results []TierResult
490Ôćĺ	for rows.Next() {
491Ôćĺ		var c ContactData
492Ôćĺ		var signalsJSON string
493Ôćĺ		if err := rows.Scan(
494Ôćĺ			&c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
495Ôćĺ			&c.Industry, &c.CompanySize, &c.FundingStage,
496Ôćĺ			&c.LinkedInURL, &c.Website, &signalsJSON,
497Ôćĺ			&c.EmailCount, &c.LastEmailedAt,
498Ôćĺ		); err != nil {
499Ôćĺ			return nil, fmt.Errorf("scanning contact row: %w", err)
500Ôćĺ		}
501Ôćĺ
502Ôćĺ		if signalsJSON != "" && signalsJSON != "[]" {
503Ôćĺ			_ = json.Unmarshal([]byte(signalsJSON), &c.Signals)
504Ôćĺ		}
505Ôćĺ
506Ôćĺ		reply := hasReplyEvent(d, c.Email)
507Ôćĺ		activeSeq := hasActiveSequenceEnrollment(d, c.Email)
508Ôćĺ		score := ScoreContact(c, icp, reply, activeSeq)
509Ôćĺ
510Ôćĺ		_, err := d.Exec(`
511Ôćĺ			UPDATE contacts
512Ôćĺ			SET tier = ?, tier_score = ?, tier_scored_at = datetime('now')
513Ôćĺ			WHERE email = ?`,
514Ôćĺ			score.Tier, score.Total, c.Email)
515Ôćĺ		if err != nil {
516Ôćĺ			return nil, fmt.Errorf("updating tier for %s: %w", c.Email, err)
517Ôćĺ		}
518Ôćĺ
519Ôćĺ		results = append(results, TierResult{
520Ôćĺ			Email: c.Email,
521Ôćĺ			Name:  c.Name,
522Ôćĺ			Score: score,
523Ôćĺ		})
524Ôćĺ	}
525Ôćĺ
526Ôćĺ	if err := rows.Err(); err != nil {
527Ôćĺ		return nil, err
528Ôćĺ	}
529Ôćĺ
530Ôćĺ	return results, nil
531Ôćĺ}
