139Ôćĺ// Assemble builds the context prompt for a given task and optional prospect.
140Ôćĺfunc Assemble(database *sql.DB, req AssembleRequest) (*AssembleResult, error) {
141Ôćĺ	if !ValidTaskTypes[req.Task] {
142Ôćĺ		return nil, fmt.Errorf("unknown task type: %s", req.Task)
143Ôćĺ	}
144Ôćĺ	if req.Format == "" {
145Ôćĺ		req.Format = "markdown"
146Ôćĺ	}
147Ôćĺ
148Ôćĺ	// Check in-memory cache
149Ôćĺ	cacheKey := string(req.Task) + ":" + req.Prospect
150Ôćĺ	if cached, ok := defaultCache.Get(cacheKey); ok {
151Ôćĺ		return &AssembleResult{
152Ôćĺ			Context:       cached,
153Ôćĺ			TokenEstimate: estimateTokens(cached),
154Ôćĺ			Cached:        true,
155Ôćĺ		}, nil
156Ôćĺ	}
157Ôćĺ
158Ôćĺ	var sections []section
159Ôćĺ	var atomsLoaded []string
160Ôćĺ	var directives []string
161Ôćĺ
162Ôćĺ	// Load prospect info if applicable
163Ôćĺ	var contact *Contact
164Ôćĺ	if req.Prospect != "" {
165Ôćĺ		c, err := getContact(database, req.Prospect)
166Ôćĺ		if err != nil {
167Ôćĺ			return nil, fmt.Errorf("querying contact: %w", err)
168Ôćĺ		}
169Ôćĺ		contact = c
170Ôćĺ	}
171Ôćĺ
172Ôćĺ	// Build prospect context section
173Ôćĺ	if contact != nil {
174Ôćĺ		sections = append(sections, section{
175Ôćĺ			heading: "Context",
176Ôćĺ			body:    formatContact(contact),
177Ôćĺ		})
178Ôćĺ	} else if req.Prospect != "" && prospectTasks[req.Task] {
179Ôćĺ		// Prospect specified but not found -- directive to enrich
180Ôćĺ		sections = append(sections, section{
181Ôćĺ			heading: "Context",
182Ôćĺ			body:    fmt.Sprintf("Prospect: %s (not in contacts -- limited context available)", req.Prospect),
183Ôćĺ		})
184Ôćĺ		directives = append(directives, "enrich_required: contact not found in database, run nurge resolve to enrich")
185Ôćĺ	}
186Ôćĺ
187Ôćĺ	// Determine scopes for atom queries based on contact
188Ôćĺ	scopes := buildScopes(contact)
189Ôćĺ
190Ôćĺ	// Load atoms for this task type
191Ôćĺ	neededAtoms := taskAtomMap[req.Task]
192Ôćĺ	for _, atomType := range neededAtoms {
193Ôćĺ		atoms, err := QueryAtoms(database, atomType, scopes...)
194Ôćĺ		if err != nil {
195Ôćĺ			return nil, fmt.Errorf("querying %s atoms: %w", atomType, err)
196Ôćĺ		}
197Ôćĺ		if len(atoms) > 0 {
198Ôćĺ			best := pickBestAtom(atoms, scopes)
199Ôćĺ			content := extractContent(best.Content)
200Ôćĺ			heading := atomHeading(atomType)
201Ôćĺ			sections = append(sections, section{heading: heading, body: content})
202Ôćĺ			atomsLoaded = append(atomsLoaded, fmt.Sprintf("%s/%s", best.AtomType, best.Scope))
203Ôćĺ			// Touch the atom to track usage
204Ôćĺ			_ = TouchAtom(database, best.ID)
205Ôćĺ		}
206Ôćĺ	}
207Ôćĺ
208Ôćĺ	// Research dossier for prospect-facing tasks
209Ôćĺ	if req.Prospect != "" && prospectTasks[req.Task] {
210Ôćĺ		dossier, err := GetDossier(database, req.Prospect)
211Ôćĺ		if err != nil {
212Ôćĺ			return nil, fmt.Errorf("getting dossier: %w", err)
213Ôćĺ		}
214Ôćĺ		if dossier != nil {
215Ôćĺ			content := extractContent(dossier.Dossier)
216Ôćĺ			sections = append(sections, section{heading: "Research", body: content})
217Ôćĺ		} else if contact != nil && contact.Tier > 0 && contact.Tier <= 2 {
218Ôćĺ			directives = append(directives, "research_required: Tier 1/2 prospect has no research dossier -- run /nurge:research first")
219Ôćĺ		}
220Ôćĺ	}
221Ôćĺ
222Ôćĺ	// Check for empty enrichment fields on known contacts
223Ôćĺ	if contact != nil && contact.EnrichedAt == "" && prospectTasks[req.Task] {
224Ôćĺ		directives = append(directives, "enrich_required: contact has not been enriched -- run nurge resolve to fill in company, title, and signals")
225Ôćĺ	}
226Ôćĺ
227Ôćĺ	// Load recent relevant learnings
228Ôćĺ	learnings, err := queryRecentLearnings(database, req.Task, 10)
229Ôćĺ	if err != nil {
230Ôćĺ		return nil, fmt.Errorf("querying learnings: %w", err)
231Ôćĺ	}
232Ôćĺ	if len(learnings) > 0 {
233Ôćĺ		var lines []string
234Ôćĺ		for _, l := range learnings {
235Ôćĺ			lines = append(lines, fmt.Sprintf("- [%s] %s", l.Type, l.Content))
236Ôćĺ		}
237Ôćĺ		sections = append(sections, section{heading: "Recent Learnings", body: strings.Join(lines, "\n")})
238Ôćĺ	}
239Ôćĺ
240Ôćĺ	// Load config context
241Ôćĺ	cfgSection := loadConfigContext(req.Task)
242Ôćĺ	if cfgSection != "" {
243Ôćĺ		sections = append(sections, section{heading: "Configuration", body: cfgSection})
244Ôćĺ	}
245Ôćĺ
246Ôćĺ	// Directives section (placed early so the skill sees it first)
247Ôćĺ	var result strings.Builder
248Ôćĺ	if len(directives) > 0 {
249Ôćĺ		result.WriteString("## Directives\n")
250Ôćĺ		for _, d := range directives {
251Ôćĺ			result.WriteString(fmt.Sprintf("- %s\n", d))
252Ôćĺ		}
253Ôćĺ		result.WriteString("\n")
254Ôćĺ	}
255Ôćĺ
256Ôćĺ	// Render remaining sections
257Ôćĺ	for _, s := range sections {
258Ôćĺ		result.WriteString(fmt.Sprintf("## %s\n%s\n\n", s.heading, s.body))
259Ôćĺ	}
260Ôćĺ
261Ôćĺ	context := strings.TrimSpace(result.String())
262Ôćĺ
263Ôćĺ	// Cache the result
264Ôćĺ	defaultCache.Set(cacheKey, context)
265Ôćĺ
266Ôćĺ	return &AssembleResult{
267Ôćĺ		Context:       context,
268Ôćĺ		TokenEstimate: estimateTokens(context),
269Ôćĺ		AtomsLoaded:   atomsLoaded,
270Ôćĺ		Directives:    directives,
271Ôćĺ		Cached:        false,
272Ôćĺ	}, nil
273Ôćĺ}
274Ôćĺ
