384Ôćĺ// pickBestAtom selects the most relevant atom from candidates.
385Ôćĺ// It prefers scoped matches over the global fallback. Among scoped matches,
386Ôćĺ// it picks the one whose scope appears earliest in the scopes list
387Ôćĺ// (most specific first). Falls back to confidence/recency ordering.
388Ôćĺfunc pickBestAtom(atoms []KnowledgeAtom, scopes []string) KnowledgeAtom {
389Ôćĺ	if len(atoms) == 1 {
390Ôćĺ		return atoms[0]
391Ôćĺ	}
392Ôćĺ
393Ôćĺ	// Build scope priority: lower index = higher priority
394Ôćĺ	scopePrio := make(map[string]int, len(scopes))
395Ôćĺ	for i, s := range scopes {
396Ôćĺ		scopePrio[s] = i
397Ôćĺ	}
398Ôćĺ
399Ôćĺ	best := atoms[0]
400Ôćĺ	bestPrio := len(scopes) + 1 // global ("") gets worst priority
401Ôćĺ	if p, ok := scopePrio[best.Scope]; ok {
402Ôćĺ		bestPrio = p
403Ôćĺ	}
404Ôćĺ
405Ôćĺ	for _, a := range atoms[1:] {
406Ôćĺ		prio := len(scopes) + 1
407Ôćĺ		if p, ok := scopePrio[a.Scope]; ok {
408Ôćĺ			prio = p
409Ôćĺ		}
410Ôćĺ		if prio < bestPrio {
411Ôćĺ			best = a
412Ôćĺ			bestPrio = prio
413Ôćĺ		}
414Ôćĺ	}
415Ôćĺ	return best
416Ôćĺ}
