497Ôćĺ// queryLearningsByTypes fetches learnings, optionally filtered by type, newest first.
498Ôćĺfunc queryLearningsByTypes(database *sql.DB, types []string, limit int) ([]Learning, error) {
499Ôćĺ	var query string
500Ôćĺ	var args []any
501Ôćĺ
502Ôćĺ	if len(types) == 0 {
503Ôćĺ		query = `SELECT id, type, content, source_session, created_at FROM learnings ORDER BY created_at DESC LIMIT ?`
504Ôćĺ		args = append(args, limit)
505Ôćĺ	} else {
506Ôćĺ		placeholders := make([]string, len(types))
507Ôćĺ		for i, t := range types {
508Ôćĺ			placeholders[i] = "?"
509Ôćĺ			args = append(args, t)
510Ôćĺ		}
511Ôćĺ		query = fmt.Sprintf(
512Ôćĺ			`SELECT id, type, content, source_session, created_at FROM learnings WHERE type IN (%s) ORDER BY created_at DESC LIMIT ?`,
513Ôćĺ			strings.Join(placeholders, ","),
514Ôćĺ		)
515Ôćĺ		args = append(args, limit)
516Ôćĺ	}
517Ôćĺ
518Ôćĺ	rows, err := database.Query(query, args...)
519Ôćĺ	if err != nil {
520Ôćĺ		return nil, fmt.Errorf("querying learnings: %w", err)
521Ôćĺ	}
522Ôćĺ	defer rows.Close()
