package enrich

// DefaultWaterfall defines the preferred provider order for each enrichable field.
// When enriching a field, providers are tried in order until one succeeds or
// returns cached data.
//
// Previously referenced apify-linkedin-person, apify-linkedin-company, and
// apollo-email, but those providers were dead code (API calls were stubbed,
// never made real HTTP requests). Enrichment now uses Convex/Unipile via
// `nurge enrich company` and `nurge enrich person` subcommands.
//
// User-defined providers from .nurge/providers/ can still populate this map
// if the waterfall-based enrichment is reactivated in the future.
var DefaultWaterfall = map[string][]string{}

// AllEnrichableFields returns every field that the waterfall can fill.
func AllEnrichableFields() []string {
	return []string{
		"email", "name", "title", "company", "phone",
		"industry", "company_size", "funding_stage",
		"headline", "location", "website",
	}
}

// WaterfallForField returns the ordered list of provider names to try for a field.
// If the field isn't in the default waterfall, returns nil.
func WaterfallForField(field string) []string {
	providers, ok := DefaultWaterfall[field]
	if !ok {
		return nil
	}
	// Return a copy to prevent mutation.
	out := make([]string, len(providers))
	copy(out, providers)
	return out
}

