286Ôćĺ// getContact queries the contacts table by email.
287Ôćĺfunc getContact(database *sql.DB, email string) (*Contact, error) {
288Ôćĺ	var c Contact
289Ôćĺ	err := database.QueryRow(`
290Ôćĺ		SELECT id, source, email, name, domain, company, title, phone,
291Ôćĺ			   lead_status, tier, tier_score, industry, funding_stage,
292Ôćĺ			   company_size, linkedin_url, signals, tech_stack,
293Ôćĺ			   data_confidence, resolve_source, enriched_at, enrichment_sources
294Ôćĺ		FROM contacts WHERE email = ?
295Ôćĺ	`, email).Scan(
296Ôćĺ		&c.ID, &c.Source, &c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
297Ôćĺ		&c.LeadStatus, &c.Tier, &c.TierScore, &c.Industry, &c.FundingStage,
298Ôćĺ		&c.CompanySize, &c.LinkedInURL, &c.Signals, &c.TechStack,
299Ôćĺ		&c.DataConfidence, &c.ResolveSource, &c.EnrichedAt, &c.EnrichmentSources,
300Ôćĺ	)
301Ôćĺ	if err == sql.ErrNoRows {
302Ôćĺ		return nil, nil
303Ôćĺ	}
304Ôćĺ	if err != nil {
305Ôćĺ		return nil, err
306Ôćĺ	}
307Ôćĺ	return &c, nil
308Ôćĺ}
309Ôćĺ
310Ôćĺ// buildScopes derives the atom lookup scopes from a contact.
311Ôćĺ// More specific scopes come first; QueryAtoms returns best match.
312Ôćĺfunc buildScopes(contact *Contact) []string {
313Ôćĺ	if contact == nil {
314Ôćĺ		return nil
315Ôćĺ	}
316Ôćĺ	var scopes []string
317Ôćĺ	// Persona/title scope
318Ôćĺ	if contact.Title != "" {
319Ôćĺ		scopes = append(scopes, normalizeScope(contact.Title))
320Ôćĺ	}
321Ôćĺ	// Tier scope
322Ôćĺ	if contact.Tier > 0 {
323Ôćĺ		scopes = append(scopes, fmt.Sprintf("tier_%d", contact.Tier))
324Ôćĺ	}
325Ôćĺ	// Industry scope
326Ôćĺ	if contact.Industry != "" {
327Ôćĺ		scopes = append(scopes, normalizeScope(contact.Industry))
328Ôćĺ	}
329Ôćĺ	// Domain scope (for company-specific atoms)
330Ôćĺ	if contact.Domain != "" {
331Ôćĺ		scopes = append(scopes, contact.Domain)
332Ôćĺ	}
333Ôćĺ	return scopes
334Ôćĺ}
335Ôćĺ
336Ôćĺ// normalizeScope lowercases and trims for consistent matching.
337Ôćĺfunc normalizeScope(s string) string {
338Ôćĺ	return strings.ToLower(strings.TrimSpace(s))
339Ôćĺ}
