341Ôćĺ// formatContact renders contact information as readable text.
342Ôćĺfunc formatContact(c *Contact) string {
343Ôćĺ	var lines []string
344Ôćĺ	lines = append(lines, fmt.Sprintf("**Prospect:** %s", c.Email))
345Ôćĺ	if c.Name != "" {
346Ôćĺ		lines = append(lines, fmt.Sprintf("**Name:** %s", c.Name))
347Ôćĺ	}
348Ôćĺ	if c.Title != "" {
349Ôćĺ		lines = append(lines, fmt.Sprintf("**Title:** %s", c.Title))
350Ôćĺ	}
351Ôćĺ	if c.Company != "" {
352Ôćĺ		lines = append(lines, fmt.Sprintf("**Company:** %s", c.Company))
353Ôćĺ	}
354Ôćĺ	if c.Domain != "" {
355Ôćĺ		lines = append(lines, fmt.Sprintf("**Domain:** %s", c.Domain))
356Ôćĺ	}
357Ôćĺ	if c.Industry != "" {
358Ôćĺ		lines = append(lines, fmt.Sprintf("**Industry:** %s", c.Industry))
359Ôćĺ	}
360Ôćĺ	if c.FundingStage != "" {
361Ôćĺ		lines = append(lines, fmt.Sprintf("**Funding:** %s", c.FundingStage))
362Ôćĺ	}
363Ôćĺ	if c.CompanySize != "" {
