442Ôćĺ// extractContent tries to pretty-print JSON content; falls back to raw string.
443Ôćĺfunc extractContent(raw json.RawMessage) string {
444Ôćĺ	// Try to unmarshal as a string first (common for text atoms)
445Ôćĺ	var s string
446Ôćĺ	if err := json.Unmarshal(raw, &s); err == nil {
447Ôćĺ		return s
448Ôćĺ	}
449Ôćĺ	// Return formatted JSON for structured atoms
450Ôćĺ	var pretty json.RawMessage
451Ôćĺ	if err := json.Unmarshal(raw, &pretty); err == nil {
452Ôćĺ		indented, err := json.MarshalIndent(pretty, "", "  ")
453Ôćĺ		if err == nil {
454Ôćĺ			return string(indented)
455Ôćĺ		}
456Ôćĺ	}
457Ôćĺ	return string(raw)
458Ôćĺ}
