535Ôćĺ// loadConfigContext reads project config and returns relevant context for the task.
536Ôćĺfunc loadConfigContext(task TaskType) string {
537Ôćĺ	cfg, err := project.Load()
538Ôćĺ	if err != nil {
539Ôćĺ		return ""
540Ôćĺ	}
541Ôćĺ
542Ôćĺ	var lines []string
543Ôćĺ
544Ôćĺ	// Show connected services
545Ôćĺ	if len(cfg.Connectors) > 0 {
546Ôćĺ		var connected []string
547Ôćĺ		for id, c := range cfg.Connectors {
548Ôćĺ			if c.Connected {
549Ôćĺ				connected = append(connected, id)
550Ôćĺ			}
551Ôćĺ		}
552Ôćĺ		if len(connected) > 0 {
553Ôćĺ			lines = append(lines, fmt.Sprintf("**Connected services:** %s", strings.Join(connected, ", ")))
554Ôćĺ		}
555Ôćĺ	}
556Ôćĺ
557Ôćĺ	// Show relevant settings
558Ôćĺ	if cfg.Settings != nil {
559Ôćĺ		// Always include ICP and product info if available
560Ôćĺ		if v, ok := cfg.Settings["product.name"]; ok && v != "" {
561Ôćĺ			lines = append(lines, fmt.Sprintf("**Product:** %s", v))
562Ôćĺ		}
563Ôćĺ		if v, ok := cfg.Settings["product.url"]; ok && v != "" {
564Ôćĺ			lines = append(lines, fmt.Sprintf("**Website:** %s", v))
565Ôćĺ		}
566Ôćĺ		if v, ok := cfg.Settings["icp.titles"]; ok && v != "" {
567Ôćĺ			lines = append(lines, fmt.Sprintf("**ICP Titles:** %s", v))
568Ôćĺ		}
569Ôćĺ		if v, ok := cfg.Settings["icp.industries"]; ok && v != "" {
570Ôćĺ			lines = append(lines, fmt.Sprintf("**ICP Industries:** %s", v))
571Ôćĺ		}
572Ôćĺ		if v, ok := cfg.Settings["icp.company_size"]; ok && v != "" {
573Ôćĺ			lines = append(lines, fmt.Sprintf("**ICP Company Size:** %s", v))
574Ôćĺ		}
575Ôćĺ		if v, ok := cfg.Settings["sender.name"]; ok && v != "" {
576Ôćĺ			lines = append(lines, fmt.Sprintf("**Sender:** %s", v))
577Ôćĺ		}
578Ôćĺ		if v, ok := cfg.Settings["sender.email"]; ok && v != "" {
579Ôćĺ			lines = append(lines, fmt.Sprintf("**From:** %s", v))
580Ôćĺ		}
581Ôćĺ
582Ôćĺ		// Task-specific settings
583Ôćĺ		switch task {
584Ôćĺ		case TaskHygiene, TaskSendHealth:
585Ôćĺ			if v, ok := cfg.Settings["sending.daily_cap"]; ok && v != "" {
586Ôćĺ				lines = append(lines, fmt.Sprintf("**Daily Cap:** %s", v))
587Ôćĺ			}
588Ôćĺ		case TaskSequence:
589Ôćĺ			if v, ok := cfg.Settings["sequence.default_template"]; ok && v != "" {
590Ôćĺ				lines = append(lines, fmt.Sprintf("**Default Sequence:** %s", v))
591Ôćĺ			}
592Ôćĺ		}
593Ôćĺ	}
594Ôćĺ
595Ôćĺ	if len(lines) == 0 {
596Ôćĺ		return ""
597Ôćĺ	}
598Ôćĺ	return strings.Join(lines, "\n")
599Ôćĺ}
600Ôćĺ
601Ôćĺ// estimateTokens does a rough word count * 1.3 approximation.
602Ôćĺfunc estimateTokens(text string) int {
603Ôćĺ	words := len(strings.Fields(text))
604Ôćĺ	return int(float64(words) * 1.3)
605Ôćĺ}
