package assembly

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/usenurge/nurgesh/internal/project"
)

// TaskType identifies the kind of work being assembled for.
type TaskType string

const (
	TaskOutbound   TaskType = "outbound"
	TaskResearch   TaskType = "research"
	TaskQualify    TaskType = "qualify"
	TaskFollowup   TaskType = "followup"
	TaskReply      TaskType = "reply"
	TaskPipeline   TaskType = "pipeline"
	TaskSequence   TaskType = "sequence"
	TaskAnalytics  TaskType = "analytics"
	TaskProspects  TaskType = "prospects"
	TaskProduct    TaskType = "product"
	TaskICP        TaskType = "icp"
	TaskPersonas   TaskType = "personas"
	TaskBook       TaskType = "book"
	TaskHygiene    TaskType = "hygiene"
	TaskSendHealth TaskType = "sending_health"
	TaskReview     TaskType = "review"
)

// ValidTaskTypes enumerates all recognized tasks.
var ValidTaskTypes = map[TaskType]bool{
	TaskOutbound:   true,
	TaskResearch:   true,
	TaskQualify:    true,
	TaskFollowup:   true,
	TaskReply:      true,
	TaskPipeline:   true,
	TaskSequence:   true,
	TaskAnalytics:  true,
	TaskProspects:  true,
	TaskProduct:    true,
	TaskICP:        true,
	TaskPersonas:   true,
	TaskBook:       true,
	TaskHygiene:    true,
	TaskSendHealth: true,
	TaskReview:     true,
}

// AssembleRequest describes what context to build.
type AssembleRequest struct {
	Task     TaskType
	Prospect string // email address; empty for non-prospect tasks
	Format   string // markdown, json, text
}

// AssembleResult is the assembled context payload.
type AssembleResult struct {
	Context       string   `json:"context"`
	TokenEstimate int      `json:"token_estimate"`
	AtomsLoaded   []string `json:"atoms_loaded"`
	Directives    []string `json:"directives"`
	Cached        bool     `json:"cached"`
}

// Contact mirrors the contacts table for assembly use.
type Contact struct {
	ID                string  `json:"id"`
	Source            string  `json:"source"`
	Email             string  `json:"email"`
	Name              string  `json:"name"`
	Domain            string  `json:"domain"`
	Company           string  `json:"company"`
	Title             string  `json:"title"`
	Phone             string  `json:"phone"`
	LeadStatus        string  `json:"lead_status"`
	Tier              int     `json:"tier"`
	TierScore         float64 `json:"tier_score"`
	Industry          string  `json:"industry"`
	FundingStage      string  `json:"funding_stage"`
	CompanySize       string  `json:"company_size"`
	LinkedInURL       string  `json:"linkedin_url"`
	Signals           string  `json:"signals"`
	TechStack         string  `json:"tech_stack"`
	DataConfidence    float64 `json:"data_confidence"`
	ResolveSource     string  `json:"resolve_source"`
	EnrichedAt        string  `json:"enriched_at"`
	EnrichmentSources string  `json:"enrichment_sources"`
}

// Learning mirrors the learnings table row.
type Learning struct {
	ID            int    `json:"id"`
	Type          string `json:"type"`
	Content       string `json:"content"`
	SourceSession string `json:"source_session"`
	CreatedAt     string `json:"created_at"`
}

// defaultCache is the package-level in-memory cache (5-minute TTL).
var defaultCache = NewAssemblyCache(5 * time.Minute)

// taskAtomMap defines which atom types each task requires.
var taskAtomMap = map[TaskType][]AtomType{
	TaskOutbound:   {AtomTone, AtomStructure, AtomHooks, AtomPositioning, AtomObjections, AtomCompliance},
	TaskFollowup:   {AtomTone, AtomStructure, AtomHooks, AtomPositioning, AtomObjections, AtomTiming},
	TaskReply:      {AtomTone, AtomStructure, AtomObjections, AtomPositioning},
	TaskResearch:   {AtomPersonas, AtomPositioning},
	TaskQualify:    {AtomPersonas, AtomPositioning, AtomObjections},
	TaskSequence:   {AtomTone, AtomStructure, AtomHooks, AtomPositioning, AtomTiming},
	TaskBook:       {AtomTone, AtomStructure, AtomHooks},
	TaskPipeline:   {},
	TaskAnalytics:  {},
	TaskProspects:  {AtomPersonas},
	TaskProduct:    {AtomPositioning},
	TaskICP:        {AtomPersonas, AtomPositioning},
	TaskPersonas:   {AtomPersonas},
	TaskHygiene:    {},
	TaskSendHealth: {},
	TaskReview:     {},
}

// prospectTasks are tasks that typically involve a specific prospect.
var prospectTasks = map[TaskType]bool{
	TaskOutbound: true,
	TaskFollowup: true,
	TaskReply:    true,
	TaskResearch: true,
	TaskQualify:  true,
	TaskSequence: true,
	TaskBook:     true,
}

// Assemble builds the context prompt for a given task and optional prospect.
func Assemble(database *sql.DB, req AssembleRequest) (*AssembleResult, error) {
	if !ValidTaskTypes[req.Task] {
		return nil, fmt.Errorf("unknown task type: %s", req.Task)
	}
	if req.Format == "" {
		req.Format = "markdown"
	}

	// Check in-memory cache
	cacheKey := string(req.Task) + ":" + req.Prospect
	if cached, ok := defaultCache.Get(cacheKey); ok {
		return &AssembleResult{
			Context:       cached,
			TokenEstimate: estimateTokens(cached),
			Cached:        true,
		}, nil
	}

	var sections []section
	var atomsLoaded []string
	var directives []string

	// Load prospect info if applicable
	var contact *Contact
	if req.Prospect != "" {
		c, err := getContact(database, req.Prospect)
		if err != nil {
			return nil, fmt.Errorf("querying contact: %w", err)
		}
		contact = c
	}

	// Build prospect context section
	if contact != nil {
		sections = append(sections, section{
			heading: "Context",
			body:    formatContact(contact),
		})
	} else if req.Prospect != "" && prospectTasks[req.Task] {
		// Prospect specified but not found -- directive to enrich
		sections = append(sections, section{
			heading: "Context",
			body:    fmt.Sprintf("Prospect: %s (not in contacts -- limited context available)", req.Prospect),
		})
		directives = append(directives, "enrich_required: contact not found in database, run nurge resolve to enrich")
	}

	// Determine scopes for atom queries based on contact
	scopes := buildScopes(contact)

	// Load atoms for this task type
	neededAtoms := taskAtomMap[req.Task]
	for _, atomType := range neededAtoms {
		atoms, err := QueryAtoms(database, atomType, scopes...)
		if err != nil {
			return nil, fmt.Errorf("querying %s atoms: %w", atomType, err)
		}
		if len(atoms) > 0 {
			best := pickBestAtom(atoms, scopes)
			content := extractContent(best.Content)
			heading := atomHeading(atomType)
			sections = append(sections, section{heading: heading, body: content})
			atomsLoaded = append(atomsLoaded, fmt.Sprintf("%s/%s", best.AtomType, best.Scope))
			// Touch the atom to track usage
			_ = TouchAtom(database, best.ID)
		}
	}

	// Research dossier for prospect-facing tasks
	if req.Prospect != "" && prospectTasks[req.Task] {
		dossier, err := GetDossier(database, req.Prospect)
		if err != nil {
			return nil, fmt.Errorf("getting dossier: %w", err)
		}
		if dossier != nil {
			content := extractContent(dossier.Dossier)
			sections = append(sections, section{heading: "Research", body: content})
		} else if contact != nil && contact.Tier > 0 && contact.Tier <= 2 {
			directives = append(directives, "research_required: Tier 1/2 prospect has no research dossier -- run /nurge:research first")
		}
	}

	// Check for empty enrichment fields on known contacts
	if contact != nil && contact.EnrichedAt == "" && prospectTasks[req.Task] {
		directives = append(directives, "enrich_required: contact has not been enriched -- run nurge resolve to fill in company, title, and signals")
	}

	// Load recent relevant learnings
	learnings, err := queryRecentLearnings(database, req.Task, 10)
	if err != nil {
		return nil, fmt.Errorf("querying learnings: %w", err)
	}
	if len(learnings) > 0 {
		var lines []string
		for _, l := range learnings {
			lines = append(lines, fmt.Sprintf("- [%s] %s", l.Type, l.Content))
		}
		sections = append(sections, section{heading: "Recent Learnings", body: strings.Join(lines, "\n")})
	}

	// Load config context
	cfgSection := loadConfigContext(req.Task)
	if cfgSection != "" {
		sections = append(sections, section{heading: "Configuration", body: cfgSection})
	}

	// Directives section (placed early so the skill sees it first)
	var result strings.Builder
	if len(directives) > 0 {
		result.WriteString("## Directives\n")
		for _, d := range directives {
			result.WriteString(fmt.Sprintf("- %s\n", d))
		}
		result.WriteString("\n")
	}

	// Render remaining sections
	for _, s := range sections {
		result.WriteString(fmt.Sprintf("## %s\n%s\n\n", s.heading, s.body))
	}

	context := strings.TrimSpace(result.String())

	// Cache the result
	defaultCache.Set(cacheKey, context)

	return &AssembleResult{
		Context:       context,
		TokenEstimate: estimateTokens(context),
		AtomsLoaded:   atomsLoaded,
		Directives:    directives,
		Cached:        false,
	}, nil
}

// InvalidateCache clears the in-memory assembly cache.
func InvalidateCache() {
	defaultCache.Invalidate()
}

// section is a titled block in the assembled output.
type section struct {
	heading string
	body    string
}

// getContact queries the contacts table by email.
func getContact(database *sql.DB, email string) (*Contact, error) {
	var c Contact
	err := database.QueryRow(`
		SELECT id, source, email, name, domain, company, title, phone,
			   lead_status, tier, tier_score, industry, funding_stage,
			   company_size, linkedin_url, signals, tech_stack,
			   data_confidence, resolve_source, enriched_at, enrichment_sources
		FROM contacts WHERE email = ?
	`, email).Scan(
		&c.ID, &c.Source, &c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
		&c.LeadStatus, &c.Tier, &c.TierScore, &c.Industry, &c.FundingStage,
		&c.CompanySize, &c.LinkedInURL, &c.Signals, &c.TechStack,
		&c.DataConfidence, &c.ResolveSource, &c.EnrichedAt, &c.EnrichmentSources,
	)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	return &c, nil
}

// buildScopes derives the atom lookup scopes from a contact.
// More specific scopes come first; QueryAtoms returns best match.
func buildScopes(contact *Contact) []string {
	if contact == nil {
		return nil
	}
	var scopes []string
	// Persona/title scope
	if contact.Title != "" {
		scopes = append(scopes, normalizeScope(contact.Title))
	}
	// Tier scope
	if contact.Tier > 0 {
		scopes = append(scopes, fmt.Sprintf("tier_%d", contact.Tier))
	}
	// Industry scope
	if contact.Industry != "" {
		scopes = append(scopes, normalizeScope(contact.Industry))
	}
	// Domain scope (for company-specific atoms)
	if contact.Domain != "" {
		scopes = append(scopes, contact.Domain)
	}
	return scopes
}

// normalizeScope lowercases and trims for consistent matching.
func normalizeScope(s string) string {
	return strings.ToLower(strings.TrimSpace(s))
}

// formatContact renders contact information as readable text.
func formatContact(c *Contact) string {
	var lines []string
	lines = append(lines, fmt.Sprintf("**Prospect:** %s", c.Email))
	if c.Name != "" {
		lines = append(lines, fmt.Sprintf("**Name:** %s", c.Name))
	}
	if c.Title != "" {
		lines = append(lines, fmt.Sprintf("**Title:** %s", c.Title))
	}
	if c.Company != "" {
		lines = append(lines, fmt.Sprintf("**Company:** %s", c.Company))
	}
	if c.Domain != "" {
		lines = append(lines, fmt.Sprintf("**Domain:** %s", c.Domain))
	}
	if c.Industry != "" {
		lines = append(lines, fmt.Sprintf("**Industry:** %s", c.Industry))
	}
	if c.FundingStage != "" {
		lines = append(lines, fmt.Sprintf("**Funding:** %s", c.FundingStage))
	}
	if c.CompanySize != "" {
		lines = append(lines, fmt.Sprintf("**Company Size:** %s", c.CompanySize))
	}
	if c.Tier > 0 {
		lines = append(lines, fmt.Sprintf("**Tier:** %d (score: %.1f)", c.Tier, c.TierScore))
	}
	if c.LeadStatus != "" {
		lines = append(lines, fmt.Sprintf("**Lead Status:** %s", c.LeadStatus))
	}
	if c.LinkedInURL != "" {
		lines = append(lines, fmt.Sprintf("**LinkedIn:** %s", c.LinkedInURL))
	}
	if c.Signals != "" && c.Signals != "[]" {
		lines = append(lines, fmt.Sprintf("**Signals:** %s", c.Signals))
	}
	if c.TechStack != "" && c.TechStack != "[]" {
		lines = append(lines, fmt.Sprintf("**Tech Stack:** %s", c.TechStack))
	}
	return strings.Join(lines, "\n")
}

// pickBestAtom selects the most relevant atom from candidates.
// It prefers scoped matches over the global fallback. Among scoped matches,
// it picks the one whose scope appears earliest in the scopes list
// (most specific first). Falls back to confidence/recency ordering.
func pickBestAtom(atoms []KnowledgeAtom, scopes []string) KnowledgeAtom {
	if len(atoms) == 1 {
		return atoms[0]
	}

	// Build scope priority: lower index = higher priority
	scopePrio := make(map[string]int, len(scopes))
	for i, s := range scopes {
		scopePrio[s] = i
	}

	best := atoms[0]
	bestPrio := len(scopes) + 1 // global ("") gets worst priority
	if p, ok := scopePrio[best.Scope]; ok {
		bestPrio = p
	}

	for _, a := range atoms[1:] {
		prio := len(scopes) + 1
		if p, ok := scopePrio[a.Scope]; ok {
			prio = p
		}
		if prio < bestPrio {
			best = a
			bestPrio = prio
		}
	}
	return best
}

// atomHeading maps atom types to markdown section headings.
func atomHeading(at AtomType) string {
	switch at {
	case AtomTone:
		return "Tone"
	case AtomStructure:
		return "Structure"
	case AtomHooks:
		return "Hooks"
	case AtomPositioning:
		return "Positioning"
	case AtomPersonas:
		return "Personas"
	case AtomObjections:
		return "Objections"
	case AtomTiming:
		return "Timing"
	case AtomCompliance:
		return "Compliance"
	default:
		return string(at)
	}
}

// extractContent tries to pretty-print JSON content; falls back to raw string.
func extractContent(raw json.RawMessage) string {
	// Try to unmarshal as a string first (common for text atoms)
	var s string
	if err := json.Unmarshal(raw, &s); err == nil {
		return s
	}
	// Return formatted JSON for structured atoms
	var pretty json.RawMessage
	if err := json.Unmarshal(raw, &pretty); err == nil {
		indented, err := json.MarshalIndent(pretty, "", "  ")
		if err == nil {
			return string(indented)
		}
	}
	return string(raw)
}

// queryRecentLearnings returns recent learnings relevant to the task.
func queryRecentLearnings(database *sql.DB, task TaskType, limit int) ([]Learning, error) {
	// Map tasks to relevant learning types
	learningTypes := taskLearningTypes(task)
	if len(learningTypes) == 0 {
		// Fallback: grab the most recent learnings of any type
		return queryLearningsByTypes(database, nil, limit)
	}
	return queryLearningsByTypes(database, learningTypes, limit)
}

// taskLearningTypes maps task types to relevant learning types.
func taskLearningTypes(task TaskType) []string {
	switch task {
	case TaskOutbound, TaskSequence, TaskBook:
		return []string{"tone", "style", "positioning", "rejection", "preference"}
	case TaskFollowup:
		return []string{"tone", "style", "timing", "preference"}
	case TaskReply:
		return []string{"tone", "objection", "style", "preference"}
	case TaskResearch, TaskQualify:
		return []string{"icp", "positioning", "preference"}
	case TaskPipeline:
		return []string{"preference", "workflow"}
	case TaskAnalytics, TaskReview:
		return []string{"preference", "metric"}
	case TaskProspects, TaskICP, TaskPersonas:
		return []string{"icp", "persona", "preference"}
	case TaskProduct:
		return []string{"positioning", "product", "preference"}
	case TaskHygiene, TaskSendHealth:
		return []string{"preference", "compliance"}
	default:
		return nil
	}
}

// queryLearningsByTypes fetches learnings, optionally filtered by type, newest first.
func queryLearningsByTypes(database *sql.DB, types []string, limit int) ([]Learning, error) {
	var query string
	var args []any

	if len(types) == 0 {
		query = `SELECT id, type, content, source_session, created_at FROM learnings ORDER BY created_at DESC LIMIT ?`
		args = append(args, limit)
	} else {
		placeholders := make([]string, len(types))
		for i, t := range types {
			placeholders[i] = "?"
			args = append(args, t)
		}
		query = fmt.Sprintf(
			`SELECT id, type, content, source_session, created_at FROM learnings WHERE type IN (%s) ORDER BY created_at DESC LIMIT ?`,
			strings.Join(placeholders, ","),
		)
		args = append(args, limit)
	}

	rows, err := database.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("querying learnings: %w", err)
	}
	defer rows.Close()

	var learnings []Learning
	for rows.Next() {
		var l Learning
		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
			return nil, fmt.Errorf("scanning learning: %w", err)
		}
		learnings = append(learnings, l)
	}
	return learnings, rows.Err()
}

// loadConfigContext reads project config and returns relevant context for the task.
func loadConfigContext(task TaskType) string {
	cfg, err := project.Load()
	if err != nil {
		return ""
	}

	var lines []string

	// Show connected services
	if len(cfg.Connectors) > 0 {
		var connected []string
		for id, c := range cfg.Connectors {
			if c.Connected {
				connected = append(connected, id)
			}
		}
		if len(connected) > 0 {
			lines = append(lines, fmt.Sprintf("**Connected services:** %s", strings.Join(connected, ", ")))
		}
	}

	// Show relevant settings
	if cfg.Settings != nil {
		// Always include ICP and product info if available
		if v, ok := cfg.Settings["product.name"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**Product:** %s", v))
		}
		if v, ok := cfg.Settings["product.url"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**Website:** %s", v))
		}
		if v, ok := cfg.Settings["icp.titles"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**ICP Titles:** %s", v))
		}
		if v, ok := cfg.Settings["icp.industries"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**ICP Industries:** %s", v))
		}
		if v, ok := cfg.Settings["icp.company_size"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**ICP Company Size:** %s", v))
		}
		if v, ok := cfg.Settings["sender.name"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**Sender:** %s", v))
		}
		if v, ok := cfg.Settings["sender.email"]; ok && v != "" {
			lines = append(lines, fmt.Sprintf("**From:** %s", v))
		}

		// Task-specific settings
		switch task {
		case TaskHygiene, TaskSendHealth:
			if v, ok := cfg.Settings["sending.daily_cap"]; ok && v != "" {
				lines = append(lines, fmt.Sprintf("**Daily Cap:** %s", v))
			}
		case TaskSequence:
			if v, ok := cfg.Settings["sequence.default_template"]; ok && v != "" {
				lines = append(lines, fmt.Sprintf("**Default Sequence:** %s", v))
			}
		}
	}

	if len(lines) == 0 {
		return ""
	}
	return strings.Join(lines, "\n")
}

// estimateTokens does a rough word count * 1.3 approximation.
func estimateTokens(text string) int {
	words := len(strings.Fields(text))
	return int(float64(words) * 1.3)
}

