122Ôćĺ		matched := false
123Ôćĺ		for _, ind := range icp.TargetIndustries {
124Ôćĺ			if strings.ToLower(ind) == contactInd {
125Ôćĺ				fit += 40
126Ôćĺ				reasons = append(reasons, fmt.Sprintf("industry match: %s", contact.Industry))
127Ôćĺ				matched = true
128Ôćĺ				break
129Ôćĺ			}
130Ôćĺ		}
131Ôćĺ		if !matched {
132Ôćĺ			// Check for related industry (substring match as heuristic)
133Ôćĺ			for _, ind := range icp.TargetIndustries {
134Ôćĺ				if strings.Contains(contactInd, strings.ToLower(ind)) ||
135Ôćĺ					strings.Contains(strings.ToLower(ind), contactInd) {
136Ôćĺ					fit += 20
137Ôćĺ					reasons = append(reasons, fmt.Sprintf("related industry: %s ~ %s", contact.Industry, ind))
138Ôćĺ					break
139Ôćĺ				}
140Ôćĺ			}
141Ôćĺ		}
142Ôćĺ	}
143Ôćĺ
144Ôćĺ	// Company size in range: +30
145Ôćĺ	if contact.CompanySize != "" && icp.CompanySizeRange != "" {
146Ôćĺ		if sizeInRange(contact.CompanySize, icp.CompanySizeRange) {
147Ôćĺ			fit += 30
148Ôćĺ			reasons = append(reasons, fmt.Sprintf("company size %s in range %s", contact.CompanySize, icp.CompanySizeRange))
149Ôćĺ		}
150Ôćĺ	}
151Ôćĺ
152Ôćĺ	// Geography match: +15
153Ôćĺ	if icp.Geography != "" && contact.Domain != "" {
154Ôćĺ		// Simple heuristic: geography is stored in config, we check domain TLD or company info
155Ôćĺ		// This is a basic check; enrichment would improve accuracy
156Ôćĺ		if strings.EqualFold(icp.Geography, "global") {
157Ôćĺ			fit += 15
158Ôćĺ			reasons = append(reasons, "geography: global target")
159Ôćĺ		}
160Ôćĺ	}
161Ôćĺ
162Ôćĺ	// Funding stage match: +15
163Ôćĺ	if contact.FundingStage != "" && icp.FundingStage != "" {
164Ôćĺ		if strings.EqualFold(contact.FundingStage, icp.FundingStage) {
165Ôćĺ			fit += 15
166Ôćĺ			reasons = append(reasons, fmt.Sprintf("funding stage match: %s", contact.FundingStage))
167Ôćĺ		}
168Ôćĺ	}
169Ôćĺ
170Ôćĺ	// Title match (bonus, uses target titles from ICP)
171Ôćĺ	if contact.Title != "" && len(icp.TargetTitles) > 0 {
172Ôćĺ		contactTitle := strings.ToLower(contact.Title)
173Ôćĺ		for _, t := range icp.TargetTitles {
174Ôćĺ			if strings.Contains(contactTitle, strings.ToLower(t)) {
175Ôćĺ				// Title match doesn't add to the 100-point scale directly
176Ôćĺ				// but we record it as a reason for context
177Ôćĺ				reasons = append(reasons, fmt.Sprintf("title match: %s", contact.Title))
178Ôćĺ				break
179Ôćĺ			}
180Ôćĺ		}
181Ôćĺ	}
182Ôćĺ
183Ôćĺ	if fit > 100 {
184Ôćĺ		fit = 100
185Ôćĺ	}
186Ôćĺ	return fit, reasons
187Ôćĺ}
188Ôćĺ
189Ôćĺfunc scoreBuyingTrigger(signals []string, reasons *[]string) float64 {
190Ôćĺ	triggerScores := map[string]float64{
191Ôćĺ		"funding":        40,
192Ôćĺ		"job_change":     35,
193Ôćĺ		"hiring":         25,
194Ôćĺ		"product_launch": 20,
195Ôćĺ		"expansion":      15,
196Ôćĺ	}
197Ôćĺ
198Ôćĺ	var total float64
199Ôćĺ	for _, sig := range signals {
200Ôćĺ		s := strings.ToLower(sig)
201Ôćĺ		if pts, ok := triggerScores[s]; ok {
202Ôćĺ			total += pts
203Ôćĺ			*reasons = append(*reasons, fmt.Sprintf("buying trigger: %s (+%.0f)", sig, pts))
204Ôćĺ		}
205Ôćĺ	}
206Ôćĺ
207Ôćĺ	if total > 100 {
208Ôćĺ		total = 100
209Ôćĺ	}
210Ôćĺ	return total
211Ôćĺ}
212Ôćĺ
213Ôćĺfunc scoreIntentSignal(contact ContactData, hasReply bool, hasActiveSequence bool, reasons *[]string) float64 {
214Ôćĺ	var total float64
215Ôćĺ
216Ôćĺ	// Has prior email interaction (email_count > 0): +40
217Ôćĺ	if contact.EmailCount > 0 {
218Ôćĺ		total += 40
219Ôćĺ		*reasons = append(*reasons, fmt.Sprintf("prior emails: %d", contact.EmailCount))
220Ôćĺ	}
221Ôćĺ
222Ôćĺ	// Was previously replied to: +30
223Ôćĺ	if hasReply {
224Ôćĺ		total += 30
225Ôćĺ		*reasons = append(*reasons, "has reply event")
226Ôćĺ	}
227Ôćĺ
228Ôćĺ	// Has been emailed recently (last 30 days): +20
229Ôćĺ	if contact.LastEmailedAt != "" {
230Ôćĺ		if t, err := time.Parse(time.RFC3339, contact.LastEmailedAt); err == nil {
231Ôćĺ			if time.Since(t) <= 30*24*time.Hour {
232Ôćĺ				total += 20
233Ôćĺ				*reasons = append(*reasons, "emailed within last 30 days")
234Ôćĺ			}
235Ôćĺ		} else if t, err := time.Parse("2006-01-02T15:04:05", contact.LastEmailedAt); err == nil {
236Ôćĺ			if time.Since(t) <= 30*24*time.Hour {
237Ôćĺ				total += 20
238Ôćĺ				*reasons = append(*reasons, "emailed within last 30 days")
239Ôćĺ			}
240Ôćĺ		}
241Ôćĺ	}
242Ôćĺ
243Ôćĺ	// Part of active sequence: +10
244Ôćĺ	if hasActiveSequence {
245Ôćĺ		total += 10
246Ôćĺ		*reasons = append(*reasons, "active sequence enrollment")
247Ôćĺ	}
248Ôćĺ
249Ôćĺ	if total > 100 {
250Ôćĺ		total = 100
251Ôćĺ	}
252Ôćĺ	return total
253Ôćĺ}
254Ôćĺ
255Ôćĺfunc scoreAccessibility(contact ContactData, reasons *[]string) float64 {
256Ôćĺ	var total float64
257Ôćĺ
258Ôćĺ	// Has verified email (we assume non-empty email is present ÔÇö check for generic): +40
259Ôćĺ	if contact.Email != "" && !isGenericEmail(contact.Email) {
260Ôćĺ		total += 40
261Ôćĺ		*reasons = append(*reasons, "has direct email")
262Ôćĺ	} else if contact.Email != "" {
263Ôćĺ		total += 20
264Ôćĺ		*reasons = append(*reasons, "has email (generic)")
265Ôćĺ	}
266Ôćĺ
267Ôćĺ	// Has phone number: +20
268Ôćĺ	if contact.Phone != "" {
269Ôćĺ		total += 20
270Ôćĺ		*reasons = append(*reasons, "has phone number")
271Ôćĺ	}
272Ôćĺ
273Ôćĺ	// Has LinkedIn URL: +20
274Ôćĺ	if contact.LinkedInURL != "" {
275Ôćĺ		total += 20
276Ôćĺ		*reasons = append(*reasons, "has LinkedIn URL")
277Ôćĺ	}
278Ôćĺ
279Ôćĺ	// Has direct contact (not generic email): +20
280Ôćĺ	// Already handled above (40 for direct vs 20 for generic)
281Ôćĺ	// Use website as an additional signal
282Ôćĺ	if contact.Website != "" {
283Ôćĺ		total += 20
284Ôćĺ		*reasons = append(*reasons, "has website")
285Ôćĺ	}
286Ôćĺ
287Ôćĺ	if total > 100 {
