367Ôćĺ// ICPConfigFromSettings builds an ICPConfig from a settings map.
368Ôćĺfunc ICPConfigFromSettings(settings map[string]string) ICPConfig {
369Ôćĺ	if settings == nil {
370Ôćĺ		return ICPConfig{}
371Ôćĺ	}
372Ôćĺ
373Ôćĺ	icp := ICPConfig{
374Ôćĺ		CompanySizeRange: settings["icp.company_size"],
375Ôćĺ		FundingStage:     settings["icp.stage"],
376Ôćĺ		Geography:        settings["icp.geography"],
377Ôćĺ	}
378Ôćĺ
379Ôćĺ	if ind := settings["icp.industry"]; ind != "" {
380Ôćĺ		icp.TargetIndustries = splitCSV(ind)
381Ôćĺ	}
382Ôćĺ	if titles := settings["icp.titles"]; titles != "" {
383Ôćĺ		icp.TargetTitles = splitCSV(titles)
384Ôćĺ	}
