389Ôćĺfunc splitCSV(s string) []string {
390Ôćĺ	parts := strings.Split(s, ",")
391Ôćĺ	var out []string
392Ôćĺ	for _, p := range parts {
393Ôćĺ		p = strings.TrimSpace(p)
394Ôćĺ		if p != "" {
395Ôćĺ			out = append(out, p)
396Ôćĺ		}
397Ôćĺ	}
398Ôćĺ	return out
399Ôćĺ}
