401Ôćĺ// loadContactFromDB reads a contact row by email.
402Ôćĺfunc loadContactFromDB(d *sql.DB, email string) (*ContactData, error) {
403Ôćĺ	row := d.QueryRow(`
404Ôćĺ		SELECT email, name, domain, company, title, phone,
405Ôćĺ		       industry, company_size, funding_stage,
406Ôćĺ		       linkedin_url, website, signals,
407Ôćĺ		       email_count, COALESCE(last_emailed_at, '')
408Ôćĺ		FROM contacts WHERE email = ?`, email)
409Ôćĺ
410Ôćĺ	var c ContactData
411Ôćĺ	var signalsJSON string
412Ôćĺ	err := row.Scan(
413Ôćĺ		&c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
414Ôćĺ		&c.Industry, &c.CompanySize, &c.FundingStage,
