package tier

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"strconv"
	"strings"
	"time"

	"github.com/usenurge/nurgesh/internal/project"
)

// TierScore holds the breakdown of a contact's tier scoring.
type TierScore struct {
	ICPFit        float64  `json:"icp_fit"`
	BuyingTrigger float64  `json:"buying_trigger"`
	IntentSignal  float64  `json:"intent_signal"`
	Accessibility float64  `json:"accessibility"`
	Total         float64  `json:"total"`
	Tier          int      `json:"tier"`
	Reasons       []string `json:"reasons,omitempty"`
}

// ICPConfig holds the ideal customer profile configuration.
type ICPConfig struct {
	TargetIndustries []string
	CompanySizeRange string // e.g., "50-500"
	FundingStage     string // e.g., "series-a"
	Geography        string
	TargetTitles     []string
}

// ContactData holds the fields needed for scoring a contact.
type ContactData struct {
	Email        string
	Name         string
	Domain       string
	Company      string
	Title        string
	Phone        string
	Industry     string
	CompanySize  string
	FundingStage string
	LinkedInURL  string
	Website      string
	Signals      []string
	EmailCount   int
	LastEmailedAt string
}

// TierResult is a scored contact returned by BatchScore.
type TierResult struct {
	Email string    `json:"email"`
	Name  string    `json:"name"`
	Score TierScore `json:"score"`
}

// TierDistribution holds counts per tier for the --show command.
type TierDistribution struct {
	Tier1   int `json:"tier_1"`
	Tier2   int `json:"tier_2"`
	Tier3   int `json:"tier_3"`
	Unscored int `json:"unscored"`
	Total   int `json:"total"`
}

// Weights for each scoring dimension.
const (
	weightICPFit        = 0.40
	weightBuyingTrigger = 0.25
	weightIntentSignal  = 0.20
	weightAccessibility = 0.15
)

// ScoreContact computes a TierScore for a contact given ICP configuration
// and database-derived intent signals.
func ScoreContact(contact ContactData, icp ICPConfig, hasReply bool, hasActiveSequence bool) TierScore {
	var score TierScore

	// --- ICP Fit (0-100) ---
	score.ICPFit, score.Reasons = scoreICPFit(contact, icp)

	// --- Buying Trigger (0-100) ---
	score.BuyingTrigger = scoreBuyingTrigger(contact.Signals, &score.Reasons)

	// --- Intent Signal (0-100) ---
	score.IntentSignal = scoreIntentSignal(contact, hasReply, hasActiveSequence, &score.Reasons)

	// --- Accessibility (0-100) ---
	score.Accessibility = scoreAccessibility(contact, &score.Reasons)

	// --- Total (weighted sum) ---
	score.Total = score.ICPFit*weightICPFit +
		score.BuyingTrigger*weightBuyingTrigger +
		score.IntentSignal*weightIntentSignal +
		score.Accessibility*weightAccessibility

	// Round to 1 decimal
	score.Total = float64(int(score.Total*10)) / 10

	// --- Tier assignment ---
	switch {
	case score.Total >= 70:
		score.Tier = 1
	case score.Total >= 40:
		score.Tier = 2
	default:
		score.Tier = 3
	}

	return score
}

func scoreICPFit(contact ContactData, icp ICPConfig) (float64, []string) {
	var fit float64
	var reasons []string

	// Industry match: +40 exact, +20 related
	if contact.Industry != "" && len(icp.TargetIndustries) > 0 {
		contactInd := strings.ToLower(contact.Industry)
		matched := false
		for _, ind := range icp.TargetIndustries {
			if strings.ToLower(ind) == contactInd {
				fit += 40
				reasons = append(reasons, fmt.Sprintf("industry match: %s", contact.Industry))
				matched = true
				break
			}
		}
		if !matched {
			// Check for related industry (substring match as heuristic)
			for _, ind := range icp.TargetIndustries {
				if strings.Contains(contactInd, strings.ToLower(ind)) ||
					strings.Contains(strings.ToLower(ind), contactInd) {
					fit += 20
					reasons = append(reasons, fmt.Sprintf("related industry: %s ~ %s", contact.Industry, ind))
					break
				}
			}
		}
	}

	// Company size in range: +30
	if contact.CompanySize != "" && icp.CompanySizeRange != "" {
		if sizeInRange(contact.CompanySize, icp.CompanySizeRange) {
			fit += 30
			reasons = append(reasons, fmt.Sprintf("company size %s in range %s", contact.CompanySize, icp.CompanySizeRange))
		}
	}

	// Geography match: +15
	if icp.Geography != "" && contact.Domain != "" {
		// Simple heuristic: geography is stored in config, we check domain TLD or company info
		// This is a basic check; enrichment would improve accuracy
		if strings.EqualFold(icp.Geography, "global") {
			fit += 15
			reasons = append(reasons, "geography: global target")
		}
	}

	// Funding stage match: +15
	if contact.FundingStage != "" && icp.FundingStage != "" {
		if strings.EqualFold(contact.FundingStage, icp.FundingStage) {
			fit += 15
			reasons = append(reasons, fmt.Sprintf("funding stage match: %s", contact.FundingStage))
		}
	}

	// Title match (bonus, uses target titles from ICP)
	if contact.Title != "" && len(icp.TargetTitles) > 0 {
		contactTitle := strings.ToLower(contact.Title)
		for _, t := range icp.TargetTitles {
			if strings.Contains(contactTitle, strings.ToLower(t)) {
				// Title match doesn't add to the 100-point scale directly
				// but we record it as a reason for context
				reasons = append(reasons, fmt.Sprintf("title match: %s", contact.Title))
				break
			}
		}
	}

	if fit > 100 {
		fit = 100
	}
	return fit, reasons
}

func scoreBuyingTrigger(signals []string, reasons *[]string) float64 {
	triggerScores := map[string]float64{
		"funding":        40,
		"job_change":     35,
		"hiring":         25,
		"product_launch": 20,
		"expansion":      15,
	}

	var total float64
	for _, sig := range signals {
		s := strings.ToLower(sig)
		if pts, ok := triggerScores[s]; ok {
			total += pts
			*reasons = append(*reasons, fmt.Sprintf("buying trigger: %s (+%.0f)", sig, pts))
		}
	}

	if total > 100 {
		total = 100
	}
	return total
}

func scoreIntentSignal(contact ContactData, hasReply bool, hasActiveSequence bool, reasons *[]string) float64 {
	var total float64

	// Has prior email interaction (email_count > 0): +40
	if contact.EmailCount > 0 {
		total += 40
		*reasons = append(*reasons, fmt.Sprintf("prior emails: %d", contact.EmailCount))
	}

	// Was previously replied to: +30
	if hasReply {
		total += 30
		*reasons = append(*reasons, "has reply event")
	}

	// Has been emailed recently (last 30 days): +20
	if contact.LastEmailedAt != "" {
		if t, err := time.Parse(time.RFC3339, contact.LastEmailedAt); err == nil {
			if time.Since(t) <= 30*24*time.Hour {
				total += 20
				*reasons = append(*reasons, "emailed within last 30 days")
			}
		} else if t, err := time.Parse("2006-01-02T15:04:05", contact.LastEmailedAt); err == nil {
			if time.Since(t) <= 30*24*time.Hour {
				total += 20
				*reasons = append(*reasons, "emailed within last 30 days")
			}
		}
	}

	// Part of active sequence: +10
	if hasActiveSequence {
		total += 10
		*reasons = append(*reasons, "active sequence enrollment")
	}

	if total > 100 {
		total = 100
	}
	return total
}

func scoreAccessibility(contact ContactData, reasons *[]string) float64 {
	var total float64

	// Has verified email (we assume non-empty email is present ÔÇö check for generic): +40
	if contact.Email != "" && !isGenericEmail(contact.Email) {
		total += 40
		*reasons = append(*reasons, "has direct email")
	} else if contact.Email != "" {
		total += 20
		*reasons = append(*reasons, "has email (generic)")
	}

	// Has phone number: +20
	if contact.Phone != "" {
		total += 20
		*reasons = append(*reasons, "has phone number")
	}

	// Has LinkedIn URL: +20
	if contact.LinkedInURL != "" {
		total += 20
		*reasons = append(*reasons, "has LinkedIn URL")
	}

	// Has direct contact (not generic email): +20
	// Already handled above (40 for direct vs 20 for generic)
	// Use website as an additional signal
	if contact.Website != "" {
		total += 20
		*reasons = append(*reasons, "has website")
	}

	if total > 100 {
		total = 100
	}
	return total
}

// isGenericEmail checks if the email looks like a generic/role address.
func isGenericEmail(email string) bool {
	prefixes := []string{
		"info@", "contact@", "hello@", "support@", "sales@",
		"admin@", "help@", "team@", "office@", "general@",
		"enquiries@", "noreply@", "no-reply@",
	}
	lower := strings.ToLower(email)
	for _, p := range prefixes {
		if strings.HasPrefix(lower, p) {
			return true
		}
	}
	return false
}

// sizeInRange checks if a company size string falls within a range like "50-500".
func sizeInRange(sizeStr, rangeStr string) bool {
	// Parse size: could be "150", "150-200", "~200", etc.
	size := parseFirstNumber(sizeStr)
	if size <= 0 {
		return false
	}

	parts := strings.SplitN(rangeStr, "-", 2)
	if len(parts) != 2 {
		return false
	}

	low := parseFirstNumber(parts[0])
	high := parseFirstNumber(parts[1])
	if low <= 0 || high <= 0 {
		return false
	}

	return size >= low && size <= high
}

// parseFirstNumber extracts the first integer from a string.
func parseFirstNumber(s string) int {
	s = strings.TrimSpace(s)
	// Strip non-digit prefix
	start := -1
	for i, c := range s {
		if c >= '0' && c <= '9' {
			if start == -1 {
				start = i
			}
		} else if start != -1 {
			n, err := strconv.Atoi(s[start:i])
			if err == nil {
				return n
			}
			return 0
		}
	}
	if start >= 0 {
		n, err := strconv.Atoi(s[start:])
		if err == nil {
			return n
		}
	}
	return 0
}

// LoadICPConfig reads ICP configuration from the project config file.
func LoadICPConfig() ICPConfig {
	cfg, err := project.Load()
	if err != nil {
		return ICPConfig{}
	}
	return ICPConfigFromSettings(cfg.Settings)
}

// ICPConfigFromSettings builds an ICPConfig from a settings map.
func ICPConfigFromSettings(settings map[string]string) ICPConfig {
	if settings == nil {
		return ICPConfig{}
	}

	icp := ICPConfig{
		CompanySizeRange: settings["icp.company_size"],
		FundingStage:     settings["icp.stage"],
		Geography:        settings["icp.geography"],
	}

	if ind := settings["icp.industry"]; ind != "" {
		icp.TargetIndustries = splitCSV(ind)
	}
	if titles := settings["icp.titles"]; titles != "" {
		icp.TargetTitles = splitCSV(titles)
	}

	return icp
}

func splitCSV(s string) []string {
	parts := strings.Split(s, ",")
	var out []string
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

// loadContactFromDB reads a contact row by email.
func loadContactFromDB(d *sql.DB, email string) (*ContactData, error) {
	row := d.QueryRow(`
		SELECT email, name, domain, company, title, phone,
		       industry, company_size, funding_stage,
		       linkedin_url, website, signals,
		       email_count, COALESCE(last_emailed_at, '')
		FROM contacts WHERE email = ?`, email)

	var c ContactData
	var signalsJSON string
	err := row.Scan(
		&c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
		&c.Industry, &c.CompanySize, &c.FundingStage,
		&c.LinkedInURL, &c.Website, &signalsJSON,
		&c.EmailCount, &c.LastEmailedAt,
	)
	if err != nil {
		return nil, fmt.Errorf("loading contact %s: %w", email, err)
	}

	if signalsJSON != "" && signalsJSON != "[]" {
		_ = json.Unmarshal([]byte(signalsJSON), &c.Signals)
	}

	return &c, nil
}

// hasReplyEvent checks if a contact has any reply events.
func hasReplyEvent(d *sql.DB, email string) bool {
	var n int
	err := d.QueryRow(`SELECT 1 FROM reply_events WHERE contact_email = ? LIMIT 1`, email).Scan(&n)
	return err == nil
}

// hasActiveSequenceEnrollment checks if a contact is in an active sequence.
func hasActiveSequenceEnrollment(d *sql.DB, email string) bool {
	var n int
	err := d.QueryRow(`SELECT 1 FROM sequence_enrollments WHERE contact_email = ? AND status = 'active' LIMIT 1`, email).Scan(&n)
	return err == nil
}

// ScoreAndSave loads a contact from the DB, scores it, updates the DB, and returns the score.
func ScoreAndSave(d *sql.DB, contactEmail string) (*TierScore, error) {
	contact, err := loadContactFromDB(d, contactEmail)
	if err != nil {
		return nil, err
	}

	icp := LoadICPConfig()
	reply := hasReplyEvent(d, contactEmail)
	activeSeq := hasActiveSequenceEnrollment(d, contactEmail)

	score := ScoreContact(*contact, icp, reply, activeSeq)

	_, err = d.Exec(`
		UPDATE contacts
		SET tier = ?, tier_score = ?, tier_scored_at = datetime('now')
		WHERE email = ?`,
		score.Tier, score.Total, contactEmail)
	if err != nil {
		return nil, fmt.Errorf("updating tier for %s: %w", contactEmail, err)
	}

	return &score, nil
}

// BatchScore scores all contacts that are unscored (tier=0) or stale.
// It returns the list of results and the count of contacts scored.
func BatchScore(d *sql.DB, limit int) ([]TierResult, error) {
	icp := LoadICPConfig()

	rows, err := d.Query(`
		SELECT email, name, domain, company, title, phone,
		       industry, company_size, funding_stage,
		       linkedin_url, website, signals,
		       email_count, COALESCE(last_emailed_at, '')
		FROM contacts
		WHERE tier = 0
		   OR tier_scored_at = ''
		   OR tier_scored_at < datetime('now', '-7 days')
		ORDER BY email_count DESC
		LIMIT ?`, limit)
	if err != nil {
		return nil, fmt.Errorf("querying contacts for batch scoring: %w", err)
	}
	defer rows.Close()

	var results []TierResult
	for rows.Next() {
		var c ContactData
		var signalsJSON string
		if err := rows.Scan(
			&c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
			&c.Industry, &c.CompanySize, &c.FundingStage,
			&c.LinkedInURL, &c.Website, &signalsJSON,
			&c.EmailCount, &c.LastEmailedAt,
		); err != nil {
			return nil, fmt.Errorf("scanning contact row: %w", err)
		}

		if signalsJSON != "" && signalsJSON != "[]" {
			_ = json.Unmarshal([]byte(signalsJSON), &c.Signals)
		}

		reply := hasReplyEvent(d, c.Email)
		activeSeq := hasActiveSequenceEnrollment(d, c.Email)
		score := ScoreContact(c, icp, reply, activeSeq)

		_, err := d.Exec(`
			UPDATE contacts
			SET tier = ?, tier_score = ?, tier_scored_at = datetime('now')
			WHERE email = ?`,
			score.Tier, score.Total, c.Email)
		if err != nil {
			return nil, fmt.Errorf("updating tier for %s: %w", c.Email, err)
		}

		results = append(results, TierResult{
			Email: c.Email,
			Name:  c.Name,
			Score: score,
		})
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return results, nil
}

// Distribution queries the contacts table for tier distribution stats.
func Distribution(d *sql.DB) (*TierDistribution, error) {
	rows, err := d.Query(`SELECT tier, COUNT(*) FROM contacts GROUP BY tier`)
	if err != nil {
		return nil, fmt.Errorf("querying tier distribution: %w", err)
	}
	defer rows.Close()

	dist := &TierDistribution{}
	for rows.Next() {
		var tierVal int
		var count int
		if err := rows.Scan(&tierVal, &count); err != nil {
			return nil, fmt.Errorf("scanning tier distribution: %w", err)
		}
		switch tierVal {
		case 1:
			dist.Tier1 = count
		case 2:
			dist.Tier2 = count
		case 3:
			dist.Tier3 = count
		default:
			dist.Unscored += count
		}
		dist.Total += count
	}

	return dist, rows.Err()
}

package resolve

import (
	"database/sql"
	"encoding/csv"
	"fmt"
	"io"
	"net/mail"
	"os"
	"strings"
	"time"

	"github.com/google/uuid"
)

// InputType classifies what the user provided as input.
type InputType string

const (
	InputEmail           InputType = "email"
	InputCSV             InputType = "csv"
	InputLinkedInPerson  InputType = "linkedin_person"
	InputLinkedInCompany InputType = "linkedin_company"
	InputWebsite         InputType = "website"
	InputNameCompany     InputType = "name_company"
)

// ResolveResult is the output of the resolve pipeline.
type ResolveResult struct {
	InputType InputType          `json:"input_type"`
	Contacts  []ResolvedContact  `json:"contacts"`
	Company   *ResolvedCompany   `json:"company,omitempty"`
	Skipped   []SkippedEntry     `json:"skipped,omitempty"`
	Summary   string             `json:"summary"`
	Next      string             `json:"next"` // enrich, find_people, ready
}

// ResolvedContact represents a contact created or matched during resolve.
type ResolvedContact struct {
	ID            string   `json:"id"`
	Email         string   `json:"email"`
	Name          string   `json:"name"`
	Company       string   `json:"company,omitempty"`
	Title         string   `json:"title,omitempty"`
	Status        string   `json:"status"` // created, updated, existing
	MissingFields []string `json:"missing_fields,omitempty"`
	IsNew         bool     `json:"is_new"`
}

// ResolvedCompany represents a company extracted from a URL or domain.
type ResolvedCompany struct {
	Domain   string `json:"domain"`
	Name     string `json:"name"`
	Industry string `json:"industry,omitempty"`
	Size     string `json:"size,omitempty"`
}

// SkippedEntry records an input that was not resolved.
type SkippedEntry struct {
	Input  string `json:"input"`
	Reason string `json:"reason"` // invalid_email, duplicate, suppressed
}

// DetectInputType determines what kind of input the user provided.
func DetectInputType(input string) InputType {
	trimmed := strings.TrimSpace(input)
	lower := strings.ToLower(trimmed)

	if strings.HasSuffix(lower, ".csv") {
		return InputCSV
	}
	if strings.Contains(lower, "linkedin.com/in/") {
		return InputLinkedInPerson
	}
	if strings.Contains(lower, "linkedin.com/company/") {
		return InputLinkedInCompany
	}
	if strings.Contains(trimmed, "@") && looksLikeEmail(trimmed) {
		return InputEmail
	}
	if looksLikeURL(trimmed) {
		return InputWebsite
	}
	return InputNameCompany
}

// Resolve is the main entry point. It detects input type and routes accordingly.
// The company parameter is only used for InputNameCompany.
func Resolve(d *sql.DB, input string, company string) (*ResolveResult, error) {
	if d == nil {
		return nil, fmt.Errorf("database is required")
	}
	input = strings.TrimSpace(input)
	if input == "" {
		return nil, fmt.Errorf("input is required")
	}

	inputType := DetectInputType(input)

	switch inputType {
	case InputEmail:
		return resolveEmail(d, input)
	case InputCSV:
		return resolveCSV(d, input)
	case InputLinkedInPerson:
		return resolveLinkedInPerson(d, input)
	case InputLinkedInCompany:
		return resolveLinkedInCompany(input)
	case InputWebsite:
		return resolveWebsite(input)
	case InputNameCompany:
		return resolveNameCompany(d, input, company)
	default:
		return nil, fmt.Errorf("unsupported input type: %s", inputType)
	}
}

// --- Email ---

func resolveEmail(d *sql.DB, input string) (*ResolveResult, error) {
	email := strings.ToLower(strings.TrimSpace(input))
	if !looksLikeEmail(email) {
		return nil, fmt.Errorf("invalid email address: %s", input)
	}

	domain := domainFromEmail(email)

	// Check suppression
	if suppressed, err := isSuppressed(d, email, domain); err != nil {
		return nil, err
	} else if suppressed {
		return &ResolveResult{
			InputType: InputEmail,
			Skipped:   []SkippedEntry{{Input: email, Reason: "suppressed"}},
			Summary:   fmt.Sprintf("%s is suppressed", email),
			Next:      "ready",
		}, nil
	}

	// Check existing contact
	existing, err := contactByEmail(d, email)
	if err != nil {
		return nil, err
	}

	if existing != nil {
		missing := missingContactFields(existing)
		next := "ready"
		if len(missing) > 0 {
			next = "enrich"
		}
		return &ResolveResult{
			InputType: InputEmail,
			Contacts: []ResolvedContact{{
				ID:            existing.id,
				Email:         existing.email,
				Name:          existing.name,
				Company:       existing.company,
				Title:         existing.title,
				Status:        "existing",
				MissingFields: missing,
				IsNew:         false,
			}},
			Summary: fmt.Sprintf("Found existing contact %s", email),
			Next:    next,
		}, nil
	}

	// Create new contact
	id := newContactID()
	now := time.Now().UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		INSERT INTO contacts (id, source, email, domain, resolve_source, last_activity_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?)`,
		id, "resolve", email, domain, string(InputEmail), now, now,
	)
	if err != nil {
		return nil, fmt.Errorf("creating contact: %w", err)
	}

	missing := []string{"name", "company", "title"}
	return &ResolveResult{
		InputType: InputEmail,
		Contacts: []ResolvedContact{{
			ID:            id,
			Email:         email,
			Name:          "",
			Company:       "",
			Title:         "",
			Status:        "created",
			MissingFields: missing,
			IsNew:         true,
		}},
		Summary: fmt.Sprintf("Created contact for %s", email),
		Next:    "enrich",
	}, nil
}

// --- CSV ---

// headerAliases maps canonical field names to common CSV header variations.
var headerAliases = map[string][]string{
	"email":    {"email", "email address", "e-mail", "mail"},
	"name":     {"name", "full name", "contact name"},
	"company":  {"company", "organization", "org", "company name"},
	"title":    {"title", "job title", "role", "position"},
	"phone":    {"phone", "phone number", "telephone"},
	"linkedin": {"linkedin", "linkedin url", "linkedin_url", "profile"},
}

func resolveCSV(d *sql.DB, path string) (*ResolveResult, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("opening CSV: %w", err)
	}
	defer f.Close()

	reader := csv.NewReader(f)
	reader.TrimLeadingSpace = true
	reader.FieldsPerRecord = -1 // Allow variable field counts

	header, err := reader.Read()
	if err != nil {
		return nil, fmt.Errorf("reading CSV header: %w", err)
	}

	colMap := buildColumnMap(header)

	// We need at least an email column
	if _, ok := colMap["email"]; !ok {
		return nil, fmt.Errorf("CSV must include an email column (tried: %s)", strings.Join(headerAliases["email"], ", "))
	}

	result := &ResolveResult{
		InputType: InputCSV,
	}

	seen := map[string]bool{}
	var created, updated, existing int

	for {
		record, err := reader.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			result.Skipped = append(result.Skipped, SkippedEntry{
				Input:  fmt.Sprintf("row %d", created+updated+existing+len(result.Skipped)+1),
				Reason: fmt.Sprintf("parse error: %s", err.Error()),
			})
			continue
		}

		email := strings.ToLower(strings.TrimSpace(colVal(record, colMap, "email")))
		if !looksLikeEmail(email) {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "invalid_email"})
			continue
		}
		if seen[email] {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "duplicate"})
			continue
		}
		seen[email] = true

		domain := domainFromEmail(email)
		if suppressed, err := isSuppressed(d, email, domain); err != nil {
			return nil, err
		} else if suppressed {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "suppressed"})
			continue
		}

		name := strings.TrimSpace(colVal(record, colMap, "name"))
		// Handle first_name + last_name combination
		if name == "" {
			first := strings.TrimSpace(colVal(record, colMap, "first_name"))
			last := strings.TrimSpace(colVal(record, colMap, "last_name"))
			name = strings.TrimSpace(first + " " + last)
		}
		company := strings.TrimSpace(colVal(record, colMap, "company"))
		title := strings.TrimSpace(colVal(record, colMap, "title"))
		phone := strings.TrimSpace(colVal(record, colMap, "phone"))
		linkedin := strings.TrimSpace(colVal(record, colMap, "linkedin"))
		if domain == "" {
			domain = domainFromEmail(email)
		}

		existingContact, err := contactByEmail(d, email)
		if err != nil {
			return nil, err
		}

		if existingContact != nil {
			// Update existing contact with non-empty fields
			_, err = d.Exec(`
				UPDATE contacts
				SET name = CASE WHEN ? = '' THEN name ELSE ? END,
					domain = CASE WHEN ? = '' THEN domain ELSE ? END,
					company = CASE WHEN ? = '' THEN company ELSE ? END,
					title = CASE WHEN ? = '' THEN title ELSE ? END,
					phone = CASE WHEN ? = '' THEN phone ELSE ? END,
					linkedin_url = CASE WHEN ? = '' THEN linkedin_url ELSE ? END,
					resolve_source = CASE WHEN resolve_source = '' THEN ? ELSE resolve_source END,
					last_activity_at = ?,
					updated_at = ?
				WHERE id = ?`,
				name, name,
				domain, domain,
				company, company,
				title, title,
				phone, phone,
				linkedin, linkedin,
				string(InputCSV),
				time.Now().UTC().Format(time.RFC3339),
				time.Now().UTC().Format(time.RFC3339),
				existingContact.id,
			)
			if err != nil {
				return nil, fmt.Errorf("updating contact %s: %w", email, err)
			}
			missing := missingContactFieldsFromValues(name, email, company, title)
			result.Contacts = append(result.Contacts, ResolvedContact{
				ID:            existingContact.id,
				Email:         email,
				Name:          coalesce(name, existingContact.name),
				Company:       coalesce(company, existingContact.company),
				Title:         coalesce(title, existingContact.title),
				Status:        "updated",
				MissingFields: missing,
				IsNew:         false,
			})
			updated++
			continue
		}

		// Create new
		id := newContactID()
		now := time.Now().UTC().Format(time.RFC3339)
		_, err = d.Exec(`
			INSERT INTO contacts (id, source, email, name, domain, company, title, phone, linkedin_url, resolve_source, last_activity_at, updated_at)
			VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
			id, "resolve", email, name, domain, company, title, phone, linkedin, string(InputCSV), now, now,
		)
		if err != nil {
			return nil, fmt.Errorf("creating contact %s: %w", email, err)
		}
		missing := missingContactFieldsFromValues(name, email, company, title)
		result.Contacts = append(result.Contacts, ResolvedContact{
			ID:            id,
			Email:         email,
			Name:          name,
			Company:       company,
			Title:         title,
			Status:        "created",
			MissingFields: missing,
			IsNew:         true,
		})
		created++
	}

	parts := []string{}
	if created > 0 {
		parts = append(parts, fmt.Sprintf("%d created", created))
	}
	if updated > 0 {
		parts = append(parts, fmt.Sprintf("%d updated", updated))
	}
	if len(result.Skipped) > 0 {
		parts = append(parts, fmt.Sprintf("%d skipped", len(result.Skipped)))
	}
	result.Summary = fmt.Sprintf("CSV import: %s", strings.Join(parts, ", "))
	if created+updated == 0 {
		result.Summary = "CSV import: no contacts resolved"
	}

	// Determine next step
	hasEnrichNeeded := false
	for _, c := range result.Contacts {
		if len(c.MissingFields) > 0 {
			hasEnrichNeeded = true
			break
		}
	}
	if hasEnrichNeeded {
		result.Next = "enrich"
	} else {
		result.Next = "ready"
	}

	return result, nil
}

// --- LinkedIn Person ---

func resolveLinkedInPerson(d *sql.DB, input string) (*ResolveResult, error) {
	slug := extractLinkedInSlug(input, "in")
	if slug == "" {
		return nil, fmt.Errorf("could not extract LinkedIn profile slug from: %s", input)
	}

	linkedinURL := normalizeLinkedInURL(input, "in")

	// Check if contact with this LinkedIn URL already exists
	existingContact, err := contactByLinkedIn(d, linkedinURL)
	if err != nil {
		return nil, err
	}

	if existingContact != nil {
		missing := missingContactFields(existingContact)
		next := "ready"
		if len(missing) > 0 {
			next = "enrich"
		}
		return &ResolveResult{
			InputType: InputLinkedInPerson,
			Contacts: []ResolvedContact{{
				ID:            existingContact.id,
				Email:         existingContact.email,
				Name:          existingContact.name,
				Company:       existingContact.company,
				Title:         existingContact.title,
				Status:        "existing",
				MissingFields: missing,
				IsNew:         false,
			}},
			Summary: fmt.Sprintf("Found existing contact with LinkedIn: %s", slug),
			Next:    next,
		}, nil
	}

	// Create new contact with LinkedIn URL, most fields empty
	id := newContactID()
	name := slugToName(slug)
	now := time.Now().UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		INSERT INTO contacts (id, source, email, name, linkedin_url, resolve_source, last_activity_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
		id, "resolve", "", name, linkedinURL, string(InputLinkedInPerson), now, now,
	)
	if err != nil {
		return nil, fmt.Errorf("creating contact from LinkedIn: %w", err)
	}

	return &ResolveResult{
		InputType: InputLinkedInPerson,
		Contacts: []ResolvedContact{{
			ID:            id,
			Email:         "",
			Name:          name,
			Status:        "created",
			MissingFields: []string{"email", "company", "title"},
			IsNew:         true,
		}},
		Summary: fmt.Sprintf("Created contact from LinkedIn profile: %s (enrichment needed)", slug),
		Next:    "enrich",
	}, nil
}

// --- LinkedIn Company ---

func resolveLinkedInCompany(input string) (*ResolveResult, error) {
	slug := extractLinkedInSlug(input, "company")
	if slug == "" {
		return nil, fmt.Errorf("could not extract LinkedIn company slug from: %s", input)
	}

	name := slugToName(slug)

	return &ResolveResult{
