package resolve

import (
	"database/sql"
	"os"
	"path/filepath"
	"testing"

	"github.com/usenurge/nurgesh/internal/db"

	_ "modernc.org/sqlite"
)

func setupTestDB(t *testing.T) *sql.DB {
	t.Helper()

	dir := t.TempDir()
	dbPath := filepath.Join(dir, "test.db")

	d, err := sql.Open("sqlite", "file:"+dbPath+"?_pragma=busy_timeout(5000)&_pragma=journal_mode(WAL)&_pragma=foreign_keys(1)")
	if err != nil {
		t.Fatalf("opening test db: %v", err)
	}
	d.SetMaxOpenConns(1)

	if _, err := d.Exec(db.Schema); err != nil {
		t.Fatalf("creating schema: %v", err)
	}
	if err := db.EnsureMigrations(d); err != nil {
		t.Fatalf("running migrations: %v", err)
	}

	t.Cleanup(func() { d.Close() })
	return d
}

func TestDetectInputType(t *testing.T) {
	tests := []struct {
		input string
		want  InputType
	}{
		{"contacts.csv", InputCSV},
		{"/path/to/file.CSV", InputCSV},
		{"john@acme.com", InputEmail},
		{"JOHN@ACME.COM", InputEmail},
		{"https://linkedin.com/in/john-doe", InputLinkedInPerson},
		{"linkedin.com/in/john-doe", InputLinkedInPerson},
		{"https://linkedin.com/company/acme", InputLinkedInCompany},
		{"linkedin.com/company/acme-inc", InputLinkedInCompany},
		{"acme.com", InputWebsite},
		{"https://acme.com", InputWebsite},
		{"http://www.acme.com/about", InputWebsite},
		{"John Doe", InputNameCompany},
		{"Jane Smith", InputNameCompany},
	}

	for _, tt := range tests {
		t.Run(tt.input, func(t *testing.T) {
			got := DetectInputType(tt.input)
			if got != tt.want {
				t.Errorf("DetectInputType(%q) = %s, want %s", tt.input, got, tt.want)
			}
		})
	}
}

func TestResolveEmail_New(t *testing.T) {
	d := setupTestDB(t)

	result, err := Resolve(d, "test@example.com", "")
	if err != nil {
		t.Fatalf("Resolve: %v", err)
	}

	if result.InputType != InputEmail {
		t.Errorf("input type = %s, want email", result.InputType)
	}
	if len(result.Contacts) != 1 {
		t.Fatalf("contacts = %d, want 1", len(result.Contacts))
	}
	c := result.Contacts[0]
	if c.Status != "created" {
		t.Errorf("status = %s, want created", c.Status)
	}
	if !c.IsNew {
		t.Error("expected IsNew = true")
	}
	if c.Email != "test@example.com" {
		t.Errorf("email = %s, want test@example.com", c.Email)
	}
	if result.Next != "enrich" {
		t.Errorf("next = %s, want enrich", result.Next)
	}
}

func TestResolveEmail_Existing(t *testing.T) {
	d := setupTestDB(t)

	// Pre-insert a contact
	_, err := d.Exec(`INSERT INTO contacts (id, source, email, name, company, title, domain) VALUES (?, ?, ?, ?, ?, ?, ?)`,
		"contact_test1", "manual", "existing@acme.com", "Jane Doe", "Acme Inc", "CTO", "acme.com")
	if err != nil {
		t.Fatalf("inserting seed contact: %v", err)
	}

	result, err := Resolve(d, "existing@acme.com", "")
	if err != nil {
		t.Fatalf("Resolve: %v", err)
	}

	if len(result.Contacts) != 1 {
		t.Fatalf("contacts = %d, want 1", len(result.Contacts))
	}
	c := result.Contacts[0]
	if c.Status != "existing" {
		t.Errorf("status = %s, want existing", c.Status)
	}
	if c.IsNew {
		t.Error("expected IsNew = false")
	}
	if c.Name != "Jane Doe" {
		t.Errorf("name = %s, want Jane Doe", c.Name)
	}
	if result.Next != "ready" {
		t.Errorf("next = %s, want ready", result.Next)
	}
}

func TestResolveEmail_Suppressed(t *testing.T) {
	d := setupTestDB(t)

	_, err := d.Exec(`INSERT INTO suppressions (id, scope, value, reason) VALUES (?, ?, ?, ?)`,
		"sup_1", "email", "blocked@spam.com", "bounced")
	if err != nil {
		t.Fatalf("inserting suppression: %v", err)
	}

	result, err := Resolve(d, "blocked@spam.com", "")
	if err != nil {
		t.Fatalf("Resolve: %v", err)
	}

	if len(result.Contacts) != 0 {
		t.Errorf("contacts = %d, want 0", len(result.Contacts))
	}
	if len(result.Skipped) != 1 {
		t.Fatalf("skipped = %d, want 1", len(result.Skipped))
	}
	if result.Skipped[0].Reason != "suppressed" {
		t.Errorf("skip reason = %s, want suppressed", result.Skipped[0].Reason)
	}
}

func TestResolveEmail_DomainSuppressed(t *testing.T) {
	d := setupTestDB(t)

	_, err := d.Exec(`INSERT INTO suppressions (id, scope, value, reason) VALUES (?, ?, ?, ?)`,
		"sup_d1", "domain", "blocked.com", "domain blocked")
	if err != nil {
		t.Fatalf("inserting suppression: %v", err)
	}

	result, err := Resolve(d, "anyone@blocked.com", "")
	if err != nil {
		t.Fatalf("Resolve: %v", err)
	}

	if len(result.Skipped) != 1 {
		t.Fatalf("skipped = %d, want 1", len(result.Skipped))
	}
	if result.Skipped[0].Reason != "suppressed" {
		t.Errorf("skip reason = %s, want suppressed", result.Skipped[0].Reason)
	}
}

func TestResolveCSV(t *testing.T) {
	d := setupTestDB(t)

	// Write a test CSV
	dir := t.TempDir()
	csvPath := filepath.Join(dir, "test.csv")
	csvContent := `Email Address,Full Name,Company,Job Title,Phone Number
alice@acme.com,Alice Smith,Acme Inc,CEO,555-0001
bob@beta.com,Bob Jones,Beta Corp,CTO,555-0002
invalid-email,Bad Row,,
alice@acme.com,Alice Dupe,Acme Inc,CEO,555-0001
`
	if err := os.WriteFile(csvPath, []byte(csvContent), 0644); err != nil {
		t.Fatalf("writing CSV: %v", err)
	}

	result, err := Resolve(d, csvPath, "")
	if err != nil {
		t.Fatalf("Resolve CSV: %v", err)
	}

	if result.InputType != InputCSV {
		t.Errorf("input type = %s, want csv", result.InputType)
	}

	// Should have 2 created contacts
	created := 0
	for _, c := range result.Contacts {
		if c.Status == "created" {
			created++
		}
	}
	if created != 2 {
		t.Errorf("created = %d, want 2", created)
	}

	// Should have skipped: 1 invalid + 1 duplicate
	skipReasons := map[string]int{}
	for _, s := range result.Skipped {
		skipReasons[s.Reason]++
	}
	if skipReasons["invalid_email"] != 1 {
		t.Errorf("invalid_email skips = %d, want 1", skipReasons["invalid_email"])
	}
	if skipReasons["duplicate"] != 1 {
		t.Errorf("duplicate skips = %d, want 1", skipReasons["duplicate"])
	}
}

func TestResolveCSV_FirstLastName(t *testing.T) {
	d := setupTestDB(t)

	dir := t.TempDir()
	csvPath := filepath.Join(dir, "names.csv")
	csvContent := `email,first_name,last_name,company
carol@gamma.com,Carol,Williams,Gamma Corp
`
	if err := os.WriteFile(csvPath, []byte(csvContent), 0644); err != nil {
		t.Fatalf("writing CSV: %v", err)
	}

	result, err := Resolve(d, csvPath, "")
	if err != nil {
		t.Fatalf("Resolve CSV: %v", err)
	}

	if len(result.Contacts) != 1 {
		t.Fatalf("contacts = %d, want 1", len(result.Contacts))
	}
	if result.Contacts[0].Name != "Carol Williams" {
		t.Errorf("name = %q, want %q", result.Contacts[0].Name, "Carol Williams")
	}
}

func TestResolveCSV_SuppressedRow(t *testing.T) {
	d := setupTestDB(t)

	_, err := d.Exec(`INSERT INTO suppressions (id, scope, value, reason) VALUES (?, ?, ?, ?)`,
		"sup_csv1", "email", "blocked@test.com", "bounced")
	if err != nil {
		t.Fatalf("inserting suppression: %v", err)
	}

	dir := t.TempDir()
	csvPath := filepath.Join(dir, "supp.csv")
	csvContent := `email,name
blocked@test.com,Blocked Person
ok@test.com,OK Person
`
	if err := os.WriteFile(csvPath, []byte(csvContent), 0644); err != nil {
		t.Fatalf("writing CSV: %v", err)
	}

	result, err := Resolve(d, csvPath, "")
	if err != nil {
		t.Fatalf("Resolve CSV: %v", err)
	}

	if len(result.Contacts) != 1 {
		t.Errorf("contacts = %d, want 1", len(result.Contacts))
	}
	suppressed := 0
	for _, s := range result.Skipped {
		if s.Reason == "suppressed" {
			suppressed++
		}
	}
	if suppressed != 1 {
		t.Errorf("suppressed skips = %d, want 1", suppressed)
	}
}

func TestResolveLinkedInPerson(t *testing.T) {
	d := setupTestDB(t)

	result, err := Resolve(d, "https://linkedin.com/in/john-doe", "")
