	}
}

func TestResolveLinkedInPerson_Existing(t *testing.T) {
	d := setupTestDB(t)

	// Pre-insert a contact with this LinkedIn URL
	_, err := d.Exec(`INSERT INTO contacts (id, source, email, name, linkedin_url) VALUES (?, ?, ?, ?, ?)`,
		"contact_li1", "resolve", "john@acme.com", "John Doe", "https://www.linkedin.com/in/john-doe")
