package resolve

import (
	"database/sql"
	"encoding/csv"
	"fmt"
	"io"
	"net/mail"
	"os"
	"strings"
	"time"

	"github.com/google/uuid"
)

// InputType classifies what the user provided as input.
type InputType string

const (
	InputEmail           InputType = "email"
	InputCSV             InputType = "csv"
	InputLinkedInPerson  InputType = "linkedin_person"
	InputLinkedInCompany InputType = "linkedin_company"
	InputWebsite         InputType = "website"
	InputNameCompany     InputType = "name_company"
)

// ResolveResult is the output of the resolve pipeline.
type ResolveResult struct {
	InputType InputType          `json:"input_type"`
	Contacts  []ResolvedContact  `json:"contacts"`
	Company   *ResolvedCompany   `json:"company,omitempty"`
	Skipped   []SkippedEntry     `json:"skipped,omitempty"`
	Summary   string             `json:"summary"`
	Next      string             `json:"next"` // enrich, find_people, ready
}

// ResolvedContact represents a contact created or matched during resolve.
type ResolvedContact struct {
	ID            string   `json:"id"`
	Email         string   `json:"email"`
	Name          string   `json:"name"`
	Company       string   `json:"company,omitempty"`
	Title         string   `json:"title,omitempty"`
	Status        string   `json:"status"` // created, updated, existing
	MissingFields []string `json:"missing_fields,omitempty"`
	IsNew         bool     `json:"is_new"`
}

// ResolvedCompany represents a company extracted from a URL or domain.
type ResolvedCompany struct {
	Domain   string `json:"domain"`
	Name     string `json:"name"`
	Industry string `json:"industry,omitempty"`
	Size     string `json:"size,omitempty"`
}

// SkippedEntry records an input that was not resolved.
type SkippedEntry struct {
	Input  string `json:"input"`
	Reason string `json:"reason"` // invalid_email, duplicate, suppressed
}

// DetectInputType determines what kind of input the user provided.
func DetectInputType(input string) InputType {
	trimmed := strings.TrimSpace(input)
	lower := strings.ToLower(trimmed)

	if strings.HasSuffix(lower, ".csv") {
		return InputCSV
	}
	if strings.Contains(lower, "linkedin.com/in/") {
		return InputLinkedInPerson
	}
	if strings.Contains(lower, "linkedin.com/company/") {
		return InputLinkedInCompany
	}
	if strings.Contains(trimmed, "@") && looksLikeEmail(trimmed) {
		return InputEmail
	}
	if looksLikeURL(trimmed) {
		return InputWebsite
	}
	return InputNameCompany
}

// Resolve is the main entry point. It detects input type and routes accordingly.
// The company parameter is only used for InputNameCompany.
func Resolve(d *sql.DB, input string, company string) (*ResolveResult, error) {
	if d == nil {
		return nil, fmt.Errorf("database is required")
	}
	input = strings.TrimSpace(input)
	if input == "" {
		return nil, fmt.Errorf("input is required")
	}

	inputType := DetectInputType(input)

	switch inputType {
	case InputEmail:
		return resolveEmail(d, input)
	case InputCSV:
		return resolveCSV(d, input)
	case InputLinkedInPerson:
		return resolveLinkedInPerson(d, input)
	case InputLinkedInCompany:
		return resolveLinkedInCompany(input)
	case InputWebsite:
		return resolveWebsite(input)
	case InputNameCompany:
		return resolveNameCompany(d, input, company)
	default:
		return nil, fmt.Errorf("unsupported input type: %s", inputType)
	}
}

// --- Email ---

func resolveEmail(d *sql.DB, input string) (*ResolveResult, error) {
	email := strings.ToLower(strings.TrimSpace(input))
	if !looksLikeEmail(email) {
		return nil, fmt.Errorf("invalid email address: %s", input)
	}

	domain := domainFromEmail(email)

	// Check suppression
	if suppressed, err := isSuppressed(d, email, domain); err != nil {
		return nil, err
	} else if suppressed {
		return &ResolveResult{
			InputType: InputEmail,
			Skipped:   []SkippedEntry{{Input: email, Reason: "suppressed"}},
			Summary:   fmt.Sprintf("%s is suppressed", email),
			Next:      "ready",
		}, nil
	}

	// Check existing contact
	existing, err := contactByEmail(d, email)
	if err != nil {
		return nil, err
	}

	if existing != nil {
		missing := missingContactFields(existing)
		next := "ready"
		if len(missing) > 0 {
			next = "enrich"
		}
		return &ResolveResult{
			InputType: InputEmail,
			Contacts: []ResolvedContact{{
				ID:            existing.id,
				Email:         existing.email,
				Name:          existing.name,
				Company:       existing.company,
				Title:         existing.title,
				Status:        "existing",
				MissingFields: missing,
				IsNew:         false,
			}},
			Summary: fmt.Sprintf("Found existing contact %s", email),
			Next:    next,
		}, nil
	}

	// Create new contact
	id := newContactID()
	now := time.Now().UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		INSERT INTO contacts (id, source, email, domain, resolve_source, last_activity_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?)`,
		id, "resolve", email, domain, string(InputEmail), now, now,
	)
	if err != nil {
		return nil, fmt.Errorf("creating contact: %w", err)
	}

	missing := []string{"name", "company", "title"}
	return &ResolveResult{
		InputType: InputEmail,
		Contacts: []ResolvedContact{{
			ID:            id,
			Email:         email,
			Name:          "",
			Company:       "",
			Title:         "",
			Status:        "created",
			MissingFields: missing,
			IsNew:         true,
		}},
		Summary: fmt.Sprintf("Created contact for %s", email),
		Next:    "enrich",
	}, nil
}

// --- CSV ---

// headerAliases maps canonical field names to common CSV header variations.
var headerAliases = map[string][]string{
	"email":    {"email", "email address", "e-mail", "mail"},
	"name":     {"name", "full name", "contact name"},
	"company":  {"company", "organization", "org", "company name"},
	"title":    {"title", "job title", "role", "position"},
	"phone":    {"phone", "phone number", "telephone"},
	"linkedin": {"linkedin", "linkedin url", "linkedin_url", "profile"},
}

func resolveCSV(d *sql.DB, path string) (*ResolveResult, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("opening CSV: %w", err)
	}
	defer f.Close()

	reader := csv.NewReader(f)
	reader.TrimLeadingSpace = true
	reader.FieldsPerRecord = -1 // Allow variable field counts

	header, err := reader.Read()
	if err != nil {
		return nil, fmt.Errorf("reading CSV header: %w", err)
	}

	colMap := buildColumnMap(header)

	// We need at least an email column
	if _, ok := colMap["email"]; !ok {
		return nil, fmt.Errorf("CSV must include an email column (tried: %s)", strings.Join(headerAliases["email"], ", "))
	}

	result := &ResolveResult{
		InputType: InputCSV,
	}

	seen := map[string]bool{}
	var created, updated, existing int

	for {
		record, err := reader.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			result.Skipped = append(result.Skipped, SkippedEntry{
				Input:  fmt.Sprintf("row %d", created+updated+existing+len(result.Skipped)+1),
				Reason: fmt.Sprintf("parse error: %s", err.Error()),
			})
			continue
		}

		email := strings.ToLower(strings.TrimSpace(colVal(record, colMap, "email")))
		if !looksLikeEmail(email) {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "invalid_email"})
			continue
		}
		if seen[email] {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "duplicate"})
			continue
		}
		seen[email] = true

		domain := domainFromEmail(email)
		if suppressed, err := isSuppressed(d, email, domain); err != nil {
			return nil, err
		} else if suppressed {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "suppressed"})
			continue
		}

		name := strings.TrimSpace(colVal(record, colMap, "name"))
		// Handle first_name + last_name combination
		if name == "" {
			first := strings.TrimSpace(colVal(record, colMap, "first_name"))
			last := strings.TrimSpace(colVal(record, colMap, "last_name"))
			name = strings.TrimSpace(first + " " + last)
		}
		company := strings.TrimSpace(colVal(record, colMap, "company"))
		title := strings.TrimSpace(colVal(record, colMap, "title"))
		phone := strings.TrimSpace(colVal(record, colMap, "phone"))
		linkedin := strings.TrimSpace(colVal(record, colMap, "linkedin"))
		if domain == "" {
			domain = domainFromEmail(email)
		}

		existingContact, err := contactByEmail(d, email)
		if err != nil {
			return nil, err
		}

		if existingContact != nil {
			// Update existing contact with non-empty fields
			_, err = d.Exec(`
				UPDATE contacts
				SET name = CASE WHEN ? = '' THEN name ELSE ? END,
					domain = CASE WHEN ? = '' THEN domain ELSE ? END,
					company = CASE WHEN ? = '' THEN company ELSE ? END,
					title = CASE WHEN ? = '' THEN title ELSE ? END,
					phone = CASE WHEN ? = '' THEN phone ELSE ? END,
					linkedin_url = CASE WHEN ? = '' THEN linkedin_url ELSE ? END,
					resolve_source = CASE WHEN resolve_source = '' THEN ? ELSE resolve_source END,
					last_activity_at = ?,
					updated_at = ?
				WHERE id = ?`,
				name, name,
				domain, domain,
				company, company,
				title, title,
				phone, phone,
				linkedin, linkedin,
				string(InputCSV),
				time.Now().UTC().Format(time.RFC3339),
				time.Now().UTC().Format(time.RFC3339),
				existingContact.id,
			)
			if err != nil {
				return nil, fmt.Errorf("updating contact %s: %w", email, err)
			}
			missing := missingContactFieldsFromValues(name, email, company, title)
			result.Contacts = append(result.Contacts, ResolvedContact{
				ID:            existingContact.id,
				Email:         email,
				Name:          coalesce(name, existingContact.name),
				Company:       coalesce(company, existingContact.company),
				Title:         coalesce(title, existingContact.title),
				Status:        "updated",
				MissingFields: missing,
				IsNew:         false,
			})
			updated++
			continue
		}

		// Create new
		id := newContactID()
		now := time.Now().UTC().Format(time.RFC3339)
		_, err = d.Exec(`
			INSERT INTO contacts (id, source, email, name, domain, company, title, phone, linkedin_url, resolve_source, last_activity_at, updated_at)
			VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
			id, "resolve", email, name, domain, company, title, phone, linkedin, string(InputCSV), now, now,
		)
		if err != nil {
			return nil, fmt.Errorf("creating contact %s: %w", email, err)
		}
		missing := missingContactFieldsFromValues(name, email, company, title)
		result.Contacts = append(result.Contacts, ResolvedContact{
			ID:            id,
			Email:         email,
			Name:          name,
			Company:       company,
			Title:         title,
			Status:        "created",
			MissingFields: missing,
			IsNew:         true,
		})
		created++
	}

	parts := []string{}
	if created > 0 {
		parts = append(parts, fmt.Sprintf("%d created", created))
	}
	if updated > 0 {
		parts = append(parts, fmt.Sprintf("%d updated", updated))
	}
	if len(result.Skipped) > 0 {
		parts = append(parts, fmt.Sprintf("%d skipped", len(result.Skipped)))
	}
	result.Summary = fmt.Sprintf("CSV import: %s", strings.Join(parts, ", "))
	if created+updated == 0 {
		result.Summary = "CSV import: no contacts resolved"
	}

	// Determine next step
	hasEnrichNeeded := false
	for _, c := range result.Contacts {
		if len(c.MissingFields) > 0 {
			hasEnrichNeeded = true
			break
		}
	}
	if hasEnrichNeeded {
		result.Next = "enrich"
	} else {
		result.Next = "ready"
	}

	return result, nil
}

// --- LinkedIn Person ---

func resolveLinkedInPerson(d *sql.DB, input string) (*ResolveResult, error) {
	slug := extractLinkedInSlug(input, "in")
	if slug == "" {
		return nil, fmt.Errorf("could not extract LinkedIn profile slug from: %s", input)
	}

	linkedinURL := normalizeLinkedInURL(input, "in")

	// Check if contact with this LinkedIn URL already exists
	existingContact, err := contactByLinkedIn(d, linkedinURL)
	if err != nil {
		return nil, err
	}

	if existingContact != nil {
		missing := missingContactFields(existingContact)
		next := "ready"
		if len(missing) > 0 {
			next = "enrich"
		}
		return &ResolveResult{
			InputType: InputLinkedInPerson,
			Contacts: []ResolvedContact{{
				ID:            existingContact.id,
				Email:         existingContact.email,
				Name:          existingContact.name,
				Company:       existingContact.company,
				Title:         existingContact.title,
				Status:        "existing",
				MissingFields: missing,
				IsNew:         false,
			}},
			Summary: fmt.Sprintf("Found existing contact with LinkedIn: %s", slug),
			Next:    next,
		}, nil
	}

	// Create new contact with LinkedIn URL, most fields empty
	id := newContactID()
	name := slugToName(slug)
	now := time.Now().UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		INSERT INTO contacts (id, source, email, name, linkedin_url, resolve_source, last_activity_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
		id, "resolve", "", name, linkedinURL, string(InputLinkedInPerson), now, now,
	)
	if err != nil {
		return nil, fmt.Errorf("creating contact from LinkedIn: %w", err)
	}

	return &ResolveResult{
		InputType: InputLinkedInPerson,
		Contacts: []ResolvedContact{{
			ID:            id,
			Email:         "",
			Name:          name,
			Status:        "created",
			MissingFields: []string{"email", "company", "title"},
			IsNew:         true,
		}},
		Summary: fmt.Sprintf("Created contact from LinkedIn profile: %s (enrichment needed)", slug),
		Next:    "enrich",
	}, nil
}

// --- LinkedIn Company ---

func resolveLinkedInCompany(input string) (*ResolveResult, error) {
	slug := extractLinkedInSlug(input, "company")
	if slug == "" {
		return nil, fmt.Errorf("could not extract LinkedIn company slug from: %s", input)
	}

	name := slugToName(slug)

	return &ResolveResult{
		InputType: InputLinkedInCompany,
		Company: &ResolvedCompany{
			Domain: "",
			Name:   name,
		},
		Summary: fmt.Sprintf("Identified company: %s (need to find people)", name),
		Next:    "find_people",
	}, nil
}

// --- Website ---

func resolveWebsite(input string) (*ResolveResult, error) {
	domain := extractDomain(input)
	if domain == "" {
		return nil, fmt.Errorf("could not extract domain from: %s", input)
	}

	// Use the domain as a rough company name (capitalize first letter of each part)
	name := domainToCompanyName(domain)

	return &ResolveResult{
		InputType: InputWebsite,
		Company: &ResolvedCompany{
			Domain: domain,
			Name:   name,
		},
		Summary: fmt.Sprintf("Identified company at %s (need to find people)", domain),
		Next:    "find_people",
	}, nil
}

// --- Name + Company ---

func resolveNameCompany(d *sql.DB, name string, company string) (*ResolveResult, error) {
	name = strings.TrimSpace(name)
	company = strings.TrimSpace(company)

	if name == "" {
		return nil, fmt.Errorf("name is required for name+company resolve")
	}

	// Check if contact with this name+company already exists
	existingContact, err := contactByNameCompany(d, name, company)
	if err != nil {
		return nil, err
	}

	if existingContact != nil {
		missing := missingContactFields(existingContact)
		next := "ready"
		if len(missing) > 0 {
			next = "enrich"
		}
		return &ResolveResult{
			InputType: InputNameCompany,
			Contacts: []ResolvedContact{{
				ID:            existingContact.id,
				Email:         existingContact.email,
				Name:          existingContact.name,
				Company:       existingContact.company,
				Title:         existingContact.title,
				Status:        "existing",
				MissingFields: missing,
				IsNew:         false,
			}},
			Summary: fmt.Sprintf("Found existing contact: %s at %s", name, company),
			Next:    next,
		}, nil
	}

	// Create new contact with name + company, email is missing
	id := newContactID()
	now := time.Now().UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		INSERT INTO contacts (id, source, email, name, company, resolve_source, last_activity_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
		id, "resolve", "", name, company, string(InputNameCompany), now, now,
	)
	if err != nil {
		return nil, fmt.Errorf("creating contact: %w", err)
	}

	missing := []string{"email", "title"}
	if company == "" {
		missing = append(missing, "company")
	}

	return &ResolveResult{
		InputType: InputNameCompany,
		Contacts: []ResolvedContact{{
			ID:            id,
			Email:         "",
			Name:          name,
			Company:       company,
			Status:        "created",
			MissingFields: missing,
			IsNew:         true,
		}},
		Summary: fmt.Sprintf("Created contact %s (email and enrichment needed)", name),
		Next:    "enrich",
	}, nil
}

// --- Helpers ---

func newContactID() string {
	return "contact_" + uuid.NewString()
}

func looksLikeEmail(s string) bool {
	_, err := mail.ParseAddress(s)
	return err == nil
}

func looksLikeURL(s string) bool {
	s = strings.ToLower(strings.TrimSpace(s))
	if strings.HasPrefix(s, "http://") || strings.HasPrefix(s, "https://") {
		return true
	}
	// Check for domain-like patterns: has a dot, no spaces, no @
	if strings.Contains(s, ".") && !strings.Contains(s, " ") && !strings.Contains(s, "@") {
		return true
	}
	return false
}

func domainFromEmail(email string) string {
	parts := strings.SplitN(strings.ToLower(strings.TrimSpace(email)), "@", 2)
	if len(parts) != 2 {
		return ""
	}
	return parts[1]
}

func extractDomain(input string) string {
	s := strings.TrimSpace(input)
	s = strings.TrimPrefix(s, "https://")
	s = strings.TrimPrefix(s, "http://")
	s = strings.TrimPrefix(s, "www.")
	// Take everything before the first /
	if idx := strings.Index(s, "/"); idx >= 0 {
		s = s[:idx]
	}
	if !strings.Contains(s, ".") {
		return ""
	}
	return strings.ToLower(s)
}

func extractLinkedInSlug(input string, kind string) string {
	lower := strings.ToLower(input)
	prefix := "linkedin.com/" + kind + "/"
	idx := strings.Index(lower, prefix)
	if idx < 0 {
		return ""
	}
	rest := input[idx+len(prefix):]
	// Remove trailing slash and query params
	if slashIdx := strings.IndexAny(rest, "/?#"); slashIdx >= 0 {
		rest = rest[:slashIdx]
	}
	return strings.TrimSpace(rest)
}

func normalizeLinkedInURL(input string, kind string) string {
	slug := extractLinkedInSlug(input, kind)
	if slug == "" {
		return ""
	}
	return "https://www.linkedin.com/" + kind + "/" + slug
}

func slugToName(slug string) string {
	// Convert "john-doe-123abc" to "John Doe"
	// Remove trailing numeric/hash segments
	parts := strings.Split(slug, "-")
	var nameParts []string
	for _, p := range parts {
		// Skip if it looks like a LinkedIn hash suffix (all hex/digits)
		if isHexOrDigits(p) && len(p) >= 5 {
			continue
		}
		if p != "" {
			nameParts = append(nameParts, capitalize(p))
		}
	}
	return strings.Join(nameParts, " ")
}

func isHexOrDigits(s string) bool {
	for _, r := range s {
		if !((r >= '0' && r <= '9') || (r >= 'a' && r <= 'f') || (r >= 'A' && r <= 'F')) {
			return false
		}
	}
	return len(s) > 0
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

func domainToCompanyName(domain string) string {
	// "acme.com" -> "Acme", "data-stack.io" -> "Data Stack"
	parts := strings.Split(domain, ".")
	if len(parts) < 2 {
		return capitalize(domain)
	}
	// Use everything except the TLD
	name := strings.Join(parts[:len(parts)-1], ".")
	name = strings.ReplaceAll(name, "-", " ")
	name = strings.ReplaceAll(name, "_", " ")
	words := strings.Fields(name)
	for i, w := range words {
		words[i] = capitalize(w)
	}
	return strings.Join(words, " ")
}

// contactRow is an internal helper to hold DB contact data.
type contactRow struct {
	id      string
	email   string
	name    string
	company string
	title   string
	phone   string
}

func contactByEmail(d *sql.DB, email string) (*contactRow, error) {
	var c contactRow
	err := d.QueryRow(`
		SELECT id, email, COALESCE(name,''), COALESCE(company,''), COALESCE(title,''), COALESCE(phone,'')
		FROM contacts
		WHERE lower(email) = lower(?)
		ORDER BY updated_at DESC
		LIMIT 1`, email).Scan(&c.id, &c.email, &c.name, &c.company, &c.title, &c.phone)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("looking up contact by email: %w", err)
	}
	return &c, nil
}

func contactByLinkedIn(d *sql.DB, linkedinURL string) (*contactRow, error) {
	var c contactRow
	err := d.QueryRow(`
		SELECT id, COALESCE(email,''), COALESCE(name,''), COALESCE(company,''), COALESCE(title,''), COALESCE(phone,'')
		FROM contacts
		WHERE lower(linkedin_url) = lower(?)
		ORDER BY updated_at DESC
		LIMIT 1`, linkedinURL).Scan(&c.id, &c.email, &c.name, &c.company, &c.title, &c.phone)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("looking up contact by LinkedIn: %w", err)
	}
	return &c, nil
}

func contactByNameCompany(d *sql.DB, name, company string) (*contactRow, error) {
	var c contactRow
	err := d.QueryRow(`
		SELECT id, COALESCE(email,''), COALESCE(name,''), COALESCE(company,''), COALESCE(title,''), COALESCE(phone,'')
		FROM contacts
		WHERE lower(name) = lower(?) AND lower(company) = lower(?)
		ORDER BY updated_at DESC
		LIMIT 1`, name, company).Scan(&c.id, &c.email, &c.name, &c.company, &c.title, &c.phone)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("looking up contact by name+company: %w", err)
	}
	return &c, nil
}

func missingContactFields(c *contactRow) []string {
	return missingContactFieldsFromValues(c.name, c.email, c.company, c.title)
}

func missingContactFieldsFromValues(name, email, company, title string) []string {
	var missing []string
	if email == "" {
		missing = append(missing, "email")
	}
	if name == "" {
		missing = append(missing, "name")
	}
	if company == "" {
		missing = append(missing, "company")
	}
	if title == "" {
		missing = append(missing, "title")
	}
	return missing
}

func isSuppressed(d *sql.DB, email, domain string) (bool, error) {
	var dummy int
	err := d.QueryRow(`
		SELECT 1 FROM suppressions
		WHERE (scope='email' AND value=?) OR (scope='domain' AND value=?)
		LIMIT 1`, strings.ToLower(email), strings.ToLower(domain)).Scan(&dummy)
	if err == sql.ErrNoRows {
		return false, nil
	}
	if err != nil {
		return false, fmt.Errorf("checking suppression: %w", err)
	}
	return true, nil
}

func coalesce(a, b string) string {
	if a != "" {
		return a
	}
	return b
}

// buildColumnMap maps canonical field names to column indices by checking header aliases.
func buildColumnMap(header []string) map[string]int {
	colMap := map[string]int{}

	// Normalize headers
	normalized := make([]string, len(header))
	for i, h := range header {
		normalized[i] = strings.ToLower(strings.TrimSpace(h))
	}

	// Check standard aliases
	for field, aliases := range headerAliases {
		for _, alias := range aliases {
			for i, h := range normalized {
				if h == alias {
					colMap[field] = i
					break
				}
			}
			if _, ok := colMap[field]; ok {
				break
			}
		}
	}

	// Handle special case: first_name + last_name
	for i, h := range normalized {
		switch h {
		case "first name", "first_name", "firstname":
			colMap["first_name"] = i
		case "last name", "last_name", "lastname":
			colMap["last_name"] = i
		}
	}

	return colMap
}

func colVal(record []string, colMap map[string]int, field string) string {
	idx, ok := colMap[field]
	if !ok || idx < 0 || idx >= len(record) {
		return ""
	}
	return record[idx]
}

