			for _, k := range keys {
				dedupMap[k] = existingContact.id
			}
			updated++
		} else {
			// Create new contact
			id := newContactID()
			dbEmail := email
			if dbEmail == "" {
				dbEmail = placeholderEmail(id)
			}

			_, err = d.Exec(`
