func resolveCSV(d *sql.DB, path string) (*ResolveResult, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("opening CSV: %w", err)
	}
	defer f.Close()

	reader := csv.NewReader(f)
	reader.TrimLeadingSpace = true
	reader.FieldsPerRecord = -1

	header, err := reader.Read()
	if err != nil {
		return nil, fmt.Errorf("reading CSV header: %w", err)
	}

	colMap := buildColumnMap(header)

	// Need at least one identifying column (email no longer required)
	hasIdentifier := false
	for _, field := range []string{"email", "linkedin", "name"} {
		if _, ok := colMap[field]; ok {
			hasIdentifier = true
			break
		}
	}
	if !hasIdentifier {
		return nil, fmt.Errorf("CSV must include at least one identifying column: email, linkedin, or name")
	}

	result := &ResolveResult{
		InputType: InputCSV,
	}

	// Dedup map: key -> contact ID in DB
	dedupMap := map[string]string{}
	// Track index in result.Contacts per contact ID for within-CSV merges
	contactIdx := map[string]int{}
	var created, updated, merged int

	rowNum := 0
	for {
		record, err := reader.Read()
		if err == io.EOF {
			break
		}
		rowNum++
		if err != nil {
			result.Skipped = append(result.Skipped, SkippedEntry{
				Input:  fmt.Sprintf("row %d", rowNum),
				Reason: fmt.Sprintf("parse error: %s", err.Error()),
			})
			continue
		}

		// Extract all fields
		email := strings.ToLower(strings.TrimSpace(colVal(record, colMap, "email")))
		if email != "" && !looksLikeEmail(email) {
			result.Skipped = append(result.Skipped, SkippedEntry{Input: email, Reason: "invalid_email"})
			continue
		}

		name := strings.TrimSpace(colVal(record, colMap, "name"))
		if name == "" {
			first := strings.TrimSpace(colVal(record, colMap, "first_name"))
			last := strings.TrimSpace(colVal(record, colMap, "last_name"))
			name = strings.TrimSpace(first + " " + last)
		}
		company := strings.TrimSpace(colVal(record, colMap, "company"))
		title := strings.TrimSpace(colVal(record, colMap, "title"))
		phone := strings.TrimSpace(colVal(record, colMap, "phone"))
		linkedin := strings.TrimSpace(colVal(record, colMap, "linkedin"))
		industry := strings.TrimSpace(colVal(record, colMap, "industry"))
		companySize := strings.TrimSpace(colVal(record, colMap, "company_size"))
		fundingStage := strings.TrimSpace(colVal(record, colMap, "funding_stage"))
		website := strings.TrimSpace(colVal(record, colMap, "website"))
		techStack := toJSONArray(strings.TrimSpace(colVal(record, colMap, "tech_stack")))
		signals := toJSONArray(strings.TrimSpace(colVal(record, colMap, "signals")))

		// Derive domain from email or website
		domain := ""
		if email != "" {
			domain = domainFromEmail(email)
		}
		if domain == "" && website != "" {
			domain = extractDomain(website)
		}

		// Skip if no identifying info at all
		if email == "" && linkedin == "" && name == "" {
			result.Skipped = append(result.Skipped, SkippedEntry{
				Input:  fmt.Sprintf("row %d", rowNum),
				Reason: "no_identifier",
			})
			continue
		}

		// Check suppression
		if email != "" || domain != "" {
			if suppressed, sErr := isSuppressed(d, email, domain); sErr != nil {
				return nil, sErr
			} else if suppressed {
				label := email
				if label == "" {
					label = domain
				}
				result.Skipped = append(result.Skipped, SkippedEntry{Input: label, Reason: "suppressed"})
				continue
			}
		}

		// Build dedup keys for this row
		keys := buildDedupKeys(email, linkedin, name, company, domain)

		// Check within-CSV dedup
		var matchID string
		for _, k := range keys {
			if id, ok := dedupMap[k]; ok {
				matchID = id
				break
			}
		}

		if matchID != "" {
			// Merge into already-processed contact
			now := time.Now().UTC().Format(time.RFC3339)
			_, err = d.Exec(mergeUpdateSQL,
				email, email,
				name, name,
				domain, domain,
				company, company,
				title, title,
				phone, phone,
				linkedin, linkedin,
				industry, industry,
				companySize, companySize,
				fundingStage, fundingStage,
				website, website,
				techStack, techStack,
				signals, signals,
				now,
				matchID,
			)
			if err != nil {
				return nil, fmt.Errorf("merging duplicate row %d: %w", rowNum, err)
			}
			// Update the result entry
			if idx, ok := contactIdx[matchID]; ok {
				rc := &result.Contacts[idx]
				if email != "" && !hasRealEmail(rc.Email) {
					rc.Email = email
				}
				if name != "" && rc.Name == "" {
					rc.Name = name
				}
				if company != "" && rc.Company == "" {
					rc.Company = company
				}
				if title != "" && rc.Title == "" {
					rc.Title = title
				}
				rc.MissingFields = missingContactFieldsFromValues(rc.Name, rc.Email, rc.Company, rc.Title)
			}
			for _, k := range keys {
				dedupMap[k] = matchID
			}
			merged++
			continue
		}

		// Check DB via cascade
		existingContact, err := findExistingContact(d, email, linkedin, name, company, domain)
		if err != nil {
			return nil, err
		}

		now := time.Now().UTC().Format(time.RFC3339)

		if existingContact != nil {
			// Update existing DB contact with non-empty fields
			_, err = d.Exec(enrichUpdateSQL,
				email, email,
				name, name,
				domain, domain,
				company, company,
				title, title,
				phone, phone,
				linkedin, linkedin,
				industry, industry,
				companySize, companySize,
				fundingStage, fundingStage,
				website, website,
				techStack, techStack,
				signals, signals,
				string(InputCSV),
				now, now,
				existingContact.id,
			)
			if err != nil {
				return nil, fmt.Errorf("updating contact %s: %w", existingContact.id, err)
			}

			effectiveEmail := coalesce(email, existingContact.email)
			if isPlaceholderEmail(effectiveEmail) {
				effectiveEmail = ""
			}
			idx := len(result.Contacts)
			result.Contacts = append(result.Contacts, ResolvedContact{
				ID:            existingContact.id,
				Email:         effectiveEmail,
				Name:          coalesce(name, existingContact.name),
				Company:       coalesce(company, existingContact.company),
				Title:         coalesce(title, existingContact.title),
				Status:        "updated",
				MissingFields: missingContactFieldsFromValues(coalesce(name, existingContact.name), effectiveEmail, coalesce(company, existingContact.company), coalesce(title, existingContact.title)),
				IsNew:         false,
			})
			contactIdx[existingContact.id] = idx
			for _, k := range keys {
				dedupMap[k] = existingContact.id
			}
			updated++
		} else {
			// Create new contact
			id := newContactID()
			dbEmail := email
			if dbEmail == "" {
				dbEmail = placeholderEmail(id)
			}

			_, err = d.Exec(`
				INSERT INTO contacts (id, source, email, name, domain, company, title, phone, linkedin_url,
					industry, company_size, funding_stage, website, tech_stack, signals,
					resolve_source, last_activity_at, updated_at)
				VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
				id, "resolve", dbEmail, name, domain, company, title, phone, linkedin,
				industry, companySize, fundingStage, website, techStack, signals,
				string(InputCSV), now, now,
			)
			if err != nil {
				return nil, fmt.Errorf("creating contact row %d: %w", rowNum, err)
			}

			idx := len(result.Contacts)
			result.Contacts = append(result.Contacts, ResolvedContact{
				ID:            id,
				Email:         email, // Real email or empty, not placeholder
				Name:          name,
				Company:       company,
				Title:         title,
				Status:        "created",
				MissingFields: missingContactFieldsFromValues(name, email, company, title),
				IsNew:         true,
			})
			contactIdx[id] = idx
			for _, k := range keys {
				dedupMap[k] = id
			}
			created++
		}
	}

	// Build summary
	parts := []string{}
	if created > 0 {
		parts = append(parts, fmt.Sprintf("%d created", created))
	}
	if updated > 0 {
		parts = append(parts, fmt.Sprintf("%d updated", updated))
	}
	if merged > 0 {
		parts = append(parts, fmt.Sprintf("%d merged", merged))
	}
	if len(result.Skipped) > 0 {
		parts = append(parts, fmt.Sprintf("%d skipped", len(result.Skipped)))
	}
	result.Summary = fmt.Sprintf("CSV import: %s", strings.Join(parts, ", "))
	if created+updated+merged == 0 {
		result.Summary = "CSV import: no contacts resolved"
	}

	// Determine next step
	hasEnrichNeeded := false
	for _, c := range result.Contacts {
		if len(c.MissingFields) > 0 {
			hasEnrichNeeded = true
			break
		}
	}
	if hasEnrichNeeded {
		result.Next = "enrich"
	} else {
		result.Next = "ready"
	}

	return result, nil
}

// SQL for merging a duplicate CSV row into an already-inserted contact.
const mergeUpdateSQL = `
	UPDATE contacts
	SET email = CASE WHEN (email = '' OR email LIKE '_noemail_%') AND ? != '' THEN ? ELSE email END,
		name = CASE WHEN ? = '' THEN name ELSE ? END,
		domain = CASE WHEN ? = '' THEN domain ELSE ? END,
		company = CASE WHEN ? = '' THEN company ELSE ? END,
		title = CASE WHEN ? = '' THEN title ELSE ? END,
		phone = CASE WHEN ? = '' THEN phone ELSE ? END,
