// findExistingContact tries to match a contact in the DB using a cascade of identifiers.
func findExistingContact(d *sql.DB, email, linkedin, name, company, domain string) (*contactRow, error) {
	// 1. Email (exact, strongest)
	if email != "" && looksLikeEmail(email) {
		if c, err := contactByEmail(d, email); err != nil {
			return nil, err
		} else if c != nil {
			return c, nil
		}
	}
	// 2. LinkedIn URL (globally unique)
	if linkedin != "" {
		norm := linkedin
		if strings.Contains(strings.ToLower(linkedin), "linkedin.com/in/") {
			norm = normalizeLinkedInURL(linkedin, "in")
		}
		if norm != "" {
			if c, err := contactByLinkedIn(d, norm); err != nil {
				return nil, err
			} else if c != nil {
				return c, nil
			}
		}
	}
	// 3. Name + domain
	if name != "" && domain != "" {
		if c, err := contactByNameDomain(d, name, domain); err != nil {
			return nil, err
		} else if c != nil {
			return c, nil
		}
	}
	// 4. Name + company (exact match in DB)
	if name != "" && company != "" {
		if c, err := contactByNameCompany(d, name, company); err != nil {
			return nil, err
		} else if c != nil {
			return c, nil
		}
	}
	return nil, nil
}

func contactByNameDomain(d *sql.DB, name, domain string) (*contactRow, error) {
	var c contactRow
	err := d.QueryRow(`
		SELECT id, COALESCE(email,''), COALESCE(name,''), COALESCE(company,''), COALESCE(title,''), COALESCE(phone,'')
		FROM contacts
		WHERE lower(name) = lower(?) AND lower(domain) = lower(?)
		ORDER BY updated_at DESC
		LIMIT 1`, name, domain).Scan(&c.id, &c.email, &c.name, &c.company, &c.title, &c.phone)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("looking up contact by name+domain: %w", err)
	}
	return &c, nil
}

// toJSONArray converts a comma-separated string to a JSON array string.
// If the input is already JSON (starts with [), it is returned as-is.
func toJSONArray(val string) string {
	val = strings.TrimSpace(val)
	if val == "" {
		return ""
	}
	if strings.HasPrefix(val, "[") {
		return val
	}
	parts := strings.Split(val, ",")
	var cleaned []string
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			cleaned = append(cleaned, p)
		}
	}
	data, _ := json.Marshal(cleaned)
	return string(data)
}

