func TestHelpers(t *testing.T) {
	t.Run("extractDomain", func(t *testing.T) {
		tests := []struct {
			input string
			want  string
		}{
			{"https://acme.com", "acme.com"},
			{"http://www.acme.com/about", "acme.com"},
			{"acme.com", "acme.com"},
			{"www.acme.com", "acme.com"},
			{"nodots", ""},
		}
		for _, tt := range tests {
			got := extractDomain(tt.input)
			if got != tt.want {
				t.Errorf("extractDomain(%q) = %q, want %q", tt.input, got, tt.want)
			}
		}
	})

	t.Run("extractLinkedInSlug", func(t *testing.T) {
		tests := []struct {
			input string
			kind  string
			want  string
		}{
			{"https://linkedin.com/in/john-doe", "in", "john-doe"},
			{"linkedin.com/in/john-doe/", "in", "john-doe"},
			{"https://www.linkedin.com/company/acme-inc?foo=bar", "company", "acme-inc"},
			{"no-linkedin-url", "in", ""},
		}
		for _, tt := range tests {
			got := extractLinkedInSlug(tt.input, tt.kind)
			if got != tt.want {
				t.Errorf("extractLinkedInSlug(%q, %q) = %q, want %q", tt.input, tt.kind, got, tt.want)
			}
		}
	})

	t.Run("slugToName", func(t *testing.T) {
		tests := []struct {
			slug string
			want string
		}{
			{"john-doe", "John Doe"},
			{"john-doe-abc123def", "John Doe"},
			{"alice", "Alice"},
		}
		for _, tt := range tests {
			got := slugToName(tt.slug)
			if got != tt.want {
				t.Errorf("slugToName(%q) = %q, want %q", tt.slug, got, tt.want)
			}
		}
	})

	t.Run("domainToCompanyName", func(t *testing.T) {
		tests := []struct {
			domain string
			want   string
		}{
			{"acme.com", "Acme"},
			{"data-stack.io", "Data Stack"},
			{"my.company.co", "My.company"},
		}
		for _, tt := range tests {
			got := domainToCompanyName(tt.domain)
			if got != tt.want {
				t.Errorf("domainToCompanyName(%q) = %q, want %q", tt.domain, got, tt.want)
			}
		}
	})

	t.Run("buildColumnMap", func(t *testing.T) {
		header := []string{"Email Address", "Full Name", "Company Name", "Job Title", "Phone Number", "LinkedIn URL"}
		colMap := buildColumnMap(header)

		expected := map[string]int{
			"email":    0,
			"name":     1,
			"company":  2,
			"title":    3,
			"phone":    4,
			"linkedin": 5,
		}
		for field, wantIdx := range expected {
			gotIdx, ok := colMap[field]
			if !ok {
				t.Errorf("field %q not found in colMap", field)
				continue
			}
			if gotIdx != wantIdx {
				t.Errorf("colMap[%q] = %d, want %d", field, gotIdx, wantIdx)
			}
		}
	})
}

