func TestResolveCSV(t *testing.T) {
	d := setupTestDB(t)

	// Write a test CSV
	dir := t.TempDir()
	csvPath := filepath.Join(dir, "test.csv")
	csvContent := `Email Address,Full Name,Company,Job Title,Phone Number
alice@acme.com,Alice Smith,Acme Inc,CEO,555-0001
bob@beta.com,Bob Jones,Beta Corp,CTO,555-0002
invalid-email,Bad Row,,
alice@acme.com,Alice Dupe,Acme Inc,CEO,555-0001
`
	if err := os.WriteFile(csvPath, []byte(csvContent), 0644); err != nil {
		t.Fatalf("writing CSV: %v", err)
	}

	result, err := Resolve(d, csvPath, "")
	if err != nil {
		t.Fatalf("Resolve CSV: %v", err)
	}

	if result.InputType != InputCSV {
		t.Errorf("input type = %s, want csv", result.InputType)
	}

	// Should have 2 created contacts (alice + bob); the alice duplicate merges, not skips
	created := 0
	for _, c := range result.Contacts {
		if c.Status == "created" {
			created++
		}
	}
	if created != 2 {
		t.Errorf("created = %d, want 2", created)
	}

	// Should have skipped 1 invalid; duplicate is now merged (not skipped)
	skipReasons := map[string]int{}
	for _, s := range result.Skipped {
		skipReasons[s.Reason]++
	}
	if skipReasons["invalid_email"] != 1 {
		t.Errorf("invalid_email skips = %d, want 1", skipReasons["invalid_email"])
	}

	// Verify the summary includes "merged"
	if !strings.Contains(result.Summary, "merged") {
		t.Errorf("summary should mention merged, got: %s", result.Summary)
	}
}

